-- Migration 008: Seed 1000 unique AWS SAA-C03 practice questions
-- 300 RESILIENT / 260 PERFORMANCE / 240 SECURITY / 100 COST / 60 OPERATIONS / 40 IMPROVEMENT

INSERT INTO public.questions (domain_id, type, content, options, explanation, difficulty, aws_doc_url, exam_objective_code, is_ai_generated, is_active) VALUES
-- ============================================================
-- DOMAIN 1: Design Resilient Architectures (300 questions)
-- ============================================================
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a web application on Amazon EC2 instances behind an Application Load Balancer. The application must remain available even if an entire Availability Zone fails. Which architecture meets this requirement?', '[{"id":"a","text":"Deploy instances in a single AZ with Auto Scaling","is_correct":false,"explanation":"A single AZ cannot survive an AZ failure."},{"id":"b","text":"Deploy instances across multiple AZs with Auto Scaling and health checks","is_correct":true,"explanation":"Multi-AZ with Auto Scaling ensures instances are replaced in healthy AZs if one fails."},{"id":"c","text":"Deploy instances in a single AZ with a larger instance type","is_correct":false,"explanation":"Vertical scaling does not protect against AZ failure."},{"id":"d","text":"Use a Network Load Balancer instead of an Application Load Balancer","is_correct":false,"explanation":"Changing the load balancer type does not address AZ redundancy."}]', 'Deploying across multiple Availability Zones with Auto Scaling ensures the application remains available even if one AZ experiences an outage.', 2, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/auto-scaling-benefits.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect needs to design a database solution for an e-commerce application that requires sub-millisecond read latency for product catalog data. The catalog is read-heavy with infrequent writes. Which solution is MOST appropriate?', '[{"id":"a","text":"Amazon RDS MySQL with read replicas","is_correct":false,"explanation":"RDS read replicas provide millisecond latency, not sub-millisecond."},{"id":"b","text":"Amazon DynamoDB with DynamoDB Accelerator (DAX)","is_correct":true,"explanation":"DAX provides sub-millisecond read latency as an in-memory cache for DynamoDB."},{"id":"c","text":"Amazon Aurora with Aurora Serverless","is_correct":false,"explanation":"Aurora Serverless does not guarantee sub-millisecond reads."},{"id":"d","text":"Amazon Redshift with concurrency scaling","is_correct":false,"explanation":"Redshift is an analytics warehouse, not designed for sub-millisecond transactional reads."}]', 'DynamoDB with DAX provides an in-memory caching layer that delivers sub-millisecond read performance, ideal for read-heavy catalog workloads.', 3, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/DAX.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application stores session state in Amazon ElastiCache for Redis. The architect must ensure that session data is not lost if a node fails. Which ElastiCache feature should be enabled?', '[{"id":"a","text":"Lazy loading caching strategy","is_correct":false,"explanation":"Lazy loading is a caching pattern, not a durability feature."},{"id":"b","text":"Multi-AZ with automatic failover","is_correct":true,"explanation":"Multi-AZ with automatic failover replicates data to a standby node and promotes it on failure."},{"id":"c","text":"Redis append-only file (AOF) on a single node","is_correct":false,"explanation":"AOF helps with persistence but does not protect against node failure without replication."},{"id":"d","text":"Memcached cluster mode","is_correct":false,"explanation":"Memcached does not support replication or persistence."}]', 'ElastiCache for Redis with Multi-AZ automatic failover maintains a synchronous replica in another AZ, ensuring session data survives node failures.', 3, 'https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/AutoFailover.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is migrating a legacy Oracle database to AWS. The database uses stored procedures and complex joins. The company wants minimal code changes. Which migration strategy is MOST appropriate?', '[{"id":"a","text":"Migrate to Amazon DynamoDB using AWS DMS","is_correct":false,"explanation":"DynamoDB is a NoSQL database and cannot run Oracle stored procedures."},{"id":"b","text":"Migrate to Amazon RDS for Oracle using AWS DMS","is_correct":true,"explanation":"RDS for Oracle supports stored procedures and complex SQL with minimal code changes."},{"id":"c","text":"Migrate to Amazon Aurora PostgreSQL using AWS SCT","is_correct":false,"explanation":"Aurora PostgreSQL would require rewriting Oracle-specific stored procedures."},{"id":"d","text":"Migrate to Amazon S3 and query with Athena","is_correct":false,"explanation":"S3 with Athena cannot replace a relational database with stored procedures."}]', 'RDS for Oracle provides a managed Oracle-compatible database engine, allowing migration with minimal code changes to stored procedures and complex queries.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/CHAP_Oracle.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to store 50 TB of archival data that is rarely accessed but must be retrievable within 12 hours when needed. Which S3 storage class is MOST cost-effective?', '[{"id":"a","text":"S3 Standard","is_correct":false,"explanation":"S3 Standard is the most expensive option for rarely accessed data."},{"id":"b","text":"S3 Glacier Deep Archive","is_correct":true,"explanation":"Glacier Deep Archive is the lowest-cost storage class with retrieval times of up to 12 hours."},{"id":"c","text":"S3 One Zone-IA","is_correct":false,"explanation":"One Zone-IA is cheaper than Standard but more expensive than Glacier Deep Archive."},{"id":"d","text":"S3 Intelligent-Tiering","is_correct":false,"explanation":"Intelligent-Tiering has monitoring fees and is not the cheapest for known access patterns."}]', 'S3 Glacier Deep Archive provides the lowest storage cost and supports standard retrieval within 12 hours, perfect for rarely accessed archival data.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/storage-class-intro.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A solutions architect is designing a highly available architecture for a critical application. (Select TWO) Which services provide built-in Multi-AZ redundancy by default?', '[{"id":"a","text":"Amazon S3","is_correct":true,"explanation":"S3 automatically stores data across a minimum of three AZs."},{"id":"b","text":"Amazon EC2 instances","is_correct":false,"explanation":"EC2 instances run in a single AZ unless you deploy across multiple AZs."},{"id":"c","text":"Amazon DynamoDB","is_correct":true,"explanation":"DynamoDB automatically replicates data across three AZs in a Region."},{"id":"d","text":"Amazon EBS volumes","is_correct":false,"explanation":"EBS volumes are replicated within a single AZ only."}]', 'S3 and DynamoDB are both designed to automatically store data across multiple Availability Zones without additional configuration.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/HowItWorks.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application running on EC2 instances must read and write to an Amazon RDS MySQL database. The architect wants to avoid storing database credentials in the application code. Which solution is MOST secure?', '[{"id":"a","text":"Store credentials in an environment variable on the EC2 instance","is_correct":false,"explanation":"Environment variables can be exposed through process listings and are not encrypted."},{"id":"b","text":"Use IAM database authentication with an IAM role attached to the EC2 instance","is_correct":true,"explanation":"IAM database authentication eliminates the need for passwords and uses temporary tokens."},{"id":"c","text":"Store credentials in an S3 bucket with server-side encryption","is_correct":false,"explanation":"S3 adds complexity and the credentials still need to be fetched and managed."},{"id":"d","text":"Hard-code credentials in the application configuration file","is_correct":false,"explanation":"Hard-coding credentials is a security anti-pattern."}]', 'IAM database authentication uses the EC2 instance role to generate temporary authentication tokens, eliminating the need to manage database passwords.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/UsingWithRDS.IAMDBAuth.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to replicate an Amazon S3 bucket to another AWS Region for disaster recovery. Objects must be replicated within 15 minutes. Which feature should be used?', '[{"id":"a","text":"S3 Cross-Region Replication (CRR) with S3 Replication Time Control (S3 RTC)","is_correct":true,"explanation":"S3 RTC guarantees 99.99% of objects are replicated within 15 minutes."},{"id":"b","text":"S3 Cross-Region Replication (CRR) without RTC","is_correct":false,"explanation":"Standard CRR does not guarantee replication time."},{"id":"c","text":"AWS DataSync scheduled hourly","is_correct":false,"explanation":"DataSync hourly schedule cannot guarantee 15-minute replication."},{"id":"d","text":"S3 Batch Operations to copy objects","is_correct":false,"explanation":"Batch Operations is a one-time operation, not continuous replication."}]', 'S3 Replication Time Control (RTC) provides an SLA that 99.99% of objects are replicated within 15 minutes, meeting the disaster recovery requirement.', 3, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/replication-time-control.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A microservices application processes orders asynchronously. If the processing service fails, messages must not be lost. Which architecture ensures durable message delivery?', '[{"id":"a","text":"Amazon SNS topic with HTTP subscribers","is_correct":false,"explanation":"SNS does not persist messages if subscribers are unavailable."},{"id":"b","text":"Amazon SQS queue with a dead-letter queue configured","is_correct":true,"explanation":"SQS persists messages until processed, and the DLQ captures failed messages for analysis."},{"id":"c","text":"Amazon EventBridge with a Lambda function target","is_correct":false,"explanation":"EventBridge can retry but does not inherently persist messages for later processing."},{"id":"d","text":"Direct HTTP calls between services with retry logic","is_correct":false,"explanation":"Direct HTTP calls can lose messages if the service is down."}]', 'SQS provides durable message storage with configurable retention, and a dead-letter queue captures messages that fail processing after the maximum receive count.', 2, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/sqs-dead-letter-queues.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company operates a three-tier web application. The database tier uses Amazon Aurora MySQL. The company requires a recovery point objective (RPO) of 1 second and a recovery time objective (RTO) of less than 1 minute for the database. Which solution meets these requirements?', '[{"id":"a","text":"Aurora Multi-AZ deployment with automated backups","is_correct":false,"explanation":"Automated backups have an RPO of 5 minutes at best."},{"id":"b","text":"Aurora Global Database with write forwarding","is_correct":true,"explanation":"Aurora Global Database provides cross-Region replication with RPO of 1 second and RTO under 1 minute."},{"id":"c","text":"Aurora read replicas in another Region","is_correct":false,"explanation":"Cross-Region read replicas have higher replication lag and require manual promotion."},{"id":"d","text":"AWS Backup with hourly snapshots","is_correct":false,"explanation":"Hourly snapshots have an RPO of up to 1 hour."}]', 'Aurora Global Database replicates data across Regions with typical lag under 1 second (RPO) and can promote a secondary Region in under 1 minute (RTO).', 4, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/aurora-global-database.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing a system that must decouple a producer from multiple consumers. Each consumer must receive every message independently. Which AWS service should be used?', '[{"id":"a","text":"Amazon SQS standard queue","is_correct":false,"explanation":"SQS delivers each message to only one consumer."},{"id":"b","text":"Amazon SNS topic with SQS subscriptions for each consumer","is_correct":true,"explanation":"SNS fan-out pattern delivers a copy of each message to all subscribed SQS queues."},{"id":"c","text":"Amazon Kinesis Data Firehose","is_correct":false,"explanation":"Firehose delivers data to destinations like S3, not to multiple independent consumers."},{"id":"d","text":"AWS Step Functions parallel state","is_correct":false,"explanation":"Step Functions orchestrates workflows, not message distribution."}]', 'The SNS fan-out pattern publishes messages to an SNS topic, which delivers copies to multiple SQS queues, ensuring each consumer processes every message independently.', 3, 'https://docs.aws.amazon.com/sns/latest/dg/sns-sqs-as-subscriber.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an on-premises application that writes data to a local NFS file share. They want to migrate to AWS while keeping the NFS interface. Which service should be used?', '[{"id":"a","text":"Amazon S3 with an S3 gateway endpoint","is_correct":false,"explanation":"S3 uses an object-based API, not NFS."},{"id":"b","text":"Amazon EFS mounted via AWS Direct Connect or VPN","is_correct":true,"explanation":"EFS provides a managed NFS file system accessible from on-premises via Direct Connect or VPN."},{"id":"c","text":"Amazon FSx for Windows File Server","is_correct":false,"explanation":"FSx for Windows uses SMB protocol, not NFS."},{"id":"d","text":"AWS Storage Gateway file gateway","is_correct":false,"explanation":"Storage Gateway file gateway provides an NFS interface but stores data in S3, adding latency."}]', 'Amazon EFS is a fully managed NFS file system that can be mounted from on-premises servers through AWS Direct Connect or VPN, preserving the existing NFS interface.', 3, 'https://docs.aws.amazon.com/efs/latest/ug/whatisefs.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A serverless application uses AWS Lambda functions triggered by API Gateway. During peak traffic, some requests are being throttled. Which approach should the architect take to handle traffic spikes?', '[{"id":"a","text":"Increase the Lambda function memory allocation","is_correct":false,"explanation":"Memory allocation affects performance but not concurrency limits."},{"id":"b","text":"Request a concurrency limit increase and configure provisioned concurrency","is_correct":true,"explanation":"Increasing the concurrency limit and using provisioned concurrency eliminates throttling and cold starts."},{"id":"c","text":"Move the application to EC2 instances","is_correct":false,"explanation":"Migrating away from serverless is unnecessary when concurrency can be adjusted."},{"id":"d","text":"Add an Amazon CloudFront distribution in front of API Gateway","is_correct":false,"explanation":"CloudFront caches responses but does not solve Lambda throttling for dynamic requests."}]', 'Requesting higher concurrency limits removes the throttling ceiling, while provisioned concurrency keeps functions initialized to handle traffic spikes without cold starts.', 3, 'https://docs.aws.amazon.com/lambda/latest/dg/configuration-concurrency.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company must ensure that Amazon EBS volumes attached to EC2 instances are encrypted. Which approach enforces encryption for all new EBS volumes across an AWS account?', '[{"id":"a","text":"Create an IAM policy that denies ec2:CreateVolume without encryption","is_correct":false,"explanation":"IAM policies can restrict but are not the simplest enforcement mechanism for default encryption."},{"id":"b","text":"Enable EBS encryption by default in the account settings for each Region","is_correct":true,"explanation":"Enabling default encryption ensures all new EBS volumes and snapshots are automatically encrypted."},{"id":"c","text":"Use AWS Config to detect unencrypted volumes","is_correct":false,"explanation":"AWS Config detects but does not prevent the creation of unencrypted volumes."},{"id":"d","text":"Encrypt each volume manually during creation","is_correct":false,"explanation":"Manual encryption is error-prone and not enforceable at scale."}]', 'Enabling EBS encryption by default at the account level ensures that all new EBS volumes and snapshots are encrypted without requiring individual configuration.', 2, 'https://docs.aws.amazon.com/ebs/latest/userguide/encryption-by-default.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application stores user-uploaded images in Amazon S3. Older images (over 90 days) are rarely accessed but must remain available. Which approach minimizes storage costs?', '[{"id":"a","text":"Delete images older than 90 days","is_correct":false,"explanation":"Deleting images would make them unavailable."},{"id":"b","text":"Configure an S3 lifecycle policy to transition objects to S3 Glacier Flexible Retrieval after 90 days","is_correct":true,"explanation":"Lifecycle policies automatically move objects to cheaper storage classes based on age."},{"id":"c","text":"Move old images to an EBS volume","is_correct":false,"explanation":"EBS is more expensive than S3 Glacier for archival storage."},{"id":"d","text":"Enable S3 versioning to reduce costs","is_correct":false,"explanation":"Versioning increases costs by retaining all versions of objects."}]', 'S3 lifecycle policies automate the transition of objects to lower-cost storage classes like Glacier Flexible Retrieval based on object age.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/lifecycle-transition-general-considerations.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a stateful web application on EC2 instances behind an ALB. Users report losing session data when they are routed to different instances. Which solution resolves this?', '[{"id":"a","text":"Enable sticky sessions (session affinity) on the ALB target group","is_correct":false,"explanation":"Sticky sessions solve the symptom but create uneven load distribution and are not resilient to instance failure."},{"id":"b","text":"Store session data in Amazon ElastiCache for Redis and remove sticky sessions","is_correct":true,"explanation":"Externalizing session state to ElastiCache makes the application stateless and resilient to instance failures."},{"id":"c","text":"Increase the number of EC2 instances","is_correct":false,"explanation":"More instances do not prevent session loss on re-routing."},{"id":"d","text":"Switch to a Network Load Balancer","is_correct":false,"explanation":"NLB does not solve session state management."}]', 'Externalizing session state to ElastiCache for Redis allows any instance to serve any user, making the application stateless, scalable, and resilient.', 3, 'https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/elasticache-use-cases.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A media company ingests terabytes of video files daily. Files must be processed immediately upon upload. Which event-driven architecture is MOST efficient?', '[{"id":"a","text":"Poll the S3 bucket every minute using a scheduled Lambda function","is_correct":false,"explanation":"Polling introduces latency and is not event-driven."},{"id":"b","text":"Configure S3 event notifications to trigger a Lambda function on object creation","is_correct":true,"explanation":"S3 event notifications instantly trigger Lambda when objects are uploaded."},{"id":"c","text":"Use CloudWatch Events to monitor S3 bucket size changes","is_correct":false,"explanation":"CloudWatch metric-based monitoring has multi-minute delays."},{"id":"d","text":"Deploy an EC2 instance to watch the bucket using the AWS CLI","is_correct":false,"explanation":"Running an EC2 instance to poll is expensive and not event-driven."}]', 'S3 event notifications provide immediate, event-driven invocation of Lambda functions when objects are created, enabling real-time processing without polling.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/EventNotifications.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect needs to design a disaster recovery strategy with an RTO of 4 hours and RPO of 1 hour for a critical application. Which DR strategy is MOST cost-effective?', '[{"id":"a","text":"Multi-site active-active","is_correct":false,"explanation":"Active-active provides near-zero RTO/RPO but is the most expensive."},{"id":"b","text":"Warm standby","is_correct":true,"explanation":"Warm standby maintains a scaled-down version of the production environment that can be scaled up within 4 hours."},{"id":"c","text":"Backup and restore","is_correct":false,"explanation":"Backup and restore typically has RTOs of 24+ hours."},{"id":"d","text":"Pilot light","is_correct":false,"explanation":"Pilot light may not meet a 4-hour RTO as it requires significant provisioning."}]', 'Warm standby keeps a minimal but functional copy of the production environment running, allowing it to be scaled up to full capacity within the 4-hour RTO window.', 3, 'https://docs.aws.amazon.com/whitepapers/latest/disaster-recovery-workloads-on-aws/disaster-recovery-options-in-the-cloud.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A solutions architect is designing a VPC for a web application. (Select TWO) Which components are required to allow instances in a private subnet to access the internet for software updates?', '[{"id":"a","text":"NAT gateway in a public subnet","is_correct":true,"explanation":"A NAT gateway allows outbound internet access for private subnet instances."},{"id":"b","text":"Internet gateway attached to the VPC","is_correct":true,"explanation":"An internet gateway is required for any internet connectivity in the VPC."},{"id":"c","text":"VPC peering connection","is_correct":false,"explanation":"VPC peering connects VPCs, not VPCs to the internet."},{"id":"d","text":"AWS PrivateLink endpoint","is_correct":false,"explanation":"PrivateLink provides private connectivity to services, not internet access."}]', 'Private subnet instances need a NAT gateway (in a public subnet) for outbound traffic and an internet gateway on the VPC for the NAT gateway to route traffic to the internet.', 2, 'https://docs.aws.amazon.com/vpc/latest/userguide/vpc-nat-gateway.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to run containers without managing servers. The containers run batch jobs that last 5-20 minutes each and have unpredictable demand. Which compute platform is MOST suitable?', '[{"id":"a","text":"Amazon ECS on EC2 instances with Auto Scaling","is_correct":false,"explanation":"Managing EC2 instances adds operational overhead."},{"id":"b","text":"AWS Fargate with Amazon ECS","is_correct":true,"explanation":"Fargate is serverless, requires no server management, and scales to zero when there are no jobs."},{"id":"c","text":"Amazon EKS with managed node groups","is_correct":false,"explanation":"EKS with managed nodes still requires managing the underlying EC2 infrastructure."},{"id":"d","text":"AWS Lambda with container images","is_correct":false,"explanation":"Lambda has a 15-minute timeout, which is insufficient for 20-minute jobs."}]', 'AWS Fargate runs containers without managing servers, automatically scales based on demand, and charges only for the compute resources used during execution.', 2, 'https://docs.aws.amazon.com/AmazonECS/latest/developerguide/AWS_Fargate.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application uses Amazon Aurora PostgreSQL. The architect wants to protect against accidental table deletions with the ability to restore to any point within the last 7 days. Which feature provides this?', '[{"id":"a","text":"Aurora automated backups with point-in-time recovery","is_correct":true,"explanation":"Aurora automated backups support point-in-time recovery to any second within the retention period."},{"id":"b","text":"Aurora manual snapshots","is_correct":false,"explanation":"Manual snapshots capture a single point in time, not continuous recovery."},{"id":"c","text":"Aurora cloning","is_correct":false,"explanation":"Cloning creates a copy of the current state, not a historical point-in-time."},{"id":"d","text":"Aurora Backtrack","is_correct":false,"explanation":"Backtrack is only available for Aurora MySQL, not PostgreSQL."}]', 'Aurora automated backups provide continuous backup with point-in-time recovery, allowing restoration to any second within the configured retention period (up to 35 days).', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Managing.Backups.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company must implement a DNS failover solution. If the primary endpoint in us-east-1 becomes unhealthy, traffic must automatically route to a standby in eu-west-1. Which Route 53 routing policy should be used?', '[{"id":"a","text":"Simple routing","is_correct":false,"explanation":"Simple routing does not support health checks or failover."},{"id":"b","text":"Failover routing policy with health checks","is_correct":true,"explanation":"Failover routing automatically directs traffic to a secondary endpoint when the primary fails health checks."},{"id":"c","text":"Weighted routing with equal weights","is_correct":false,"explanation":"Weighted routing distributes traffic but does not provide automatic failover."},{"id":"d","text":"Latency-based routing","is_correct":false,"explanation":"Latency-based routing optimizes performance, not failover."}]', 'Route 53 failover routing policy with health checks automatically directs DNS queries to a secondary endpoint when the primary endpoint fails its health check.', 2, 'https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/routing-policy-failover.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A mobile application backend uses API Gateway and Lambda. The architect needs to protect the API from request floods and ensure fair usage across clients. Which feature should be configured?', '[{"id":"a","text":"Lambda reserved concurrency","is_correct":false,"explanation":"Reserved concurrency limits Lambda invocations but does not rate-limit per client."},{"id":"b","text":"API Gateway usage plans with API keys and throttling","is_correct":true,"explanation":"Usage plans with API keys enable per-client rate limiting and throttling."},{"id":"c","text":"AWS WAF rate-based rules","is_correct":false,"explanation":"WAF rate-based rules block IPs but do not manage per-client fair usage."},{"id":"d","text":"CloudFront origin request policy","is_correct":false,"explanation":"CloudFront policies control forwarded headers, not client-level throttling."}]', 'API Gateway usage plans associate API keys with throttling limits (requests per second and burst), enabling per-client rate limiting and fair usage enforcement.', 3, 'https://docs.aws.amazon.com/apigateway/latest/developerguide/api-gateway-api-usage-plans.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a legacy monolithic application on a single large EC2 instance. They want to improve availability without refactoring. Which is the simplest approach?', '[{"id":"a","text":"Use an Auto Scaling group with min=1, max=1 across multiple AZs with an ALB","is_correct":true,"explanation":"An ASG with min/max=1 automatically replaces the instance in a healthy AZ if it fails."},{"id":"b","text":"Create an AMI and manually launch a replacement instance when the current one fails","is_correct":false,"explanation":"Manual intervention increases downtime."},{"id":"c","text":"Convert the application to microservices on Lambda","is_correct":false,"explanation":"This requires significant refactoring."},{"id":"d","text":"Deploy on AWS Outposts for dedicated hardware","is_correct":false,"explanation":"Outposts does not improve availability for a single-instance application."}]', 'An Auto Scaling group with min/max capacity of 1 automatically detects instance failure and launches a replacement in a healthy AZ, improving availability without refactoring.', 2, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/auto-scaling-groups.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A financial application requires encryption of all data at rest in Amazon S3. The company must manage the encryption keys and rotate them annually. Which encryption option meets this requirement?', '[{"id":"a","text":"SSE-S3 (S3-managed keys)","is_correct":false,"explanation":"SSE-S3 uses Amazon-managed keys; the customer has no control over key rotation."},{"id":"b","text":"SSE-KMS with a customer managed key (CMK) and automatic annual rotation","is_correct":true,"explanation":"SSE-KMS with a CMK allows the customer to manage keys and enable automatic annual rotation."},{"id":"c","text":"SSE-C (customer-provided keys)","is_correct":false,"explanation":"SSE-C requires the customer to provide keys with every request, adding operational burden."},{"id":"d","text":"Client-side encryption with AWS Encryption SDK","is_correct":false,"explanation":"Client-side encryption adds complexity and the question specifies S3-level encryption."}]', 'SSE-KMS with a customer managed key provides customer control over encryption keys with the option to enable automatic annual key rotation in AWS KMS.', 3, 'https://docs.aws.amazon.com/kms/latest/developerguide/rotate-keys.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A data pipeline ingests streaming data from IoT devices at 10,000 records per second. The data must be stored in S3 for batch analytics. Which service is MOST appropriate for ingestion?', '[{"id":"a","text":"Amazon Kinesis Data Firehose","is_correct":true,"explanation":"Kinesis Data Firehose automatically buffers, batches, and delivers streaming data to S3."},{"id":"b","text":"Amazon SQS with a Lambda consumer writing to S3","is_correct":false,"explanation":"SQS with Lambda adds complexity and may not handle 10K records/sec efficiently."},{"id":"c","text":"AWS Glue streaming ETL","is_correct":false,"explanation":"Glue streaming ETL is designed for transformation, not simple ingestion to S3."},{"id":"d","text":"Amazon Managed Streaming for Apache Kafka (MSK)","is_correct":false,"explanation":"MSK is powerful but over-engineered for simple ingestion to S3."}]', 'Kinesis Data Firehose is a fully managed service that captures, transforms, and delivers streaming data to S3 with automatic batching, compression, and encryption.', 3, 'https://docs.aws.amazon.com/firehose/latest/dev/what-is-this-service.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect designs a system where an EC2 instance must securely access an S3 bucket without using access keys. Which approach is correct?', '[{"id":"a","text":"Attach an IAM role with an S3 access policy to the EC2 instance","is_correct":true,"explanation":"IAM roles provide temporary credentials automatically rotated by STS."},{"id":"b","text":"Create an IAM user and store access keys in ~/.aws/credentials on the instance","is_correct":false,"explanation":"Storing long-term credentials on an instance is a security risk."},{"id":"c","text":"Use S3 pre-signed URLs for all operations","is_correct":false,"explanation":"Pre-signed URLs are for time-limited access, not ongoing application access."},{"id":"d","text":"Make the S3 bucket public","is_correct":false,"explanation":"Making a bucket public is a major security risk."}]', 'IAM roles for EC2 provide temporary security credentials that are automatically rotated, eliminating the need to store long-term access keys on the instance.', 1, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/iam-roles-for-amazon-ec2.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A SaaS company wants to deploy a multi-tenant application where each tenant has isolated DynamoDB tables. What is the MOST scalable approach to tenant isolation?', '[{"id":"a","text":"Create separate DynamoDB tables per tenant","is_correct":false,"explanation":"Separate tables do not scale with thousands of tenants and increase management complexity."},{"id":"b","text":"Use a single table with a partition key that includes the tenant ID","is_correct":true,"explanation":"A single-table design with tenant ID in the partition key provides logical isolation while scaling efficiently."},{"id":"c","text":"Create separate AWS accounts per tenant","is_correct":false,"explanation":"Separate accounts per tenant is operationally expensive for a multi-tenant SaaS."},{"id":"d","text":"Use DynamoDB global tables with one Region per tenant","is_correct":false,"explanation":"Global tables are for multi-Region replication, not tenant isolation."}]', 'A single-table design with tenant ID as part of the partition key provides efficient tenant isolation, scales to millions of tenants, and simplifies management.', 3, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/bp-partition-key-design.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has a VPC with public and private subnets. They want EC2 instances in private subnets to access AWS services like S3 and DynamoDB without internet access. Which solution should be used?', '[{"id":"a","text":"Deploy a NAT gateway in the public subnet","is_correct":false,"explanation":"A NAT gateway routes traffic through the internet, which the requirement explicitly avoids."},{"id":"b","text":"Create VPC gateway endpoints for S3 and interface endpoints for DynamoDB","is_correct":false,"explanation":"DynamoDB supports gateway endpoints, not interface endpoints. S3 supports both."},{"id":"c","text":"Create VPC gateway endpoints for S3 and DynamoDB","is_correct":true,"explanation":"Gateway endpoints for S3 and DynamoDB provide private access without traversing the internet."},{"id":"d","text":"Use VPC peering to connect to the AWS service VPC","is_correct":false,"explanation":"VPC peering is for connecting customer VPCs, not for accessing AWS services."}]', 'VPC gateway endpoints provide free, private connectivity to S3 and DynamoDB from within a VPC without requiring NAT gateways or internet gateways.', 3, 'https://docs.aws.amazon.com/vpc/latest/privatelink/gateway-endpoints.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application requires a relational database with automatic storage scaling, up to 128 TB, and compatibility with MySQL. Which service should the architect choose?', '[{"id":"a","text":"Amazon RDS for MySQL with gp3 storage","is_correct":false,"explanation":"RDS MySQL supports up to 64 TB of storage."},{"id":"b","text":"Amazon Aurora MySQL","is_correct":true,"explanation":"Aurora MySQL automatically scales storage up to 128 TB in 10 GB increments."},{"id":"c","text":"Amazon Redshift","is_correct":false,"explanation":"Redshift is a data warehouse, not a transactional relational database."},{"id":"d","text":"Amazon Neptune","is_correct":false,"explanation":"Neptune is a graph database, not a relational database."}]', 'Amazon Aurora MySQL-Compatible Edition automatically scales storage from 10 GB up to 128 TB without downtime, making it ideal for growing workloads.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Overview.StorageReliability.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A company wants to implement a caching strategy for a read-heavy application that uses Amazon RDS PostgreSQL. (Select TWO) Which caching solutions can reduce database load?', '[{"id":"a","text":"Amazon ElastiCache for Redis","is_correct":true,"explanation":"ElastiCache for Redis provides in-memory caching to offload read traffic from RDS."},{"id":"b","text":"Amazon CloudFront","is_correct":true,"explanation":"CloudFront can cache API responses at edge locations, reducing requests to the database."},{"id":"c","text":"Amazon SQS","is_correct":false,"explanation":"SQS is a message queue, not a caching solution."},{"id":"d","text":"AWS Glue","is_correct":false,"explanation":"Glue is an ETL service, not a caching solution."}]', 'ElastiCache for Redis provides application-level caching for database queries, while CloudFront caches HTTP responses at edge locations, both reducing read load on RDS.', 3, 'https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/WhatIs.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company operates a global application and needs to route users to the nearest AWS Region for the lowest latency. Which Route 53 routing policy should be used?', '[{"id":"a","text":"Geolocation routing","is_correct":false,"explanation":"Geolocation routing is based on the user''s geographic location, not network latency."},{"id":"b","text":"Latency-based routing","is_correct":true,"explanation":"Latency-based routing directs users to the Region with the lowest measured network latency."},{"id":"c","text":"Weighted routing","is_correct":false,"explanation":"Weighted routing distributes traffic by proportion, not by latency."},{"id":"d","text":"Multivalue answer routing","is_correct":false,"explanation":"Multivalue returns multiple records but does not optimize for latency."}]', 'Route 53 latency-based routing measures network latency from the user to each Region and routes traffic to the endpoint with the lowest latency.', 2, 'https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/routing-policy-latency.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A data engineering team runs Apache Spark jobs on Amazon EMR. Cluster utilization varies significantly, with peak usage for 4 hours daily. Which approach minimizes cost?', '[{"id":"a","text":"Use long-running EMR clusters with On-Demand instances","is_correct":false,"explanation":"Long-running On-Demand clusters are expensive for variable workloads."},{"id":"b","text":"Use transient EMR clusters with Spot instances for task nodes and On-Demand for master nodes","is_correct":true,"explanation":"Transient clusters terminate after job completion, and Spot instances provide up to 90% savings for task nodes."},{"id":"c","text":"Run Spark on EC2 instances with reserved capacity","is_correct":false,"explanation":"Reserved instances are cost-effective for steady-state, not variable workloads."},{"id":"d","text":"Migrate to AWS Glue and run jobs continuously","is_correct":false,"explanation":"Running Glue continuously is wasteful for 4-hour daily usage."}]', 'Transient EMR clusters with Spot instances for task nodes provide significant cost savings by only running during processing windows and leveraging spare capacity.', 3, 'https://docs.aws.amazon.com/emr/latest/ManagementGuide/emr-instance-purchasing-options.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an application that writes logs to Amazon CloudWatch Logs. They need to query and visualize log data across multiple log groups. Which service should they use?', '[{"id":"a","text":"Amazon Athena","is_correct":false,"explanation":"Athena queries data in S3, not CloudWatch Logs directly."},{"id":"b","text":"CloudWatch Logs Insights","is_correct":true,"explanation":"CloudWatch Logs Insights provides interactive querying and visualization across multiple log groups."},{"id":"c","text":"Amazon Elasticsearch Service","is_correct":false,"explanation":"Elasticsearch requires data to be ingested separately from CloudWatch."},{"id":"d","text":"AWS X-Ray","is_correct":false,"explanation":"X-Ray is for distributed tracing, not log querying."}]', 'CloudWatch Logs Insights enables ad-hoc querying of log data using a purpose-built query language, with support for cross-log-group queries and visualization.', 2, 'https://docs.aws.amazon.com/AmazonCloudWatch/latest/logs/AnalyzingLogData.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is transferring 100 TB of data from an on-premises data center to Amazon S3. The network connection is 1 Gbps. Which service enables the fastest transfer?', '[{"id":"a","text":"AWS DataSync over the existing network","is_correct":false,"explanation":"At 1 Gbps, 100 TB would take over 9 days, and DataSync still uses the network."},{"id":"b","text":"AWS Snowball Edge Storage Optimized","is_correct":true,"explanation":"Snowball Edge can transfer up to 80 TB per device and avoids network bottlenecks."},{"id":"c","text":"S3 multipart upload via the AWS CLI","is_correct":false,"explanation":"Multipart upload still relies on the 1 Gbps connection."},{"id":"d","text":"AWS Transfer Family SFTP endpoint","is_correct":false,"explanation":"Transfer Family still uses the network and adds protocol overhead."}]', 'AWS Snowball Edge physically ships storage devices, bypassing network limitations. Two devices can transfer 100+ TB in days including shipping time.', 2, 'https://docs.aws.amazon.com/snowball/latest/developer-guide/whatisedge.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing a system where a Lambda function processes messages from an SQS queue. Occasionally, some messages fail repeatedly. What should the architect configure to prevent infinite retries?', '[{"id":"a","text":"Set the SQS visibility timeout to 0","is_correct":false,"explanation":"A visibility timeout of 0 would cause immediate reprocessing, worsening the problem."},{"id":"b","text":"Configure a dead-letter queue with a maximum receive count","is_correct":true,"explanation":"A DLQ captures messages that exceed the maximum receive count, preventing infinite retries."},{"id":"c","text":"Set the Lambda function timeout to 1 second","is_correct":false,"explanation":"A short timeout may cause more failures, not prevent retries."},{"id":"d","text":"Enable long polling on the SQS queue","is_correct":false,"explanation":"Long polling reduces empty responses but does not handle failed messages."}]', 'A dead-letter queue with a configured maximum receive count isolates messages that repeatedly fail processing, allowing investigation without blocking the main queue.', 2, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/sqs-dead-letter-queues.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A healthcare application stores sensitive patient data. The architect must ensure that S3 objects cannot be deleted or overwritten for 7 years to meet compliance. Which S3 feature should be used?', '[{"id":"a","text":"S3 versioning with MFA delete","is_correct":false,"explanation":"MFA delete adds protection but does not enforce immutable retention periods."},{"id":"b","text":"S3 Object Lock in compliance mode with a 7-year retention period","is_correct":true,"explanation":"Object Lock in compliance mode prevents anyone, including the root user, from deleting objects during the retention period."},{"id":"c","text":"S3 bucket policy denying s3:DeleteObject","is_correct":false,"explanation":"Bucket policies can be modified by administrators, so they do not guarantee immutability."},{"id":"d","text":"S3 Glacier Vault Lock","is_correct":false,"explanation":"Glacier Vault Lock applies to Glacier vaults, not S3 buckets directly."}]', 'S3 Object Lock in compliance mode creates a WORM (Write Once Read Many) storage model where objects cannot be deleted or overwritten by anyone during the retention period.', 4, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/object-lock.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses AWS CloudFormation to manage infrastructure. They want to detect when manually created resources drift from the template. Which feature should be used?', '[{"id":"a","text":"CloudFormation change sets","is_correct":false,"explanation":"Change sets preview changes before updates but do not detect manual modifications."},{"id":"b","text":"CloudFormation drift detection","is_correct":true,"explanation":"Drift detection identifies resources whose actual configuration differs from the template definition."},{"id":"c","text":"AWS Config rules","is_correct":false,"explanation":"Config rules evaluate compliance but are not specific to CloudFormation template drift."},{"id":"d","text":"CloudFormation stack policies","is_correct":false,"explanation":"Stack policies prevent updates to specific resources but do not detect drift."}]', 'CloudFormation drift detection compares the actual resource configuration with the template definition, identifying any manual changes made outside of CloudFormation.', 2, 'https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/using-cfn-stack-drift.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to share an Amazon AMI with another AWS account in a different organization. Which approach is correct?', '[{"id":"a","text":"Copy the AMI to an S3 bucket and share the bucket with the other account","is_correct":false,"explanation":"AMIs cannot be shared by copying to S3."},{"id":"b","text":"Modify the AMI launch permissions to include the target account ID","is_correct":true,"explanation":"AMI launch permissions allow sharing with specific AWS account IDs."},{"id":"c","text":"Create an IAM cross-account role for the other account to copy the AMI","is_correct":false,"explanation":"IAM roles cannot directly share AMI launch permissions."},{"id":"d","text":"Use AWS RAM to share the AMI","is_correct":false,"explanation":"AWS RAM does not support sharing AMIs directly."}]', 'AMI launch permissions can be modified to grant specific AWS accounts permission to launch instances from the AMI, enabling cross-account sharing.', 2, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/sharingamis-explicit.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a batch processing workload on EC2 instances. Jobs are fault-tolerant and can be interrupted. The workload runs for 2-3 hours daily. Which purchasing option is MOST cost-effective?', '[{"id":"a","text":"On-Demand instances","is_correct":false,"explanation":"On-Demand pricing is the highest for interruptible, short workloads."},{"id":"b","text":"Spot instances with Spot Fleet","is_correct":true,"explanation":"Spot instances provide up to 90% savings and are ideal for fault-tolerant, interruptible workloads."},{"id":"c","text":"1-year Reserved Instances","is_correct":false,"explanation":"Reserved Instances are cost-effective for steady-state workloads, not 2-3 hour daily jobs."},{"id":"d","text":"Dedicated Hosts","is_correct":false,"explanation":"Dedicated Hosts are the most expensive option and are used for licensing requirements."}]', 'Spot instances leverage unused EC2 capacity at up to 90% discount. Spot Fleet diversifies across instance types and AZs to minimize interruption impact.', 2, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/using-spot-instances.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Amazon RDS Multi-AZ for a production database. During a planned maintenance window, how does RDS perform updates?', '[{"id":"a","text":"The primary instance is updated, causing downtime during the maintenance window","is_correct":false,"explanation":"Multi-AZ deployments minimize downtime during maintenance."},{"id":"b","text":"The standby instance is updated first, then a failover promotes it to primary","is_correct":true,"explanation":"RDS updates the standby first, performs failover, then updates the old primary, minimizing downtime."},{"id":"c","text":"Both instances are updated simultaneously","is_correct":false,"explanation":"Simultaneous updates would eliminate the availability benefit of Multi-AZ."},{"id":"d","text":"A new instance is created with the update and DNS is switched","is_correct":false,"explanation":"RDS does not create new instances for maintenance updates."}]', 'In Multi-AZ deployments, RDS applies updates to the standby first, fails over to make it the new primary, then updates the former primary, minimizing downtime to the failover duration.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/Concepts.MultiAZSingleStandby.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application needs to process video files immediately after upload to S3. Processing takes 30 minutes per file. Which architecture handles this reliably?', '[{"id":"a","text":"S3 event notification → Lambda function for processing","is_correct":false,"explanation":"Lambda has a 15-minute timeout, which is insufficient for 30-minute processing."},{"id":"b","text":"S3 event notification → SQS queue → ECS Fargate task","is_correct":true,"explanation":"SQS durably queues the event, and ECS Fargate runs long-duration processing without timeout limits."},{"id":"c","text":"S3 event notification → Step Functions → Lambda","is_correct":false,"explanation":"Lambda still has the 15-minute timeout regardless of the orchestrator."},{"id":"d","text":"CloudWatch Events rule triggered by S3 PutObject metric","is_correct":false,"explanation":"CloudWatch metrics have multi-minute delays and are not event-driven."}]', 'SQS provides durable message storage while ECS Fargate allows long-running container tasks without timeout constraints, making it ideal for 30-minute video processing.', 3, 'https://docs.aws.amazon.com/AmazonECS/latest/developerguide/AWS_Fargate.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to implement blue-green deployments for their application running on EC2 instances behind an ALB. Which AWS service simplifies this process?', '[{"id":"a","text":"AWS CodeDeploy with blue-green deployment type","is_correct":true,"explanation":"CodeDeploy automates blue-green deployments by provisioning a new environment and switching traffic."},{"id":"b","text":"AWS CloudFormation with stack updates","is_correct":false,"explanation":"CloudFormation performs in-place updates by default, not blue-green deployments."},{"id":"c","text":"AWS Elastic Beanstalk with rolling updates","is_correct":false,"explanation":"Rolling updates are not the same as blue-green deployments."},{"id":"d","text":"AWS OpsWorks with Chef recipes","is_correct":false,"explanation":"OpsWorks does not natively support blue-green deployments."}]', 'AWS CodeDeploy blue-green deployments create a replacement environment, shift traffic via the ALB, and provide automatic rollback if deployment health checks fail.', 3, 'https://docs.aws.amazon.com/codedeploy/latest/userguide/deployments-create-blue-green.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has multiple AWS accounts managed by AWS Organizations. They want to share a common VPC subnet with workloads in other accounts. Which feature enables this?', '[{"id":"a","text":"VPC peering between accounts","is_correct":false,"explanation":"VPC peering connects VPCs but does not share subnets."},{"id":"b","text":"AWS RAM (Resource Access Manager) to share VPC subnets","is_correct":true,"explanation":"RAM allows sharing VPC subnets with other accounts in the organization, enabling resource deployment in shared subnets."},{"id":"c","text":"Transit Gateway with cross-account attachments","is_correct":false,"explanation":"Transit Gateway connects VPCs but does not share subnets."},{"id":"d","text":"AWS PrivateLink interface endpoints","is_correct":false,"explanation":"PrivateLink provides private connectivity to services, not subnet sharing."}]', 'AWS RAM enables sharing VPC subnets across accounts within an organization, allowing multiple accounts to deploy resources in a centrally managed VPC.', 3, 'https://docs.aws.amazon.com/ram/latest/userguide/shareable.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing a system that must handle 100,000 concurrent WebSocket connections for a real-time chat application. Which service supports this?', '[{"id":"a","text":"Amazon API Gateway REST API","is_correct":false,"explanation":"REST APIs do not support persistent WebSocket connections."},{"id":"b","text":"Amazon API Gateway WebSocket API","is_correct":true,"explanation":"API Gateway WebSocket APIs support persistent connections and scale to handle millions of concurrent connections."},{"id":"c","text":"Application Load Balancer with sticky sessions","is_correct":false,"explanation":"ALB supports WebSocket upgrade but does not manage connection state like API Gateway."},{"id":"d","text":"Amazon CloudFront with origin failover","is_correct":false,"explanation":"CloudFront is a CDN and does not manage WebSocket connections."}]', 'API Gateway WebSocket APIs provide fully managed WebSocket connection management, automatic scaling, and integration with Lambda and other AWS services for real-time applications.', 3, 'https://docs.aws.amazon.com/apigateway/latest/developerguide/apigateway-websocket-api.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to run a high-performance computing (HPC) workload that requires low-latency network communication between instances. Which EC2 feature should be used?', '[{"id":"a","text":"Enhanced networking with Elastic Network Adapter (ENA)","is_correct":false,"explanation":"ENA improves throughput but does not provide the lowest inter-instance latency."},{"id":"b","text":"EC2 placement group with cluster strategy","is_correct":true,"explanation":"Cluster placement groups place instances in the same AZ on low-latency network segments."},{"id":"c","text":"EC2 Dedicated Hosts","is_correct":false,"explanation":"Dedicated Hosts provide dedicated hardware but do not optimize inter-instance networking."},{"id":"d","text":"EC2 instances with multiple ENIs","is_correct":false,"explanation":"Multiple ENIs provide additional interfaces but do not reduce inter-instance latency."}]', 'Cluster placement groups pack instances close together in a single AZ, providing the lowest possible network latency between instances for HPC and tightly coupled workloads.', 3, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/placement-groups.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an on-premises MySQL database with 500 GB of data. They want to migrate to Aurora MySQL with minimal downtime. Which migration approach should be used?', '[{"id":"a","text":"Export data using mysqldump, upload to S3, and import into Aurora","is_correct":false,"explanation":"mysqldump import causes significant downtime for 500 GB of data."},{"id":"b","text":"Use AWS DMS with ongoing replication for near-zero downtime migration","is_correct":true,"explanation":"DMS performs a full load followed by continuous replication (CDC), enabling cutover with minimal downtime."},{"id":"c","text":"Create an Aurora read replica of the on-premises MySQL instance","is_correct":false,"explanation":"Aurora cannot create a direct read replica of an on-premises MySQL instance."},{"id":"d","text":"Use S3 Transfer Acceleration to upload the database backup","is_correct":false,"explanation":"Transfer Acceleration speeds uploads but does not address migration downtime."}]', 'AWS DMS performs an initial full load migration followed by continuous change data capture (CDC), keeping the target synchronized until cutover with minimal downtime.', 3, 'https://docs.aws.amazon.com/dms/latest/userguide/Welcome.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs an API that experiences predictable traffic spikes every weekday from 9 AM to 5 PM. Outside those hours, traffic drops to near zero. Which Auto Scaling approach is MOST cost-effective?', '[{"id":"a","text":"Target tracking scaling based on CPU utilization","is_correct":false,"explanation":"Target tracking is reactive and may not scale fast enough for predictable patterns."},{"id":"b","text":"Scheduled scaling to increase capacity at 8:45 AM and decrease at 5:15 PM","is_correct":true,"explanation":"Scheduled scaling pre-provisions capacity for known traffic patterns, ensuring readiness."},{"id":"c","text":"Manual scaling each morning","is_correct":false,"explanation":"Manual scaling is error-prone and not operationally efficient."},{"id":"d","text":"Maintain peak capacity at all times","is_correct":false,"explanation":"Running peak capacity 24/7 wastes money during off-hours."}]', 'Scheduled scaling proactively adjusts capacity based on known traffic patterns, ensuring resources are available before demand increases and removed when traffic drops.', 2, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/ec2-auto-scaling-scheduled-scaling.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect needs to implement cross-Region read replicas for an Aurora MySQL database. Which benefit does this provide?', '[{"id":"a","text":"Automatic multi-Region write capability","is_correct":false,"explanation":"Cross-Region read replicas are read-only; writes go to the primary Region."},{"id":"b","text":"Lower read latency for users in the secondary Region and a DR promotion target","is_correct":true,"explanation":"Cross-Region replicas serve reads locally and can be promoted to a standalone cluster in a DR scenario."},{"id":"c","text":"Automatic conflict resolution for multi-Region writes","is_correct":false,"explanation":"Read replicas do not support writes or conflict resolution."},{"id":"d","text":"Reduced storage costs by deduplicating data across Regions","is_correct":false,"explanation":"Each Region maintains its own full copy of the data."}]', 'Aurora cross-Region read replicas serve read traffic with low latency in the secondary Region and can be promoted to a standalone cluster for disaster recovery.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/AuroraMySQL.Replication.CrossRegion.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing an event-driven architecture using Amazon EventBridge. The system must trigger different workflows based on the event source and type. Which EventBridge feature enables this?', '[{"id":"a","text":"Event buses with custom rules and event patterns","is_correct":true,"explanation":"EventBridge rules use event patterns to match specific event sources and types, routing to different targets."},{"id":"b","text":"EventBridge Scheduler for time-based triggers","is_correct":false,"explanation":"Scheduler triggers based on time, not event patterns."},{"id":"c","text":"EventBridge Pipes for point-to-point integration","is_correct":false,"explanation":"Pipes connect a source to a target but do not provide pattern-based routing."},{"id":"d","text":"EventBridge Schema Registry","is_correct":false,"explanation":"Schema Registry discovers and stores event schemas but does not route events."}]', 'EventBridge rules use event patterns (JSON-based matching) to filter events by source, detail-type, and other attributes, routing matching events to specific targets.', 3, 'https://docs.aws.amazon.com/eventbridge/latest/userguide/eb-event-patterns.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an Amazon S3 bucket that receives 10,000 PUT requests per second. Some requests are failing with HTTP 503 errors. What is the MOST likely cause and solution?', '[{"id":"a","text":"S3 has a hard limit of 5,000 PUTs per second; the bucket must be split","is_correct":false,"explanation":"S3 supports 3,500 PUTs per second per prefix and scales automatically."},{"id":"b","text":"Use randomized prefixes in object keys to distribute load across partitions","is_correct":true,"explanation":"S3 partitions based on key prefixes; distributing keys prevents hot partitions."},{"id":"c","text":"Enable S3 Transfer Acceleration","is_correct":false,"explanation":"Transfer Acceleration improves upload speed over long distances but does not solve partition throttling."},{"id":"d","text":"Switch to S3 Intelligent-Tiering","is_correct":false,"explanation":"Storage class does not affect request rate limits."}]', 'S3 supports 3,500 PUT and 5,500 GET requests per second per prefix. Distributing objects across multiple prefixes avoids hot partitions and 503 errors.', 4, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/optimizing-performance.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs a fully managed file system that supports the SMB protocol for Windows-based workloads migrating to AWS. Which service should be used?', '[{"id":"a","text":"Amazon EFS","is_correct":false,"explanation":"EFS uses the NFS protocol, not SMB."},{"id":"b","text":"Amazon FSx for Windows File Server","is_correct":true,"explanation":"FSx for Windows provides fully managed Windows file shares with native SMB protocol support."},{"id":"c","text":"Amazon S3 with a file gateway","is_correct":false,"explanation":"S3 with file gateway provides NFS/SMB but stores data as objects, not as a true file system."},{"id":"d","text":"Amazon FSx for Lustre","is_correct":false,"explanation":"FSx for Lustre is a high-performance file system for compute workloads, not Windows SMB."}]', 'Amazon FSx for Windows File Server provides fully managed, highly available Windows file shares with native SMB support, Active Directory integration, and DFS namespaces.', 2, 'https://docs.aws.amazon.com/fsx/latest/WindowsGuide/what-is.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an application that stores data in DynamoDB. They need to capture all changes to items and trigger processing workflows. Which DynamoDB feature enables this?', '[{"id":"a","text":"DynamoDB on-demand backup","is_correct":false,"explanation":"On-demand backups capture point-in-time snapshots, not real-time changes."},{"id":"b","text":"DynamoDB Streams","is_correct":true,"explanation":"DynamoDB Streams captures item-level changes in near real-time, which can trigger Lambda functions."},{"id":"c","text":"DynamoDB Global Tables","is_correct":false,"explanation":"Global Tables replicate across Regions but do not provide change capture for processing."},{"id":"d","text":"DynamoDB Time to Live (TTL)","is_correct":false,"explanation":"TTL automatically deletes expired items but does not capture changes."}]', 'DynamoDB Streams provides a time-ordered sequence of item-level modifications, enabling event-driven architectures where Lambda functions process each change.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/Streams.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect wants to implement a pilot light disaster recovery strategy. Which components should be running in the DR Region?', '[{"id":"a","text":"Full production infrastructure at reduced capacity","is_correct":false,"explanation":"Full infrastructure at reduced capacity is a warm standby strategy."},{"id":"b","text":"Only the database with replication; compute infrastructure is pre-configured but turned off","is_correct":true,"explanation":"Pilot light keeps the core database running with replication while other resources are provisioned only during failover."},{"id":"c","text":"No infrastructure; everything is provisioned from scratch during failover","is_correct":false,"explanation":"Provisioning from scratch is a backup and restore strategy."},{"id":"d","text":"Active-active infrastructure serving production traffic","is_correct":false,"explanation":"Active-active is the most expensive DR strategy."}]', 'Pilot light maintains the minimal critical core (typically the database with continuous replication) in the DR Region, while application servers and other resources are provisioned during failover.', 3, 'https://docs.aws.amazon.com/whitepapers/latest/disaster-recovery-workloads-on-aws/disaster-recovery-options-in-the-cloud.html', 'SAA-C03-1.1', true, true)
,
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to ensure high availability for their Amazon RDS PostgreSQL database. The database handles mixed read/write workloads. Which configuration provides automatic failover with minimal data loss?', '[{"id":"a","text":"RDS Single-AZ with automated backups","is_correct":false,"explanation":"Single-AZ does not provide automatic failover."},{"id":"b","text":"RDS Multi-AZ deployment with synchronous standby replication","is_correct":true,"explanation":"Multi-AZ maintains a synchronous standby replica that is automatically promoted during failure."},{"id":"c","text":"RDS with a cross-Region read replica","is_correct":false,"explanation":"Cross-Region replicas use asynchronous replication and require manual promotion."},{"id":"d","text":"RDS on EC2 with custom replication scripts","is_correct":false,"explanation":"Managing replication manually is error-prone and not a managed solution."}]', 'RDS Multi-AZ maintains a synchronous standby in another AZ. During failure, RDS automatically promotes the standby with minimal data loss and updates the DNS endpoint.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/Concepts.MultiAZSingleStandby.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to host a static website with a custom domain and HTTPS. Which combination of services should be used?', '[{"id":"a","text":"EC2 instance with Apache and a self-signed certificate","is_correct":false,"explanation":"EC2 for static hosting is over-engineered and a self-signed certificate causes browser warnings."},{"id":"b","text":"S3 static website hosting with CloudFront and ACM certificate","is_correct":true,"explanation":"S3 hosts static content, CloudFront distributes globally, and ACM provides free SSL/TLS certificates."},{"id":"c","text":"AWS Amplify with Route 53 only","is_correct":false,"explanation":"Amplify is a valid option but does not use ACM for custom domain HTTPS in the same way."},{"id":"d","text":"Amazon Lightsail with a load balancer","is_correct":false,"explanation":"Lightsail is over-engineered for a static website."}]', 'S3 for hosting, CloudFront for global distribution and HTTPS termination, and ACM for free SSL/TLS certificates is the standard, cost-effective architecture for static websites.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/WebsiteHosting.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application uses DynamoDB and requires strongly consistent reads across all requests. What is the trade-off of enabling strongly consistent reads?', '[{"id":"a","text":"Higher latency and double the read capacity unit consumption","is_correct":true,"explanation":"Strongly consistent reads consume twice the RCU and may have higher latency due to reading from the leader node."},{"id":"b","text":"Lower availability because reads are limited to a single AZ","is_correct":false,"explanation":"DynamoDB maintains availability even with strongly consistent reads."},{"id":"c","text":"No trade-off; strong consistency is the default","is_correct":false,"explanation":"Eventually consistent reads are the default and consume fewer RCUs."},{"id":"d","text":"Writes become slower due to synchronous replication","is_correct":false,"explanation":"Read consistency settings do not affect write performance."}]', 'Strongly consistent reads in DynamoDB consume double the read capacity units compared to eventually consistent reads and must read from the leader storage node.', 3, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/HowItWorks.ReadConsistency.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a critical application across two AWS Regions. They need the database to accept writes in both Regions simultaneously. Which database solution supports this?', '[{"id":"a","text":"Amazon RDS with cross-Region read replicas","is_correct":false,"explanation":"Read replicas are read-only and do not accept writes."},{"id":"b","text":"Amazon DynamoDB Global Tables","is_correct":true,"explanation":"DynamoDB Global Tables provide multi-Region, multi-active replication with writes accepted in any Region."},{"id":"c","text":"Amazon Aurora with cross-Region read replicas","is_correct":false,"explanation":"Aurora cross-Region replicas are read-only."},{"id":"d","text":"Amazon ElastiCache Global Datastore","is_correct":false,"explanation":"ElastiCache Global Datastore supports reads in secondary Regions but writes only in the primary."}]', 'DynamoDB Global Tables provide fully replicated, multi-Region tables that accept read and write operations in any Region with automatic conflict resolution.', 3, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/GlobalTables.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to automatically distribute incoming application traffic across multiple targets in multiple AZs. The application uses HTTP/2 and requires path-based routing. Which load balancer type should be used?', '[{"id":"a","text":"Classic Load Balancer","is_correct":false,"explanation":"Classic Load Balancer does not support HTTP/2 or path-based routing."},{"id":"b","text":"Application Load Balancer","is_correct":true,"explanation":"ALB supports HTTP/2, path-based routing, host-based routing, and operates at Layer 7."},{"id":"c","text":"Network Load Balancer","is_correct":false,"explanation":"NLB operates at Layer 4 and does not support path-based routing."},{"id":"d","text":"Gateway Load Balancer","is_correct":false,"explanation":"GWLB is for deploying third-party virtual appliances, not application traffic routing."}]', 'Application Load Balancer operates at Layer 7 (HTTP/HTTPS), supports HTTP/2, and provides advanced routing rules including path-based and host-based routing.', 2, 'https://docs.aws.amazon.com/elasticloadbalancing/latest/application/introduction.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to store configuration data that Lambda functions access at runtime. The data includes database connection strings and API keys. Which service provides secure, centralized configuration management?', '[{"id":"a","text":"Amazon S3 with SSE-S3 encryption","is_correct":false,"explanation":"S3 is not designed for configuration management and adds latency."},{"id":"b","text":"AWS Systems Manager Parameter Store with SecureString parameters","is_correct":true,"explanation":"Parameter Store provides centralized, encrypted configuration management with KMS integration."},{"id":"c","text":"Environment variables in Lambda function configuration","is_correct":false,"explanation":"Environment variables are decentralized and harder to manage across multiple functions."},{"id":"d","text":"Amazon DynamoDB table with encryption at rest","is_correct":false,"explanation":"DynamoDB adds unnecessary complexity for simple configuration data."}]', 'Systems Manager Parameter Store provides hierarchical, versioned storage for configuration data with SecureString encryption using KMS, and integrates natively with Lambda.', 2, 'https://docs.aws.amazon.com/systems-manager/latest/userguide/systems-manager-parameter-store.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect needs to design a solution where an EC2 Auto Scaling group scales based on the number of messages in an SQS queue. Which scaling approach should be used?', '[{"id":"a","text":"Simple scaling with CloudWatch alarm on ApproximateNumberOfMessagesVisible","is_correct":false,"explanation":"Simple scaling is less responsive and does not account for instances already processing."},{"id":"b","text":"Target tracking scaling with a custom metric: messages per instance","is_correct":true,"explanation":"A custom metric dividing queue depth by running instances provides optimal scaling based on actual load per instance."},{"id":"c","text":"Step scaling based on CPU utilization","is_correct":false,"explanation":"CPU utilization does not reflect queue depth."},{"id":"d","text":"Scheduled scaling based on historical patterns","is_correct":false,"explanation":"Scheduled scaling cannot respond to variable queue depths."}]', 'A custom metric that divides ApproximateNumberOfMessagesVisible by the number of running instances provides target tracking with accurate per-instance load measurement.', 4, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/as-using-sqs-dead-letter-queue.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is designing a multi-account strategy using AWS Organizations. They want to prevent any account from launching EC2 instances in Regions outside of us-east-1 and eu-west-1. Which mechanism should be used?', '[{"id":"a","text":"IAM policies attached to every IAM user in each account","is_correct":false,"explanation":"IAM policies per user are not scalable and can be overridden by administrators."},{"id":"b","text":"Service Control Policies (SCPs) denying ec2:RunInstances outside allowed Regions","is_correct":true,"explanation":"SCPs provide organization-wide guardrails that cannot be overridden by individual account administrators."},{"id":"c","text":"AWS Config rules to detect non-compliant instances","is_correct":false,"explanation":"Config rules detect but do not prevent non-compliant resource creation."},{"id":"d","text":"VPC configurations that block traffic in restricted Regions","is_correct":false,"explanation":"VPC configurations do not prevent resource creation."}]', 'Service Control Policies in AWS Organizations provide a permissions guardrail that restricts actions across all accounts, including preventing resource creation in unauthorized Regions.', 3, 'https://docs.aws.amazon.com/organizations/latest/userguide/orgs_manage_policies_scps.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an application that generates temporary files during processing. These files are only needed for the duration of the EC2 instance lifetime. Which storage option provides the highest I/O performance?', '[{"id":"a","text":"Amazon EBS gp3 volume","is_correct":false,"explanation":"EBS provides persistent storage with good performance but not the highest I/O for temporary data."},{"id":"b","text":"EC2 instance store (ephemeral storage)","is_correct":true,"explanation":"Instance store provides the highest I/O performance as it is physically attached to the host, ideal for temporary data."},{"id":"c","text":"Amazon EFS Standard","is_correct":false,"explanation":"EFS is a network file system with higher latency than local storage."},{"id":"d","text":"Amazon S3 with VPC endpoint","is_correct":false,"explanation":"S3 is object storage with higher latency than local storage."}]', 'EC2 instance store volumes provide the highest I/O performance because they are physically attached NVMe SSDs on the host server, ideal for temporary, non-persistent data.', 2, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/InstanceStorage.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A solutions architect is implementing defense in depth for a web application. (Select TWO) Which AWS services provide protection at the network edge?', '[{"id":"a","text":"AWS WAF","is_correct":true,"explanation":"WAF inspects HTTP/HTTPS requests at the edge, blocking malicious traffic."},{"id":"b","text":"AWS Shield Advanced","is_correct":true,"explanation":"Shield Advanced provides DDoS protection at the network edge with 24/7 DRT support."},{"id":"c","text":"Amazon Inspector","is_correct":false,"explanation":"Inspector assesses EC2 instance vulnerabilities, not network edge protection."},{"id":"d","text":"Amazon GuardDuty","is_correct":false,"explanation":"GuardDuty provides threat detection from logs, not edge-level protection."}]', 'AWS WAF filters malicious web requests and Shield Advanced provides DDoS mitigation, both operating at the network edge through CloudFront and ALB integrations.', 3, 'https://docs.aws.amazon.com/waf/latest/developerguide/what-is-aws-waf.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has a data lake in S3 and wants to run SQL queries on the data without loading it into a database. Which serverless service should be used?', '[{"id":"a","text":"Amazon Redshift","is_correct":false,"explanation":"Redshift requires provisioned clusters (unless using Serverless) and loads data."},{"id":"b","text":"Amazon Athena","is_correct":true,"explanation":"Athena is a serverless query service that runs SQL directly on data in S3 without loading."},{"id":"c","text":"Amazon RDS","is_correct":false,"explanation":"RDS requires data to be loaded into the database."},{"id":"d","text":"AWS Glue ETL","is_correct":false,"explanation":"Glue performs ETL transformations but is not a SQL query service."}]', 'Amazon Athena is a serverless, interactive query service that uses standard SQL to analyze data directly in Amazon S3 without requiring data loading or infrastructure management.', 2, 'https://docs.aws.amazon.com/athena/latest/ug/what-is.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application uses Amazon Cognito for user authentication. The architect needs to support social identity providers like Google and Facebook alongside email/password sign-in. Which Cognito component handles this?', '[{"id":"a","text":"Cognito Identity Pools","is_correct":false,"explanation":"Identity Pools provide temporary AWS credentials, not user authentication."},{"id":"b","text":"Cognito User Pools with federated identity providers","is_correct":true,"explanation":"User Pools support built-in sign-up/sign-in and federation with social and enterprise identity providers."},{"id":"c","text":"Cognito Sync","is_correct":false,"explanation":"Cognito Sync synchronizes user data across devices, not authentication."},{"id":"d","text":"AWS IAM SAML federation","is_correct":false,"explanation":"IAM SAML federation is for enterprise SSO to AWS console, not application authentication."}]', 'Cognito User Pools provide a complete user directory with built-in authentication and support for federating with social providers (Google, Facebook, Apple) and SAML/OIDC providers.', 2, 'https://docs.aws.amazon.com/cognito/latest/developerguide/cognito-user-pools-identity-federation.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to enable encryption in transit for an Amazon RDS MySQL database. Which approach should be used?', '[{"id":"a","text":"Enable EBS encryption on the RDS instance","is_correct":false,"explanation":"EBS encryption protects data at rest, not in transit."},{"id":"b","text":"Configure the RDS instance to use SSL/TLS and require SSL connections in the MySQL parameter group","is_correct":true,"explanation":"RDS supports SSL/TLS connections, and the require_secure_transport parameter enforces encryption in transit."},{"id":"c","text":"Place the RDS instance behind a Network Load Balancer with TLS termination","is_correct":false,"explanation":"NLB TLS termination adds complexity and RDS already supports native SSL."},{"id":"d","text":"Use a VPN connection between the application and RDS","is_correct":false,"explanation":"VPN adds unnecessary overhead when native SSL is available."}]', 'RDS provides SSL/TLS certificates for encrypted connections. Setting require_secure_transport=ON in the parameter group forces all clients to use encrypted connections.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/UsingWithRDS.SSL.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to implement a queue that guarantees exactly-once processing and preserves message ordering. Which SQS queue type should be used?', '[{"id":"a","text":"SQS Standard queue with deduplication logic in the consumer","is_correct":false,"explanation":"Standard queues provide at-least-once delivery and best-effort ordering."},{"id":"b","text":"SQS FIFO queue with message deduplication enabled","is_correct":true,"explanation":"FIFO queues guarantee exactly-once processing and strict message ordering."},{"id":"c","text":"SQS Standard queue with long polling","is_correct":false,"explanation":"Long polling reduces empty responses but does not guarantee ordering or deduplication."},{"id":"d","text":"Amazon MQ with RabbitMQ","is_correct":false,"explanation":"Amazon MQ requires managing broker instances and is not a managed SQS feature."}]', 'SQS FIFO queues guarantee exactly-once processing through deduplication and preserve strict message ordering within message groups, with throughput up to 3,000 messages/second.', 2, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/FIFO-queues.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to use Amazon CloudFront to serve content from an S3 bucket. They must ensure that users cannot bypass CloudFront and access S3 directly. Which feature should be configured?', '[{"id":"a","text":"S3 bucket policy allowing only public read access","is_correct":false,"explanation":"Public access allows anyone to bypass CloudFront."},{"id":"b","text":"CloudFront Origin Access Control (OAC) with S3 bucket policy restricting access to the OAC","is_correct":true,"explanation":"OAC restricts S3 access to only CloudFront, preventing direct S3 access."},{"id":"c","text":"CloudFront signed URLs for all requests","is_correct":false,"explanation":"Signed URLs restrict who can access content but do not prevent direct S3 access."},{"id":"d","text":"S3 Block Public Access settings","is_correct":false,"explanation":"Block Public Access alone would prevent CloudFront from accessing the bucket without proper OAC configuration."}]', 'CloudFront Origin Access Control (OAC) provides a secure way to restrict S3 access so content can only be served through CloudFront, not by direct S3 URLs.', 3, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/private-content-restricting-access-to-s3.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company operates a microservices architecture with services communicating via REST APIs. They want to implement distributed tracing to identify performance bottlenecks. Which AWS service should be used?', '[{"id":"a","text":"Amazon CloudWatch Logs","is_correct":false,"explanation":"CloudWatch Logs collects log data but does not provide distributed tracing."},{"id":"b","text":"AWS X-Ray","is_correct":true,"explanation":"X-Ray provides distributed tracing, service maps, and performance analysis for microservices."},{"id":"c","text":"AWS CloudTrail","is_correct":false,"explanation":"CloudTrail logs API calls for auditing, not application-level tracing."},{"id":"d","text":"Amazon EventBridge","is_correct":false,"explanation":"EventBridge routes events but does not trace requests across services."}]', 'AWS X-Ray traces requests as they flow through distributed services, creating a visual service map and identifying latency bottlenecks, errors, and throttling issues.', 2, 'https://docs.aws.amazon.com/xray/latest/devguide/aws-xray.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to run a Windows-based .NET application with a SQL Server database on AWS. They want a fully managed solution. Which combination of services should be used?', '[{"id":"a","text":"EC2 Windows instances with SQL Server installed manually","is_correct":false,"explanation":"Manual installation increases operational burden."},{"id":"b","text":"AWS Elastic Beanstalk for the .NET application and Amazon RDS for SQL Server","is_correct":true,"explanation":"Elastic Beanstalk manages the .NET deployment and RDS provides fully managed SQL Server."},{"id":"c","text":"Amazon ECS on Fargate with Aurora PostgreSQL","is_correct":false,"explanation":"Aurora PostgreSQL is not compatible with SQL Server applications without code changes."},{"id":"d","text":"AWS Lambda with .NET runtime and DynamoDB","is_correct":false,"explanation":"This requires significant application refactoring from a traditional .NET app."}]', 'Elastic Beanstalk supports .NET applications on Windows Server and handles deployment, scaling, and monitoring. RDS for SQL Server provides a fully managed database engine.', 2, 'https://docs.aws.amazon.com/elasticbeanstalk/latest/dg/create_deploy_NET.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect needs to ensure that an Auto Scaling group launches instances evenly across Availability Zones. Which Auto Scaling feature provides this?', '[{"id":"a","text":"Launch template with multiple subnet configurations","is_correct":false,"explanation":"Launch templates define instance configuration, not AZ distribution."},{"id":"b","text":"AZ rebalancing (enabled by default)","is_correct":true,"explanation":"Auto Scaling automatically attempts to distribute instances evenly across the specified AZs."},{"id":"c","text":"Placement groups with spread strategy","is_correct":false,"explanation":"Spread placement groups limit instances per AZ rack, not overall AZ distribution."},{"id":"d","text":"Target tracking scaling policy","is_correct":false,"explanation":"Scaling policies control when to scale, not where instances are placed."}]', 'Auto Scaling groups automatically balance instances across specified AZs. When imbalanced (e.g., after an AZ recovery), AZ rebalancing launches new instances in under-represented AZs.', 2, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/auto-scaling-benefits.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has a workload that requires exactly 100 Gbps of dedicated network bandwidth between their data center and AWS. Which connectivity option should they choose?', '[{"id":"a","text":"AWS Site-to-Site VPN with two tunnels","is_correct":false,"explanation":"VPN over the internet cannot guarantee 100 Gbps bandwidth."},{"id":"b","text":"AWS Direct Connect with a 100 Gbps dedicated connection","is_correct":true,"explanation":"Direct Connect offers dedicated connections up to 100 Gbps for consistent, high-bandwidth connectivity."},{"id":"c","text":"AWS Direct Connect with multiple 10 Gbps connections using LAG","is_correct":false,"explanation":"While LAG aggregates connections, a single 100 Gbps port is simpler and meets the requirement."},{"id":"d","text":"AWS Transit Gateway with VPN attachment","is_correct":false,"explanation":"Transit Gateway VPN attachments are limited by VPN throughput over the internet."}]', 'AWS Direct Connect provides dedicated 100 Gbps connections between on-premises data centers and AWS, offering consistent bandwidth, lower latency, and reduced data transfer costs.', 3, 'https://docs.aws.amazon.com/directconnect/latest/UserGuide/Welcome.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company stores sensitive documents in S3 and needs to prevent accidental public access across all buckets. Which feature provides account-level protection?', '[{"id":"a","text":"S3 bucket policies on each bucket","is_correct":false,"explanation":"Bucket policies must be configured individually and can be misconfigured."},{"id":"b","text":"S3 Block Public Access settings at the account level","is_correct":true,"explanation":"Account-level Block Public Access prevents any bucket in the account from being made public."},{"id":"c","text":"IAM policy denying s3:PutBucketPolicy","is_correct":false,"explanation":"This prevents policy changes but does not block ACL-based public access."},{"id":"d","text":"AWS Config rule for s3-bucket-public-read-prohibited","is_correct":false,"explanation":"Config rules detect but do not prevent public access."}]', 'S3 Block Public Access at the account level overrides any bucket policy or ACL that would grant public access, providing a single safeguard across all buckets.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/access-control-block-public-access.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application requires a NoSQL database with single-digit millisecond latency at any scale. The data model uses key-value and document access patterns. Which service should be used?', '[{"id":"a","text":"Amazon RDS","is_correct":false,"explanation":"RDS is a relational database, not optimized for key-value access patterns."},{"id":"b","text":"Amazon DynamoDB","is_correct":true,"explanation":"DynamoDB provides single-digit millisecond latency at any scale for key-value and document workloads."},{"id":"c","text":"Amazon Neptune","is_correct":false,"explanation":"Neptune is a graph database optimized for relationship queries."},{"id":"d","text":"Amazon DocumentDB","is_correct":false,"explanation":"DocumentDB is MongoDB-compatible but does not match DynamoDB''s key-value performance at scale."}]', 'DynamoDB is a fully managed NoSQL database that delivers single-digit millisecond performance at any scale, supporting both key-value and document data models.', 1, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/Introduction.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is using AWS Lambda functions that need to connect to resources in a VPC (such as RDS). What must be configured to enable VPC access from Lambda?', '[{"id":"a","text":"Attach an Elastic IP to each Lambda function","is_correct":false,"explanation":"Lambda functions do not directly use Elastic IPs."},{"id":"b","text":"Configure the Lambda function with VPC subnets and a security group","is_correct":true,"explanation":"Lambda creates ENIs in the specified subnets and applies the security group for VPC connectivity."},{"id":"c","text":"Create a VPN connection between Lambda and the VPC","is_correct":false,"explanation":"Lambda uses ENIs for VPC access, not VPN."},{"id":"d","text":"Deploy the Lambda function on a Dedicated Host","is_correct":false,"explanation":"Lambda is a serverless service and does not run on Dedicated Hosts."}]', 'When configured with VPC settings, Lambda creates Hyperplane ENIs in the specified subnets, allowing the function to access VPC resources like RDS, ElastiCache, and private APIs.', 2, 'https://docs.aws.amazon.com/lambda/latest/dg/configuration-vpc.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to automate the rotation of database credentials stored in AWS Secrets Manager. Which feature handles this?', '[{"id":"a","text":"CloudWatch Events scheduled rule calling a custom script","is_correct":false,"explanation":"Custom scripts add operational overhead when Secrets Manager has built-in rotation."},{"id":"b","text":"Secrets Manager automatic rotation with a Lambda rotation function","is_correct":true,"explanation":"Secrets Manager provides built-in automatic rotation that uses a Lambda function to update credentials."},{"id":"c","text":"AWS Config remediation action","is_correct":false,"explanation":"Config remediation is for compliance, not credential rotation."},{"id":"d","text":"IAM access key rotation policy","is_correct":false,"explanation":"IAM key rotation is for IAM access keys, not database credentials."}]', 'AWS Secrets Manager can automatically rotate database credentials using a Lambda function that generates new credentials, updates the database, and stores the new secret.', 3, 'https://docs.aws.amazon.com/secretsmanager/latest/userguide/rotating-secrets.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has a REST API served by Amazon API Gateway. They want to cache responses for frequently requested resources to reduce backend load. Which feature should be enabled?', '[{"id":"a","text":"Lambda provisioned concurrency","is_correct":false,"explanation":"Provisioned concurrency keeps Lambda warm but does not cache responses."},{"id":"b","text":"API Gateway stage-level caching","is_correct":true,"explanation":"API Gateway caching stores endpoint responses for a configurable TTL, reducing backend calls."},{"id":"c","text":"CloudFront with API Gateway as origin","is_correct":false,"explanation":"CloudFront can cache but API Gateway built-in caching is simpler for API responses."},{"id":"d","text":"ElastiCache between API Gateway and Lambda","is_correct":false,"explanation":"ElastiCache requires application-level caching logic, adding complexity."}]', 'API Gateway caching stores responses at the stage level with a configurable TTL (up to 3600 seconds), reducing the number of calls to backend integrations.', 2, 'https://docs.aws.amazon.com/apigateway/latest/developerguide/api-gateway-caching.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to deploy a containerized application that scales to zero when not in use and costs nothing during idle periods. Which compute option should be used?', '[{"id":"a","text":"ECS on EC2 with minimum capacity of 1","is_correct":false,"explanation":"A minimum capacity of 1 means at least one instance is always running and incurring costs."},{"id":"b","text":"AWS App Runner","is_correct":true,"explanation":"App Runner scales to zero and charges nothing when there are no active requests."},{"id":"c","text":"EKS with Karpenter autoscaler","is_correct":false,"explanation":"EKS requires a control plane that incurs costs even when idle."},{"id":"d","text":"ECS on Fargate with minimum task count of 1","is_correct":false,"explanation":"A minimum of 1 task means Fargate costs continue during idle."}]', 'AWS App Runner fully manages containerized applications with automatic scaling, including scaling to zero during idle periods with no compute charges.', 2, 'https://docs.aws.amazon.com/apprunner/latest/dg/what-is-apprunner.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to analyze clickstream data from their website in near real-time. Data arrives at thousands of events per second. Which ingestion and analysis pipeline should be used?', '[{"id":"a","text":"Amazon SQS → Lambda → RDS","is_correct":false,"explanation":"SQS and Lambda are not optimized for high-throughput streaming analytics."},{"id":"b","text":"Amazon Kinesis Data Streams → Kinesis Data Analytics → Amazon OpenSearch","is_correct":true,"explanation":"Kinesis handles high-throughput ingestion, Data Analytics enables real-time processing, and OpenSearch provides search and visualization."},{"id":"c","text":"AWS Glue streaming → Amazon Redshift","is_correct":false,"explanation":"Glue streaming has higher latency than Kinesis for real-time analytics."},{"id":"d","text":"S3 event notifications → Lambda → DynamoDB","is_correct":false,"explanation":"S3 event notifications are not designed for high-throughput streaming."}]', 'Kinesis Data Streams ingests high-throughput streaming data, Data Analytics runs real-time SQL queries, and OpenSearch provides near real-time search and dashboarding.', 4, 'https://docs.aws.amazon.com/streams/latest/dev/introduction.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Amazon EFS for shared file storage across multiple EC2 instances. They notice high storage costs. Most files are accessed only in the first 30 days after creation. Which feature reduces costs?', '[{"id":"a","text":"EFS Provisioned Throughput mode","is_correct":false,"explanation":"Provisioned Throughput affects performance, not storage costs."},{"id":"b","text":"EFS Lifecycle Management to move files to Infrequent Access (IA) storage class after 30 days","is_correct":true,"explanation":"EFS Lifecycle Management automatically moves files to the lower-cost IA tier after the specified period."},{"id":"c","text":"Compress files using a scheduled Lambda function","is_correct":false,"explanation":"Application-level compression adds complexity and does not leverage EFS storage tiers."},{"id":"d","text":"Switch to EFS One Zone storage class","is_correct":false,"explanation":"One Zone reduces availability costs but does not address access-pattern-based optimization."}]', 'EFS Lifecycle Management automatically transitions files to the Infrequent Access storage class after a configurable period, reducing storage costs by up to 92%.', 2, 'https://docs.aws.amazon.com/efs/latest/ug/lifecycle-management-efs.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses AWS Step Functions to orchestrate a data processing pipeline. One step may fail intermittently due to a third-party API timeout. What is the BEST way to handle this?', '[{"id":"a","text":"Add a Wait state before the API call","is_correct":false,"explanation":"A static wait does not help with intermittent failures."},{"id":"b","text":"Configure a Retry policy with exponential backoff on the Task state","is_correct":true,"explanation":"Retry with exponential backoff automatically retries failed steps with increasing delays."},{"id":"c","text":"Wrap the entire workflow in a try-catch Lambda function","is_correct":false,"explanation":"This defeats the purpose of Step Functions error handling."},{"id":"d","text":"Set a longer timeout on the Step Functions execution","is_correct":false,"explanation":"A longer execution timeout does not address individual step failures."}]', 'Step Functions Retry policies support exponential backoff with configurable intervals, maximum attempts, and backoff rates, providing resilient handling of transient failures.', 3, 'https://docs.aws.amazon.com/step-functions/latest/dg/concepts-error-handling.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to establish private connectivity between their VPC and Amazon S3 without traversing the public internet. Data transfer costs must be minimized. Which solution should be used?', '[{"id":"a","text":"S3 Transfer Acceleration","is_correct":false,"explanation":"Transfer Acceleration uses CloudFront edge locations over the public internet."},{"id":"b","text":"VPC Gateway Endpoint for S3","is_correct":true,"explanation":"Gateway endpoints provide free, private connectivity to S3 without NAT gateway data processing charges."},{"id":"c","text":"VPC Interface Endpoint for S3","is_correct":false,"explanation":"Interface endpoints incur hourly and data processing charges, while gateway endpoints are free."},{"id":"d","text":"AWS PrivateLink","is_correct":false,"explanation":"PrivateLink for S3 uses interface endpoints which have associated costs."}]', 'VPC Gateway Endpoints for S3 are free and route traffic privately through the AWS network, avoiding NAT gateway data processing charges and internet transit.', 2, 'https://docs.aws.amazon.com/vpc/latest/privatelink/vpc-endpoints-s3.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs an Aurora MySQL cluster and needs to scale read capacity during peak hours. Which approach provides the fastest read scaling?', '[{"id":"a","text":"Add more Aurora read replicas manually","is_correct":false,"explanation":"Manual scaling is slow and requires operational intervention."},{"id":"b","text":"Aurora Auto Scaling for read replicas based on CPU utilization","is_correct":true,"explanation":"Aurora Auto Scaling automatically adds or removes read replicas based on CloudWatch metrics."},{"id":"c","text":"Enable Aurora Serverless v2","is_correct":false,"explanation":"Migrating to Serverless v2 is a significant change for an existing provisioned cluster."},{"id":"d","text":"Use RDS Proxy to pool connections","is_correct":false,"explanation":"RDS Proxy improves connection management but does not add read capacity."}]', 'Aurora Auto Scaling dynamically adjusts the number of read replicas based on metrics like CPU utilization or connections, providing automatic read capacity scaling.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Integrating.AutoScaling.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is building a real-time fraud detection system. Transactions must be analyzed within 200 milliseconds. Which architecture supports this latency requirement?', '[{"id":"a","text":"Kinesis Data Firehose → S3 → Athena","is_correct":false,"explanation":"Firehose buffers data for at least 60 seconds and Athena is not real-time."},{"id":"b","text":"API Gateway → Lambda with in-memory ML model inference","is_correct":true,"explanation":"Lambda with a pre-loaded ML model can process requests within milliseconds via API Gateway."},{"id":"c","text":"SQS → EC2 consumer → RDS for analysis","is_correct":false,"explanation":"SQS polling and database queries add significant latency."},{"id":"d","text":"Kinesis Data Streams → EMR Spark Streaming","is_correct":false,"explanation":"EMR Spark Streaming has higher processing latency than direct Lambda invocation."}]', 'API Gateway provides low-latency HTTP invocation, and Lambda with a pre-loaded ML model can perform inference within the 200ms requirement for synchronous fraud detection.', 4, 'https://docs.aws.amazon.com/lambda/latest/dg/welcome.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to implement a global content delivery solution that serves dynamic content from the nearest AWS Region. Which feature of CloudFront helps reduce latency for dynamic content?', '[{"id":"a","text":"CloudFront edge caching with high TTL","is_correct":false,"explanation":"High TTL caching is for static content; dynamic content changes per request."},{"id":"b","text":"CloudFront with persistent connections and TLS session reuse to the origin","is_correct":true,"explanation":"CloudFront uses persistent connections to origins and optimized network paths to reduce dynamic content latency."},{"id":"c","text":"CloudFront Lambda@Edge for server-side rendering","is_correct":false,"explanation":"Lambda@Edge can generate content but does not address origin fetch optimization."},{"id":"d","text":"CloudFront with S3 as origin","is_correct":false,"explanation":"S3 is for static content, not dynamic."}]', 'CloudFront reduces dynamic content latency through persistent connections to origins, optimized TCP/TLS handshakes, and AWS backbone network routing.', 3, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/dynamic-content.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect needs to connect 15 VPCs together, including VPCs in different AWS accounts. All VPCs must be able to communicate with each other. Which service simplifies this connectivity?', '[{"id":"a","text":"VPC peering between all VPCs","is_correct":false,"explanation":"VPC peering requires n*(n-1)/2 connections = 105 peering connections, which is unmanageable."},{"id":"b","text":"AWS Transit Gateway","is_correct":true,"explanation":"Transit Gateway acts as a hub, connecting all VPCs through a single gateway with simplified routing."},{"id":"c","text":"AWS PrivateLink for all inter-VPC traffic","is_correct":false,"explanation":"PrivateLink is for service-to-consumer connectivity, not general VPC-to-VPC networking."},{"id":"d","text":"AWS Cloud WAN","is_correct":false,"explanation":"Cloud WAN is for global network management and is over-engineered for simple VPC connectivity."}]', 'Transit Gateway provides a hub-and-spoke model that connects multiple VPCs, VPN connections, and Direct Connect gateways through a single, centrally managed gateway.', 3, 'https://docs.aws.amazon.com/vpc/latest/tgw/what-is-transit-gateway.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a legacy application that only supports the MySQL 5.6 database engine. They want to migrate to AWS with automated backups and Multi-AZ support. Which service should be used?', '[{"id":"a","text":"Amazon Aurora MySQL","is_correct":false,"explanation":"Aurora requires MySQL 5.7 or later compatibility."},{"id":"b","text":"Amazon RDS for MySQL 5.6","is_correct":true,"explanation":"RDS supports MySQL 5.6 with automated backups, Multi-AZ, and managed patching."},{"id":"c","text":"Self-managed MySQL on EC2","is_correct":false,"explanation":"Self-managed MySQL loses the benefits of automated backups and Multi-AZ."},{"id":"d","text":"Amazon DynamoDB","is_correct":false,"explanation":"DynamoDB is NoSQL and incompatible with MySQL applications."}]', 'Amazon RDS supports specific MySQL engine versions including 5.6, providing managed features like automated backups, Multi-AZ failover, and maintenance windows.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/CHAP_MySQL.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect needs to design a system where multiple Lambda functions process events from the same Kinesis Data Stream concurrently. How should the stream be configured?', '[{"id":"a","text":"Create multiple Kinesis streams and distribute events","is_correct":false,"explanation":"Multiple streams add complexity when a single stream with multiple consumers is sufficient."},{"id":"b","text":"Enable enhanced fan-out for the consumers","is_correct":true,"explanation":"Enhanced fan-out provides dedicated 2 MB/s throughput per consumer, allowing concurrent processing without contention."},{"id":"c","text":"Increase the shard count","is_correct":false,"explanation":"More shards increase throughput but do not solve consumer contention on shared throughput."},{"id":"d","text":"Use SQS as an intermediary between Kinesis and Lambda","is_correct":false,"explanation":"Adding SQS creates unnecessary complexity."}]', 'Kinesis enhanced fan-out provides each consumer with a dedicated read throughput of 2 MB/s per shard, eliminating the shared 2 MB/s limit among standard consumers.', 4, 'https://docs.aws.amazon.com/streams/latest/dev/enhanced-consumers.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to restrict access to an S3 bucket so that only a specific IAM role can access it. Which S3 feature should be used?', '[{"id":"a","text":"S3 ACL granting access to the role ARN","is_correct":false,"explanation":"S3 ACLs do not support IAM role ARNs."},{"id":"b","text":"S3 bucket policy with a Condition using aws:PrincipalArn","is_correct":true,"explanation":"A bucket policy with a Condition restricting to a specific principal ARN ensures only that role can access the bucket."},{"id":"c","text":"S3 Block Public Access","is_correct":false,"explanation":"Block Public Access prevents public access but does not restrict to specific roles."},{"id":"d","text":"CORS configuration","is_correct":false,"explanation":"CORS controls browser-based cross-origin requests, not IAM access control."}]', 'S3 bucket policies support IAM condition keys like aws:PrincipalArn to restrict access to specific IAM roles, providing fine-grained access control.', 3, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/bucket-policies.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs batch analytics jobs that process data stored in S3. The jobs use Apache Spark and run for 4 hours every night. They want to minimize cost while maintaining performance. Which solution is best?', '[{"id":"a","text":"Amazon EMR with On-Demand instances running 24/7","is_correct":false,"explanation":"Running 24/7 wastes money for a 4-hour nightly job."},{"id":"b","text":"Amazon EMR with transient clusters using Spot instances for task nodes","is_correct":true,"explanation":"Transient clusters terminate after the job completes, and Spot instances reduce compute costs by up to 90%."},{"id":"c","text":"AWS Glue with standard workers","is_correct":false,"explanation":"Glue is simpler but less cost-effective than EMR with Spot for long-running Spark jobs."},{"id":"d","text":"Amazon Athena","is_correct":false,"explanation":"Athena is for interactive queries, not long-running batch Spark jobs."}]', 'Transient EMR clusters with Spot instances for task nodes provide the most cost-effective solution for scheduled batch analytics, paying only for the 4-hour processing window.', 3, 'https://docs.aws.amazon.com/emr/latest/ManagementGuide/emr-plan-instances-guidelines.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to implement a content management system that stores metadata in a database and large binary files (images, videos) separately. Which architecture is MOST scalable?', '[{"id":"a","text":"Store everything in Amazon RDS","is_correct":false,"explanation":"Storing large binary files in RDS is expensive and degrades performance."},{"id":"b","text":"Store metadata in DynamoDB and binary files in S3 with pre-signed URLs","is_correct":true,"explanation":"DynamoDB handles fast metadata lookups while S3 provides unlimited, cost-effective binary storage with secure access."},{"id":"c","text":"Store everything in Amazon EFS","is_correct":false,"explanation":"EFS is more expensive than S3 for large file storage."},{"id":"d","text":"Store metadata and file paths in S3 JSON files","is_correct":false,"explanation":"S3 is not designed for fast metadata queries."}]', 'Separating metadata (in DynamoDB) from binary content (in S3) leverages each service''s strengths: DynamoDB for fast key-value lookups and S3 for unlimited object storage.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/bp-use-s3-too.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A company is designing a multi-tier application for high availability. (Select TWO) Which design principles should be applied?', '[{"id":"a","text":"Design for failure by using multiple AZs and health checks","is_correct":true,"explanation":"Designing for failure ensures the application survives component and AZ failures."},{"id":"b","text":"Implement loose coupling between tiers using message queues","is_correct":true,"explanation":"Loose coupling prevents failures in one tier from cascading to other tiers."},{"id":"c","text":"Use the largest possible instance type for each tier","is_correct":false,"explanation":"Vertical scaling creates single points of failure and does not improve availability."},{"id":"d","text":"Deploy all tiers in a single Availability Zone for lowest latency","is_correct":false,"explanation":"A single AZ is a single point of failure."}]', 'High availability requires designing for failure (multi-AZ, health checks, auto-replacement) and loose coupling (queues, event-driven) to prevent cascading failures.', 2, 'https://docs.aws.amazon.com/wellarchitected/latest/reliability-pillar/design-principles.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to serve an API that handles both read-heavy and write-heavy traffic. Read traffic is 10x the write traffic. Which database pattern optimizes performance?', '[{"id":"a","text":"Single Aurora instance handling all traffic","is_correct":false,"explanation":"A single instance may become a bottleneck under heavy combined read/write traffic."},{"id":"b","text":"Aurora with a writer instance and multiple reader instances using reader endpoint","is_correct":true,"explanation":"The reader endpoint load-balances read traffic across replicas while the writer handles writes."},{"id":"c","text":"Two separate DynamoDB tables for reads and writes","is_correct":false,"explanation":"Separate tables require complex synchronization logic."},{"id":"d","text":"Amazon Redshift for reads and RDS for writes","is_correct":false,"explanation":"Redshift is for analytics, not real-time read serving."}]', 'Aurora''s reader endpoint automatically load-balances connections across read replicas, distributing the read-heavy traffic while the writer instance handles writes.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Overview.Endpoints.html', 'SAA-C03-1.2', true, true)
,
-- ============================================================
-- Additional questions: RESILIENT, PERFORMANCE, SECURITY, COST, OPERATIONS, IMPROVEMENT
-- ============================================================
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a monolithic application on a single EC2 instance. Management wants improved reliability without re-architecting. What is the quickest improvement?', '[{"id": "a", "text": "Create an AMI and configure an Auto Scaling group with min=1 max=1 across multiple AZs", "is_correct": true, "explanation": "ASG auto-replaces failed instances in healthy AZs"}, {"id": "b", "text": "Add an Elastic IP address", "is_correct": false, "explanation": "An EIP does not improve instance reliability"}, {"id": "c", "text": "Purchase a Reserved Instance", "is_correct": false, "explanation": "Reserved Instances reduce cost not reliability"}, {"id": "d", "text": "Enable detailed monitoring", "is_correct": false, "explanation": "Monitoring alerts on failures but does not auto-recover"}]', 'An Auto Scaling group with min/max of 1 across multiple AZs automatically replaces a failed instance in a healthy AZ.', 2, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/what-is-amazon-ec2-auto-scaling.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect is designing a storage layer for a genomics research application that requires high-throughput parallel reads from hundreds of EC2 instances. Which storage service is BEST suited?', '[{"id": "a", "text": "Amazon EBS io2 Block Express volumes", "is_correct": false, "explanation": "EBS volumes cannot be shared across hundreds of instances"}, {"id": "b", "text": "Amazon FSx for Lustre linked to an S3 bucket", "is_correct": true, "explanation": "FSx for Lustre is designed for high-throughput parallel file system workloads"}, {"id": "c", "text": "Amazon EFS with Max I/O performance mode", "is_correct": false, "explanation": "EFS Max I/O has higher per-operation latency than FSx for Lustre"}, {"id": "d", "text": "Amazon S3 with Transfer Acceleration", "is_correct": false, "explanation": "S3 is object storage and does not support POSIX file system access"}]', 'Amazon FSx for Lustre provides a high-performance parallel file system that integrates with S3 and supports sub-millisecond latencies at hundreds of GB/s throughput.', 4, 'https://docs.aws.amazon.com/fsx/latest/LustreGuide/what-is.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application uses an Amazon SQS queue to buffer write requests to a database. During peak hours the queue depth grows significantly. How should the architect scale the consumer fleet?', '[{"id": "a", "text": "Scale based on SQS NumberOfMessagesSent metric", "is_correct": false, "explanation": "NumberOfMessagesSent reflects producer activity not consumer load"}, {"id": "b", "text": "Use scheduled scaling based on expected peak hours", "is_correct": false, "explanation": "Scheduled scaling cannot react to variable queue depths"}, {"id": "c", "text": "Use a custom CloudWatch metric of backlog per instance to drive target tracking Auto Scaling", "is_correct": true, "explanation": "Backlog per instance is the recommended metric for SQS-based scaling"}, {"id": "d", "text": "Increase the visibility timeout to reduce apparent queue depth", "is_correct": false, "explanation": "Increasing visibility timeout hides messages but does not reduce the backlog"}]', 'AWS recommends a custom metric dividing ApproximateNumberOfMessagesVisible by running instances for optimal SQS consumer scaling.', 4, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/as-using-sqs-dead-letter-queue.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to migrate a petabyte-scale data warehouse to AWS within 2 weeks. Which service should be used?', '[{"id": "a", "text": "AWS DataSync over a 10 Gbps Direct Connect", "is_correct": false, "explanation": "10 Gbps would take over 11 days for 1 PB excluding protocol overhead"}, {"id": "b", "text": "S3 multipart upload over the internet", "is_correct": false, "explanation": "Internet transfer of 1 PB would take weeks even with high bandwidth"}, {"id": "c", "text": "AWS Storage Gateway Volume Gateway", "is_correct": false, "explanation": "Storage Gateway is for hybrid access not bulk migration"}, {"id": "d", "text": "AWS Snowball Edge Storage Optimized devices shipped in parallel", "is_correct": true, "explanation": "Multiple Snowball Edge devices can transfer petabytes within days including shipping time"}]', 'AWS Snowball Edge devices support up to 80 TB each. Shipping multiple devices in parallel enables petabyte-scale migration within the 2-week window.', 3, 'https://docs.aws.amazon.com/snowball/latest/developer-guide/whatisedge.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect is designing a globally distributed application. Users in each Region should read from a local database but writes should propagate globally. Which database solution supports this?', '[{"id": "a", "text": "Amazon DynamoDB Global Tables", "is_correct": true, "explanation": "Global Tables provide multi-Region multi-active replication"}, {"id": "b", "text": "Amazon Aurora Global Database", "is_correct": false, "explanation": "Aurora Global Database has a single write Region only"}, {"id": "c", "text": "Amazon RDS with cross-Region read replicas", "is_correct": false, "explanation": "RDS cross-Region replicas are read-only"}, {"id": "d", "text": "Amazon ElastiCache Global Datastore", "is_correct": false, "explanation": "ElastiCache Global Datastore only allows writes in the primary Region"}]', 'DynamoDB Global Tables replicate data across AWS Regions with sub-second latency and accept writes in any Region with last-writer-wins conflict resolution.', 3, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/GlobalTables.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing an event-driven serverless application that must coordinate multiple Lambda functions in sequence with error handling. Which service should orchestrate the workflow?', '[{"id": "a", "text": "AWS Step Functions with a Standard workflow", "is_correct": true, "explanation": "Step Functions provides workflow orchestration with built-in error handling and state management"}, {"id": "b", "text": "Amazon EventBridge with chained rules", "is_correct": false, "explanation": "EventBridge does not provide sequential orchestration or state management"}, {"id": "c", "text": "Amazon SQS with a chain of queues between functions", "is_correct": false, "explanation": "SQS chains are harder to manage for complex workflows with branching"}, {"id": "d", "text": "A coordinator Lambda function that invokes others", "is_correct": false, "explanation": "A coordinator Lambda has a 15-minute timeout and adds complexity"}]', 'AWS Step Functions Standard workflows provide durable execution with built-in retry policies, catch blocks, parallel execution, and visual monitoring.', 3, 'https://docs.aws.amazon.com/step-functions/latest/dg/welcome.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company hosts a web application behind an ALB. 30% of requests come from known malicious IP ranges. Which service blocks these IPs?', '[{"id": "a", "text": "Security groups on the ALB", "is_correct": false, "explanation": "ALB security groups cannot reference large dynamic IP sets"}, {"id": "b", "text": "Network ACLs on the VPC subnets", "is_correct": false, "explanation": "NACLs have a limit of 20 rules which may be insufficient"}, {"id": "c", "text": "Amazon GuardDuty", "is_correct": false, "explanation": "GuardDuty detects threats but does not block traffic"}, {"id": "d", "text": "AWS WAF with an IP set rule attached to the ALB", "is_correct": true, "explanation": "WAF IP set rules block requests from specific IP ranges at the ALB"}]', 'AWS WAF allows creating IP set rules containing up to 10,000 IP addresses or CIDR ranges that can be attached directly to an ALB.', 2, 'https://docs.aws.amazon.com/waf/latest/developerguide/waf-ip-set-managing.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to back up EBS volumes, RDS databases, and DynamoDB tables using a single centralized service. Which service provides this?', '[{"id": "a", "text": "Amazon Data Lifecycle Manager", "is_correct": false, "explanation": "DLM only manages EBS snapshot lifecycles"}, {"id": "b", "text": "AWS CloudFormation", "is_correct": false, "explanation": "CloudFormation manages infrastructure as code not backups"}, {"id": "c", "text": "AWS Backup", "is_correct": true, "explanation": "AWS Backup provides centralized automated backup management across multiple AWS services"}, {"id": "d", "text": "Amazon S3 cross-Region replication", "is_correct": false, "explanation": "S3 CRR replicates S3 objects not EBS or RDS"}]', 'AWS Backup is a centralized service that automates backup creation, retention, and restoration across EBS, RDS, DynamoDB, EFS, and other services.', 2, 'https://docs.aws.amazon.com/aws-backup/latest/devguide/whatisbackup.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has a three-tier application where the database in a private subnet must be patched but has no internet access. How can the database reach the patch repository?', '[{"id": "a", "text": "Assign public IP addresses to database instances", "is_correct": false, "explanation": "Public IPs on databases expose them to the internet"}, {"id": "b", "text": "Use VPC peering to connect to the patch repository", "is_correct": false, "explanation": "VPC peering connects VPCs not VPCs to external repos"}, {"id": "c", "text": "Deploy a NAT gateway in the public subnet and update the private subnet route table", "is_correct": true, "explanation": "A NAT gateway allows private subnet instances to initiate outbound internet connections"}, {"id": "d", "text": "Create an internet gateway route in the private subnet", "is_correct": false, "explanation": "An IGW route in a private subnet makes it a public subnet"}]', 'A NAT gateway in a public subnet allows instances in private subnets to initiate outbound internet connections while preventing inbound connections.', 2, 'https://docs.aws.amazon.com/vpc/latest/userguide/vpc-nat-gateway.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Aurora MySQL and wants to test a new app version against a copy of production. Creating a full copy via snapshots takes too long. Which Aurora feature creates a fast copy?', '[{"id": "a", "text": "Aurora read replica promotion", "is_correct": false, "explanation": "Promoting a replica removes it from the cluster"}, {"id": "b", "text": "Aurora Backtrack", "is_correct": false, "explanation": "Backtrack rewinds the database but does not create a separate copy"}, {"id": "c", "text": "Aurora cross-Region replica", "is_correct": false, "explanation": "Cross-Region replicas are for DR not fast database copying"}, {"id": "d", "text": "Aurora cloning", "is_correct": true, "explanation": "Aurora cloning uses copy-on-write to create a fast space-efficient copy"}]', 'Aurora cloning creates a new cluster sharing the same storage using copy-on-write, making it nearly instantaneous regardless of database size.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Managing.Clone.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a stateless API on ECS Fargate. Traffic is bursty with 10x spikes lasting 5-10 minutes. The current scaling policy reacts too slowly. Which approach reduces scaling lag?', '[{"id": "a", "text": "Increase the minimum task count to handle peak", "is_correct": false, "explanation": "Over-provisioning wastes money during low traffic"}, {"id": "b", "text": "Switch to EC2 launch type with warm pools", "is_correct": false, "explanation": "EC2 launch type adds management overhead vs Fargate"}, {"id": "c", "text": "Use ECS Service Auto Scaling with target tracking on CPU plus a step scaling policy for rapid scale-out", "is_correct": true, "explanation": "Combining target tracking with step scaling provides both steady-state and burst handling"}, {"id": "d", "text": "Use Lambda instead of Fargate", "is_correct": false, "explanation": "Lambda has a 15-minute timeout and concurrency limits"}]', 'Combining target tracking scaling for steady traffic with step scaling for rapid bursts ensures Fargate tasks scale quickly during traffic spikes.', 4, 'https://docs.aws.amazon.com/AmazonECS/latest/developerguide/service-auto-scaling.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A media company stores video assets in S3. They want to ensure no data is lost if objects are accidentally deleted. Which S3 feature provides protection?', '[{"id": "a", "text": "Enable S3 Transfer Acceleration", "is_correct": false, "explanation": "Transfer Acceleration speeds uploads not deletion protection"}, {"id": "b", "text": "Configure S3 lifecycle policies", "is_correct": false, "explanation": "Lifecycle policies manage transitions and expiration not deletion recovery"}, {"id": "c", "text": "Enable S3 versioning to retain previous versions of deleted objects", "is_correct": true, "explanation": "Versioning keeps all previous versions including delete markers allowing recovery"}, {"id": "d", "text": "Enable S3 server access logging", "is_correct": false, "explanation": "Access logging records operations but does not prevent data loss"}]', 'S3 versioning preserves every version of every object. When an object is deleted, a delete marker is placed but previous versions remain retrievable.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/Versioning.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A company is implementing a multi-Region disaster recovery strategy for their web application. (Select TWO) Which components should be replicated to the DR Region?', '[{"id": "a", "text": "CloudWatch alarms and dashboards", "is_correct": false, "explanation": "CloudWatch alarms are Region-specific but not critical for DR functionality"}, {"id": "b", "text": "Database with cross-Region read replicas or Global Tables", "is_correct": true, "explanation": "Database replication ensures data availability in the DR Region"}, {"id": "c", "text": "AMIs and launch templates registered in the DR Region", "is_correct": true, "explanation": "Pre-registered AMIs enable rapid instance provisioning during failover"}, {"id": "d", "text": "IAM roles and policies", "is_correct": false, "explanation": "IAM is a global service and does not need cross-Region replication"}]', 'Database replication and pre-registered AMIs in the DR Region are critical for rapid failover, minimizing RTO during a disaster.', 3, 'https://docs.aws.amazon.com/whitepapers/latest/disaster-recovery-workloads-on-aws/disaster-recovery-options-in-the-cloud.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to implement a message queue where multiple consumer groups each receive a copy of every message, but within each group messages are processed by only one consumer. Which architecture supports this?', '[{"id": "a", "text": "A single SQS queue with multiple consumers", "is_correct": false, "explanation": "A single SQS queue delivers each message to only one consumer"}, {"id": "b", "text": "Amazon SNS topic fanning out to multiple SQS queues, one per consumer group", "is_correct": true, "explanation": "SNS fan-out sends a copy to each SQS queue, and SQS ensures single-consumer processing within each queue"}, {"id": "c", "text": "Amazon Kinesis with enhanced fan-out", "is_correct": false, "explanation": "Kinesis supports multiple consumers but processes per shard not per message"}, {"id": "d", "text": "Amazon MQ with multiple queues", "is_correct": false, "explanation": "MQ requires managing broker infrastructure"}]', 'The SNS-SQS fan-out pattern creates independent message copies per consumer group while SQS ensures each message is processed once within each group.', 3, 'https://docs.aws.amazon.com/sns/latest/dg/sns-sqs-as-subscriber.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Amazon Aurora Serverless v2 for a development database. They want to pause the database during nights and weekends to save costs. Which approach works?', '[{"id": "a", "text": "Set the minimum ACU to 0", "is_correct": false, "explanation": "Aurora Serverless v2 minimum is 0.5 ACU, it cannot be set to 0"}, {"id": "b", "text": "Aurora Serverless v2 scales to a minimum of 0.5 ACU but cannot pause. Use Aurora Serverless v1 or stop the cluster manually", "is_correct": true, "explanation": "Serverless v2 has a minimum of 0.5 ACU; true pause is only available in v1 or by stopping the cluster"}, {"id": "c", "text": "Use a scheduled Lambda function to delete and recreate the cluster", "is_correct": false, "explanation": "Deleting and recreating loses the data unless snapshots are used"}, {"id": "d", "text": "Enable auto-pause in the Aurora cluster settings", "is_correct": false, "explanation": "Auto-pause is a Serverless v1 feature, not available in v2"}]', 'Aurora Serverless v2 scales down to 0.5 ACU but cannot auto-pause. For zero cost during idle periods, manually stop the cluster or use Serverless v1.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/aurora-serverless-v2.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs an application that processes events from Amazon Kinesis Data Streams. The application occasionally fails to process a batch of records. How should errors be handled?', '[{"id": "a", "text": "Increase the batch size to reduce processing frequency", "is_correct": false, "explanation": "Larger batches make error isolation harder"}, {"id": "b", "text": "Skip failed records using a try-catch in the Lambda code", "is_correct": false, "explanation": "Skipping records loses data"}, {"id": "c", "text": "Configure a bisect-on-error setting with a destination for failed records", "is_correct": true, "explanation": "Bisect-on-error splits the failed batch in half to isolate the problematic record and sends failures to a destination"}, {"id": "d", "text": "Increase the retry count to maximum", "is_correct": false, "explanation": "More retries delay processing without fixing the root cause"}]', 'Kinesis Lambda event source mapping supports bisect-on-error to isolate failing records and on-failure destinations to capture them for analysis.', 4, 'https://docs.aws.amazon.com/lambda/latest/dg/with-kinesis.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company stores customer data in DynamoDB and needs the ability to restore the table to any point in the last 35 days. Which feature provides this?', '[{"id": "a", "text": "DynamoDB on-demand backups", "is_correct": false, "explanation": "On-demand backups capture a single point in time, not continuous recovery"}, {"id": "b", "text": "DynamoDB Streams with a replay Lambda", "is_correct": false, "explanation": "Streams can replay events but are limited to 24-hour retention"}, {"id": "c", "text": "DynamoDB Global Tables", "is_correct": false, "explanation": "Global Tables provide multi-Region replication not point-in-time recovery"}, {"id": "d", "text": "DynamoDB point-in-time recovery (PITR)", "is_correct": true, "explanation": "PITR provides continuous backups and allows restoration to any second within the last 35 days"}]', 'DynamoDB PITR maintains continuous incremental backups of the table data, allowing restoration to any second within the 35-day retention window.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/PointInTimeRecovery.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect needs to design a system that gracefully handles the termination of Spot Instances. Which mechanism provides advance warning?', '[{"id": "a", "text": "EC2 Spot Instance interruption notice via instance metadata (2-minute warning)", "is_correct": true, "explanation": "AWS provides a 2-minute interruption notice via instance metadata and CloudWatch Events"}, {"id": "b", "text": "Auto Scaling group lifecycle hooks", "is_correct": false, "explanation": "Lifecycle hooks help with instance transitions but do not provide Spot-specific interruption warnings"}, {"id": "c", "text": "CloudTrail events for instance termination", "is_correct": false, "explanation": "CloudTrail logs events after they happen, not as advance warning"}, {"id": "d", "text": "Reserved Instance expiration notifications", "is_correct": false, "explanation": "Reserved Instances are a pricing model with no interruption"}]', 'EC2 provides a 2-minute interruption notice via the instance metadata service and EventBridge, giving applications time to save state and gracefully shut down.', 3, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/spot-instance-termination-notices.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an application that requires shared storage accessible by multiple EC2 instances across AZs. The storage must support POSIX permissions and NFSv4. Which service should be used?', '[{"id": "a", "text": "Amazon EBS with multi-attach", "is_correct": false, "explanation": "EBS multi-attach is limited to io1/io2 volumes within a single AZ"}, {"id": "b", "text": "Amazon S3", "is_correct": false, "explanation": "S3 is object storage and does not support POSIX permissions or NFS"}, {"id": "c", "text": "Amazon Elastic File System (EFS)", "is_correct": true, "explanation": "EFS provides a managed NFS file system with POSIX permissions accessible across multiple AZs"}, {"id": "d", "text": "Amazon FSx for Windows File Server", "is_correct": false, "explanation": "FSx for Windows uses SMB protocol not NFS"}]', 'Amazon EFS provides a fully managed, elastic NFS file system that supports POSIX permissions and can be mounted by thousands of instances across multiple AZs.', 2, 'https://docs.aws.amazon.com/efs/latest/ug/whatisefs.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to implement canary deployments for their Lambda function to gradually shift traffic to a new version. Which feature enables this?', '[{"id": "a", "text": "Lambda layers", "is_correct": false, "explanation": "Layers provide shared code libraries not traffic routing"}, {"id": "b", "text": "Lambda provisioned concurrency", "is_correct": false, "explanation": "Provisioned concurrency manages cold starts not traffic shifting"}, {"id": "c", "text": "API Gateway stage variables", "is_correct": false, "explanation": "Stage variables point to a single version, not weighted traffic splitting"}, {"id": "d", "text": "Lambda alias with weighted routing between two function versions", "is_correct": true, "explanation": "Lambda aliases support traffic shifting between versions using configurable weights"}]', 'Lambda aliases can route a percentage of traffic to a new version using weighted aliases, enabling gradual canary deployments with automatic rollback via CodeDeploy.', 3, 'https://docs.aws.amazon.com/lambda/latest/dg/configuration-aliases.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is building an application that needs to send notifications to mobile devices, email addresses, and HTTP endpoints simultaneously. Which service should be used?', '[{"id": "a", "text": "Amazon SES", "is_correct": false, "explanation": "SES is for email only, not mobile push or HTTP"}, {"id": "b", "text": "Amazon Pinpoint", "is_correct": false, "explanation": "Pinpoint is for targeted marketing communications not general pub/sub"}, {"id": "c", "text": "Amazon EventBridge", "is_correct": false, "explanation": "EventBridge routes events to targets but is not designed for direct user notifications"}, {"id": "d", "text": "Amazon SNS topic with multiple subscription types", "is_correct": true, "explanation": "SNS supports multiple subscription protocols including mobile push, email, HTTP/S, SQS, and Lambda"}]', 'Amazon SNS provides a pub/sub messaging service that supports multiple subscription protocols, enabling simultaneous notification delivery to diverse endpoint types.', 2, 'https://docs.aws.amazon.com/sns/latest/dg/welcome.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to use AWS CloudFormation to deploy infrastructure but needs to preview changes before applying them. Which feature should be used?', '[{"id": "a", "text": "CloudFormation drift detection", "is_correct": false, "explanation": "Drift detection identifies manual changes, not previews of template updates"}, {"id": "b", "text": "CloudFormation stack policies", "is_correct": false, "explanation": "Stack policies prevent updates to specific resources, not preview changes"}, {"id": "c", "text": "CloudFormation change sets", "is_correct": true, "explanation": "Change sets show a preview of proposed changes before execution"}, {"id": "d", "text": "CloudFormation nested stacks", "is_correct": false, "explanation": "Nested stacks organize templates, not preview changes"}]', 'CloudFormation change sets create a summary of proposed changes showing which resources will be added, modified, or deleted before the update is executed.', 2, 'https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/using-cfn-updating-stacks-changesets.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to replicate an on-premises NFS file server to AWS for disaster recovery. Files should be incrementally synced. Which service is BEST suited?', '[{"id": "a", "text": "AWS DataSync with an on-premises agent", "is_correct": true, "explanation": "DataSync provides automated, incremental file transfer between on-premises NFS and AWS storage services"}, {"id": "b", "text": "AWS Storage Gateway File Gateway", "is_correct": false, "explanation": "File Gateway provides ongoing hybrid access, not one-way DR replication"}, {"id": "c", "text": "AWS Snowball Edge", "is_correct": false, "explanation": "Snowball is for bulk offline transfer, not incremental sync"}, {"id": "d", "text": "rsync on an EC2 instance", "is_correct": false, "explanation": "rsync requires manual management and is not a managed service"}]', 'AWS DataSync automates incremental data transfer between on-premises NFS file systems and AWS storage services like S3 or EFS with built-in scheduling.', 3, 'https://docs.aws.amazon.com/datasync/latest/userguide/what-is-datasync.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a critical database on Amazon RDS and needs to create a read-only copy in a different AWS account for analytics. Which approach should be used?', '[{"id": "a", "text": "Create a cross-account read replica", "is_correct": false, "explanation": "RDS does not support cross-account read replicas directly"}, {"id": "b", "text": "Use AWS DMS to replicate data continuously", "is_correct": false, "explanation": "DMS is more complex than snapshot sharing for a one-time copy"}, {"id": "c", "text": "Share an RDS automated snapshot with the target account and restore it there", "is_correct": true, "explanation": "RDS snapshots can be shared with specific AWS accounts allowing them to restore a read-only copy"}, {"id": "d", "text": "Export the database to S3 and share the bucket", "is_correct": false, "explanation": "Exporting to S3 loses the relational database format"}]', 'RDS automated and manual snapshots can be shared with other AWS accounts, allowing them to restore the database as an independent instance for analytics.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_ShareSnapshot.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A serverless application uses API Gateway with Lambda proxy integration. The architect wants to implement request validation before the Lambda function is invoked. Which feature should be configured?', '[{"id": "a", "text": "Lambda authorizers", "is_correct": false, "explanation": "Authorizers handle authentication and authorization, not request body validation"}, {"id": "b", "text": "API Gateway WAF integration", "is_correct": false, "explanation": "WAF filters malicious requests but does not validate request body schema"}, {"id": "c", "text": "Lambda function input validation", "is_correct": false, "explanation": "This works but wastes Lambda invocations on invalid requests"}, {"id": "d", "text": "API Gateway request validators with a JSON schema model", "is_correct": true, "explanation": "Request validators check request parameters and body against a model before invoking the backend"}]', 'API Gateway request validators enforce JSON schema models on incoming requests, rejecting malformed requests before they reach the Lambda function.', 3, 'https://docs.aws.amazon.com/apigateway/latest/developerguide/api-gateway-method-request-validation.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs a managed graph database for a social networking application that stores relationships between millions of users. Which AWS service should be used?', '[{"id": "a", "text": "Amazon Neptune", "is_correct": true, "explanation": "Neptune is a managed graph database supporting both property graphs (Gremlin) and RDF (SPARQL)"}, {"id": "b", "text": "Amazon DynamoDB with adjacency list pattern", "is_correct": false, "explanation": "DynamoDB can model graphs but lacks native graph traversal capabilities"}, {"id": "c", "text": "Amazon RDS with join queries", "is_correct": false, "explanation": "Relational databases struggle with deep graph traversals at scale"}, {"id": "d", "text": "Amazon Redshift", "is_correct": false, "explanation": "Redshift is a data warehouse not designed for graph queries"}]', 'Amazon Neptune is a managed graph database optimized for storing and querying highly connected datasets with millions of relationships.', 3, 'https://docs.aws.amazon.com/neptune/latest/userguide/intro.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs an application that needs to process exactly 1 million messages per day with no message loss. Messages average 256 KB each. Which queue service handles this?', '[{"id": "a", "text": "Amazon SQS FIFO queue", "is_correct": false, "explanation": "FIFO queues have a throughput limit of 3,000 messages per second with batching which is sufficient but the 256 KB payload may need extended client"}, {"id": "b", "text": "Amazon Kinesis Data Streams", "is_correct": false, "explanation": "Kinesis has a 1 MB record size limit but the ordering semantics add unnecessary complexity"}, {"id": "c", "text": "Amazon SQS Standard queue with extended client library for large messages", "is_correct": true, "explanation": "SQS extended client library stores message payloads in S3 for messages exceeding the 256 KB limit"}, {"id": "d", "text": "Amazon MQ for RabbitMQ", "is_correct": false, "explanation": "MQ requires managing broker instances and is not serverless"}]', 'SQS Standard queue with the extended client library handles messages up to 2 GB by storing payloads in S3, with virtually unlimited throughput.', 3, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/sqs-s3-messages.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is implementing a landing zone with AWS Control Tower. Which benefit does Control Tower provide over manually creating AWS accounts?', '[{"id": "a", "text": "Automated account provisioning with pre-configured guardrails, logging, and security baselines", "is_correct": true, "explanation": "Control Tower automates the setup of multi-account environments with built-in governance"}, {"id": "b", "text": "Lower AWS account costs", "is_correct": false, "explanation": "Control Tower does not reduce account costs"}, {"id": "c", "text": "Faster EC2 instance launch times", "is_correct": false, "explanation": "Instance performance is not affected by Control Tower"}, {"id": "d", "text": "Automatic application deployment", "is_correct": false, "explanation": "Control Tower manages account governance, not application deployment"}]', 'AWS Control Tower automates the creation of a well-architected multi-account environment with guardrails, centralized logging, and identity management.', 2, 'https://docs.aws.amazon.com/controltower/latest/userguide/what-is-control-tower.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to run a Windows-based batch processing job that requires GPU instances. Jobs run for 2-4 hours and must access a shared file system. Which architecture is appropriate?', '[{"id": "a", "text": "EC2 P3 instances with Amazon FSx for Windows File Server", "is_correct": true, "explanation": "P3 instances provide GPU compute and FSx for Windows provides a shared SMB file system"}, {"id": "b", "text": "AWS Batch with Fargate", "is_correct": false, "explanation": "Fargate does not support GPU instances"}, {"id": "c", "text": "Lambda with container images", "is_correct": false, "explanation": "Lambda does not support GPU or Windows"}, {"id": "d", "text": "SageMaker training jobs", "is_correct": false, "explanation": "SageMaker is for ML training not general Windows batch processing"}]', 'EC2 P-series instances provide GPU compute for Windows workloads, and FSx for Windows File Server provides a fully managed shared SMB file system.', 3, 'https://docs.aws.amazon.com/AWSEC2/latest/WindowsGuide/accelerated-computing-instances.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses AWS Elastic Beanstalk to deploy web applications. They want zero-downtime deployments where the new version runs alongside the old before traffic is switched. Which deployment policy should be used?', '[{"id": "a", "text": "Rolling deployment", "is_correct": false, "explanation": "Rolling updates replace instances in batches, causing temporary reduced capacity"}, {"id": "b", "text": "All at once", "is_correct": false, "explanation": "All at once replaces all instances simultaneously causing downtime"}, {"id": "c", "text": "Immutable deployment", "is_correct": true, "explanation": "Immutable deployment launches new instances with the new version in a temporary ASG, then swaps"}, {"id": "d", "text": "Rolling with additional batch", "is_correct": false, "explanation": "This adds instances but still replaces in place, not fully immutable"}]', 'Immutable deployments create a full set of new instances running the new version in a separate ASG, validate health, then swap into the original ASG.', 3, 'https://docs.aws.amazon.com/elasticbeanstalk/latest/dg/using-features.deploy-existing-version.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect needs to ensure that an EC2 instance automatically recovers if the underlying hardware fails. Which feature should be configured?', '[{"id": "a", "text": "EC2 instance reboot", "is_correct": false, "explanation": "Reboot does not help with hardware failures"}, {"id": "b", "text": "EBS volume detach and reattach", "is_correct": false, "explanation": "This does not address the instance hardware failure"}, {"id": "c", "text": "EC2 auto-recovery using a CloudWatch alarm on StatusCheckFailed_System", "is_correct": true, "explanation": "Auto-recovery automatically moves the instance to healthy hardware when a system status check fails"}, {"id": "d", "text": "Launch template with spot fleet", "is_correct": false, "explanation": "Spot fleet manages capacity but does not auto-recover specific instances"}]', 'EC2 auto-recovery uses CloudWatch alarms on system status checks to automatically migrate the instance to new hardware while preserving its instance ID, IP, and EBS volumes.', 3, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ec2-instance-recover.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to implement a write-through caching strategy for their DynamoDB table. Which service should be used as the cache?', '[{"id": "a", "text": "Amazon ElastiCache for Redis", "is_correct": false, "explanation": "ElastiCache works but requires application-level cache management"}, {"id": "b", "text": "Amazon CloudFront", "is_correct": false, "explanation": "CloudFront is a CDN for HTTP content, not database caching"}, {"id": "c", "text": "DynamoDB Accelerator (DAX)", "is_correct": true, "explanation": "DAX is a fully managed write-through cache specifically designed for DynamoDB"}, {"id": "d", "text": "AWS AppSync caching", "is_correct": false, "explanation": "AppSync caching is for GraphQL API responses, not direct DynamoDB caching"}]', 'DAX provides a fully managed, in-memory write-through cache for DynamoDB that requires no application code changes for cache management.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/DAX.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a real-time bidding platform that needs to handle 500,000 requests per second with ultra-low latency. The application is stateless. Which load balancer type is MOST appropriate?', '[{"id": "a", "text": "Application Load Balancer", "is_correct": false, "explanation": "ALB operates at Layer 7 with higher latency than NLB"}, {"id": "b", "text": "Network Load Balancer", "is_correct": true, "explanation": "NLB handles millions of requests per second with ultra-low latency at Layer 4"}, {"id": "c", "text": "Classic Load Balancer", "is_correct": false, "explanation": "CLB is legacy and does not match NLB performance"}, {"id": "d", "text": "Gateway Load Balancer", "is_correct": false, "explanation": "GWLB is for third-party virtual appliances, not application traffic"}]', 'Network Load Balancer operates at Layer 4, handling millions of connections per second with single-digit millisecond latency, ideal for high-throughput low-latency applications.', 3, 'https://docs.aws.amazon.com/elasticloadbalancing/latest/network/introduction.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to host a multi-container Docker application with service discovery between containers. They want minimal infrastructure management. Which approach is BEST?', '[{"id": "a", "text": "Amazon ECS on Fargate with AWS Cloud Map for service discovery", "is_correct": true, "explanation": "ECS Fargate eliminates server management and Cloud Map provides DNS-based service discovery"}, {"id": "b", "text": "Docker Compose on a single EC2 instance", "is_correct": false, "explanation": "A single EC2 instance is a single point of failure"}, {"id": "c", "text": "Amazon EKS with self-managed node groups", "is_correct": false, "explanation": "Self-managed nodes increase operational burden"}, {"id": "d", "text": "AWS Elastic Beanstalk multi-container Docker", "is_correct": false, "explanation": "Beanstalk multi-container requires managing the underlying EC2 instances"}]', 'ECS Fargate removes all server management while AWS Cloud Map provides automatic DNS-based service discovery for inter-container communication.', 3, 'https://docs.aws.amazon.com/AmazonECS/latest/developerguide/service-discovery.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs an in-memory data store for sub-millisecond response times. The data structure includes sorted sets, lists, and pub/sub channels. Which service should be used?', '[{"id": "a", "text": "Amazon ElastiCache for Memcached", "is_correct": false, "explanation": "Memcached only supports simple key-value pairs, not sorted sets or pub/sub"}, {"id": "b", "text": "Amazon ElastiCache for Redis", "is_correct": true, "explanation": "Redis supports advanced data structures including sorted sets, lists, hashes, and pub/sub"}, {"id": "c", "text": "Amazon DynamoDB with DAX", "is_correct": false, "explanation": "DynamoDB does not natively support sorted sets or pub/sub"}, {"id": "d", "text": "Amazon MemoryDB for Redis", "is_correct": false, "explanation": "MemoryDB provides durability but is more expensive for a pure caching use case"}]', 'ElastiCache for Redis provides sub-millisecond latency with support for advanced data structures including sorted sets, lists, streams, and pub/sub messaging.', 2, 'https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/WhatIs.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an application that uses Amazon RDS PostgreSQL. They want to create a disaster recovery solution in another Region with the ability to promote the DR database to primary. Which approach should be used?', '[{"id": "a", "text": "Use RDS automated backups copied to another Region", "is_correct": false, "explanation": "Backup restoration takes longer than promoting a replica"}, {"id": "b", "text": "Use AWS DMS for continuous replication", "is_correct": false, "explanation": "DMS adds operational complexity compared to native read replicas"}, {"id": "c", "text": "Create a cross-Region read replica and promote it during a disaster", "is_correct": true, "explanation": "Cross-Region read replicas provide asynchronous replication and can be promoted to standalone instances"}, {"id": "d", "text": "Use Aurora Global Database", "is_correct": false, "explanation": "Aurora Global Database requires Aurora, not RDS PostgreSQL"}]', 'RDS cross-Region read replicas asynchronously replicate data to another Region and can be promoted to a standalone primary instance during a disaster.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_ReadRepl.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is designing a data processing pipeline where each step depends on the output of the previous step. If any step fails, the entire pipeline should halt and notify operators. Which service provides this?', '[{"id": "a", "text": "AWS Step Functions with a Catch state that sends to an SNS topic", "is_correct": true, "explanation": "Step Functions orchestrates sequential steps with error handling that can route failures to SNS"}, {"id": "b", "text": "AWS Glue workflow", "is_correct": false, "explanation": "Glue workflows are for ETL jobs, not general-purpose pipeline orchestration"}, {"id": "c", "text": "Amazon EventBridge Pipes", "is_correct": false, "explanation": "Pipes connect a source to a target but do not orchestrate multi-step pipelines"}, {"id": "d", "text": "AWS CodePipeline", "is_correct": false, "explanation": "CodePipeline is for CI/CD, not general data processing pipelines"}]', 'Step Functions provides sequential execution with error handling via Catch states, enabling automatic pipeline halting and notification through SNS integration.', 3, 'https://docs.aws.amazon.com/step-functions/latest/dg/concepts-error-handling.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company stores application logs in CloudWatch Logs. They need to retain logs for 1 year for compliance but want to minimize costs. Which approach is MOST cost-effective?', '[{"id": "a", "text": "Set CloudWatch Logs retention to 365 days", "is_correct": false, "explanation": "CloudWatch Logs retention is more expensive than S3 Glacier for long-term storage"}, {"id": "b", "text": "Export logs to S3 using a subscription filter and transition to S3 Glacier after 30 days", "is_correct": true, "explanation": "S3 with Glacier lifecycle is significantly cheaper than long-term CloudWatch Logs retention"}, {"id": "c", "text": "Use CloudWatch Logs Insights for compression", "is_correct": false, "explanation": "Logs Insights is for querying, not storage optimization"}, {"id": "d", "text": "Delete logs after 30 days", "is_correct": false, "explanation": "Deleting logs violates the 1-year compliance requirement"}]', 'Exporting logs to S3 via subscription filters and using lifecycle policies to transition to Glacier provides the most cost-effective long-term log retention.', 3, 'https://docs.aws.amazon.com/AmazonCloudWatch/latest/logs/S3Export.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a high-traffic API on EC2 instances behind an ALB. They notice that health checks are incorrectly marking healthy instances as unhealthy. What should be investigated?', '[{"id": "a", "text": "Check that the health check path returns HTTP 200 and the interval/threshold settings are appropriate for the application startup time", "is_correct": true, "explanation": "Misconfigured health check paths or aggressive thresholds can cause false unhealthy marks"}, {"id": "b", "text": "Increase the instance size", "is_correct": false, "explanation": "Instance size does not affect health check accuracy"}, {"id": "c", "text": "Disable health checks", "is_correct": false, "explanation": "Disabling health checks prevents load balancer from routing around failures"}, {"id": "d", "text": "Switch to TCP health checks", "is_correct": false, "explanation": "TCP checks only verify the port is open, missing application-level issues"}]', 'ALB health checks must target a path that reliably returns 200 OK. The interval, timeout, and healthy/unhealthy thresholds must account for application startup time.', 3, 'https://docs.aws.amazon.com/elasticloadbalancing/latest/application/target-group-health-checks.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to process large-scale ETL jobs that transform data from multiple sources into a data warehouse. Which fully managed service should be used?', '[{"id": "a", "text": "Amazon EMR", "is_correct": false, "explanation": "EMR requires cluster management and is not fully serverless"}, {"id": "b", "text": "AWS Glue", "is_correct": true, "explanation": "Glue is a fully managed serverless ETL service that discovers, transforms, and loads data"}, {"id": "c", "text": "AWS Lambda", "is_correct": false, "explanation": "Lambda has timeout and memory limits that may be insufficient for large ETL"}, {"id": "d", "text": "Amazon Redshift Spectrum", "is_correct": false, "explanation": "Spectrum queries data in S3 but does not perform ETL transformations"}]', 'AWS Glue provides serverless ETL with automatic schema discovery via crawlers, PySpark/Python transformations, and integrated job scheduling.', 2, 'https://docs.aws.amazon.com/glue/latest/dg/what-is-glue.html', 'SAA-C03-1.4', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to implement a time-to-live (TTL) mechanism to automatically delete expired items from a DynamoDB table. How should this be configured?', '[{"id": "a", "text": "Enable TTL on a numeric attribute that stores the expiration time as a Unix epoch timestamp", "is_correct": true, "explanation": "DynamoDB TTL automatically deletes items whose TTL attribute value is past the current time"}, {"id": "b", "text": "Create a scheduled Lambda function to scan and delete expired items", "is_correct": false, "explanation": "This is operationally complex and incurs scan costs"}, {"id": "c", "text": "Use DynamoDB Streams to detect and delete expired items", "is_correct": false, "explanation": "Streams react to changes but do not proactively expire items"}, {"id": "d", "text": "Set a lifecycle policy on the DynamoDB table", "is_correct": false, "explanation": "DynamoDB does not have lifecycle policies like S3"}]', 'DynamoDB TTL automatically deletes items when their TTL attribute (Unix epoch timestamp) is older than the current time, at no additional cost.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/TTL.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company runs a read-heavy app on RDS MySQL. Primary CPU is above 80% despite adding read replicas. What should the architect investigate first?', '[{"id": "a", "text": "Increase the primary instance size", "is_correct": false, "explanation": "Vertical scaling helps temporarily but does not address misdirected reads"}, {"id": "b", "text": "Verify the application is routing read queries to the read replica endpoint instead of the primary", "is_correct": true, "explanation": "If reads still target the primary adding replicas has no effect"}, {"id": "c", "text": "Enable Multi-AZ for the primary", "is_correct": false, "explanation": "Multi-AZ provides failover not read scaling"}, {"id": "d", "text": "Switch to DynamoDB", "is_correct": false, "explanation": "Switching engines is a major change and not the first troubleshooting step"}]', 'Read replicas only reduce primary CPU when the application uses the replica endpoints. Verify the connection strings before adding more replicas.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_ReadRepl.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company wants to improve the performance of their CloudFront distribution for dynamic API responses. Which CloudFront feature helps?', '[{"id": "a", "text": "Enable Origin Shield in a Region close to the origin", "is_correct": true, "explanation": "Origin Shield consolidates requests and reduces origin load for dynamic content"}, {"id": "b", "text": "Increase the default TTL to 86400 seconds", "is_correct": false, "explanation": "Long TTL caching is inappropriate for dynamic responses"}, {"id": "c", "text": "Use Lambda@Edge to rewrite all responses", "is_correct": false, "explanation": "Rewriting responses adds latency"}, {"id": "d", "text": "Switch to a Regional CloudFront distribution", "is_correct": false, "explanation": "There is no Regional CloudFront distribution type"}]', 'CloudFront Origin Shield adds a centralized caching layer that reduces origin load and optimizes connections for dynamic content.', 4, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/origin-shield.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company uses DynamoDB with provisioned capacity. They experience throttled reads during unpredictable traffic spikes. What is the simplest solution?', '[{"id": "a", "text": "Switch the table to on-demand capacity mode", "is_correct": true, "explanation": "On-demand mode automatically scales to handle any traffic level without planning"}, {"id": "b", "text": "Add DynamoDB Accelerator (DAX)", "is_correct": false, "explanation": "DAX helps latency but adds architectural complexity"}, {"id": "c", "text": "Implement exponential backoff", "is_correct": false, "explanation": "Backoff handles throttling gracefully but does not prevent it"}, {"id": "d", "text": "Create a Global Secondary Index", "is_correct": false, "explanation": "A GSI does not address capacity throttling"}]', 'DynamoDB on-demand capacity mode handles thousands of requests per second without capacity planning, automatically scaling with traffic.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/HowItWorks.ReadWriteCapacityMode.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A solutions architect needs to reduce Lambda cold start latency for API requests. Cold starts add 3-5 seconds. Which feature addresses this?', '[{"id": "a", "text": "Increase Lambda memory allocation", "is_correct": false, "explanation": "More memory speeds execution but does not eliminate cold starts"}, {"id": "b", "text": "Configure provisioned concurrency for the Lambda function", "is_correct": true, "explanation": "Provisioned concurrency keeps functions initialized and ready to respond immediately"}, {"id": "c", "text": "Use Lambda SnapStart", "is_correct": false, "explanation": "SnapStart is only available for Java runtimes"}, {"id": "d", "text": "Reduce the deployment package size", "is_correct": false, "explanation": "Smaller packages help marginally but do not eliminate cold starts"}]', 'Lambda provisioned concurrency pre-initializes execution environments, eliminating cold starts for latency-sensitive applications.', 3, 'https://docs.aws.amazon.com/lambda/latest/dg/provisioned-concurrency.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company operates a global web application and wants to route users to the nearest AWS Region. Which service provides the lowest network latency routing?', '[{"id": "a", "text": "Amazon CloudFront", "is_correct": false, "explanation": "CloudFront is a CDN for content not TCP/UDP traffic routing"}, {"id": "b", "text": "AWS Global Accelerator", "is_correct": true, "explanation": "Global Accelerator uses Anycast IPs and the AWS global network to route to the optimal endpoint"}, {"id": "c", "text": "Route 53 latency-based routing", "is_correct": false, "explanation": "DNS-based routing can have stale caching and higher resolution times"}, {"id": "d", "text": "AWS Direct Connect", "is_correct": false, "explanation": "Direct Connect is for on-premises connectivity not global user routing"}]', 'AWS Global Accelerator provides two static Anycast IP addresses and routes traffic over the AWS global network to the optimal endpoint.', 3, 'https://docs.aws.amazon.com/global-accelerator/latest/dg/what-is-global-accelerator.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'An application stores images in S3 and serves them via CloudFront. The architect wants to resize images on-the-fly based on query parameters. Which approach is MOST efficient?', '[{"id": "a", "text": "Pre-generate all possible image sizes in S3", "is_correct": false, "explanation": "Pre-generating wastes storage and may not cover all dimensions"}, {"id": "b", "text": "Use a Lambda@Edge function on origin request to resize and cache the result", "is_correct": true, "explanation": "Lambda@Edge processes the image at the edge on first request and CloudFront caches the result"}, {"id": "c", "text": "Use a CloudFront Function", "is_correct": false, "explanation": "CloudFront Functions have 10KB code limit and 1ms timeout, insufficient for image processing"}, {"id": "d", "text": "Deploy an EC2 image resizing service", "is_correct": false, "explanation": "EC2 adds infrastructure management overhead"}]', 'Lambda@Edge runs at CloudFront edge locations allowing dynamic image resizing on first request with subsequent requests served from cache.', 4, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/lambda-at-the-edge.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company has a DynamoDB table with partition key user_id. Some users generate far more traffic causing hot partitions. What should the architect do?', '[{"id": "a", "text": "Add a random suffix to the partition key and implement scatter-gather reads", "is_correct": true, "explanation": "Adding a random suffix distributes hot keys across multiple partitions"}, {"id": "b", "text": "Increase provisioned capacity", "is_correct": false, "explanation": "More capacity does not solve hot partitions as throttling occurs at partition level"}, {"id": "c", "text": "Create a GSI on a different attribute", "is_correct": false, "explanation": "A GSI does not change base table partition distribution"}, {"id": "d", "text": "Enable DynamoDB Streams", "is_correct": false, "explanation": "Streams capture changes but do not address hot partitions"}]', 'Write sharding by appending a random suffix to the partition key distributes writes across multiple physical partitions, preventing hot key throttling.', 4, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/bp-partition-key-sharding.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company runs a high-traffic PostgreSQL database on RDS. Connection count frequently hits max_connections. Which service helps manage connections?', '[{"id": "a", "text": "Increase the instance size for more max_connections", "is_correct": false, "explanation": "Larger instances have higher limits but the problem may recur"}, {"id": "b", "text": "Add more read replicas", "is_correct": false, "explanation": "Replicas help read scaling but not connection management to the writer"}, {"id": "c", "text": "Amazon RDS Proxy", "is_correct": true, "explanation": "RDS Proxy pools and shares database connections reducing overhead on the database"}, {"id": "d", "text": "Switch to Aurora Serverless v2", "is_correct": false, "explanation": "Aurora Serverless v2 scales compute but still has connection limits"}]', 'Amazon RDS Proxy maintains a pool of established connections and multiplexes application connections, reducing database connection overhead by up to 90%.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/rds-proxy.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company wants to accelerate S3 uploads from an on-premises data center in a distant Region. Which S3 feature helps?', '[{"id": "a", "text": "S3 Transfer Acceleration", "is_correct": true, "explanation": "Transfer Acceleration uses CloudFront edge locations to speed up long-distance transfers"}, {"id": "b", "text": "S3 multipart upload", "is_correct": false, "explanation": "Multipart parallelizes but does not optimize the network path"}, {"id": "c", "text": "S3 Intelligent-Tiering", "is_correct": false, "explanation": "Intelligent-Tiering manages storage classes not transfer speed"}, {"id": "d", "text": "S3 Batch Operations", "is_correct": false, "explanation": "Batch Operations processes existing objects not upload acceleration"}]', 'S3 Transfer Acceleration routes uploads through the nearest CloudFront edge location and over the optimized AWS backbone network.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/transfer-acceleration.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company is designing a DynamoDB schema for order data. Queries include all orders for a customer and all orders in a date range. Which key design is optimal?', '[{"id": "a", "text": "Partition key: order_id only", "is_correct": false, "explanation": "Cannot efficiently query by customer or date range"}, {"id": "b", "text": "Partition key: order_date, sort key: customer_id", "is_correct": false, "explanation": "Using date as partition key creates hot partitions"}, {"id": "c", "text": "Partition key: customer_id, sort key: order_date, with a GSI on order_date", "is_correct": true, "explanation": "This supports both access patterns with the GSI enabling date range queries"}, {"id": "d", "text": "Composite partition key: customer_id#order_date", "is_correct": false, "explanation": "Requires knowing the exact combination to query"}]', 'A partition key of customer_id with sort key order_date supports per-customer queries. A GSI on order_date enables date range queries across all customers.', 3, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/bp-sort-keys.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company has an API that returns large JSON responses averaging 500 KB. Most responses are identical for the same query parameters. How can response time be improved?', '[{"id": "a", "text": "Increase Lambda memory to 10 GB", "is_correct": false, "explanation": "More memory helps processing speed but not repeated identical queries"}, {"id": "b", "text": "Enable API Gateway response caching with cache keys based on query parameters", "is_correct": true, "explanation": "API Gateway caching stores responses avoiding backend invocation for repeated queries"}, {"id": "c", "text": "Enable gzip compression on the API", "is_correct": false, "explanation": "Compression reduces payload size but still invokes the backend"}, {"id": "d", "text": "Use a larger DynamoDB instance", "is_correct": false, "explanation": "DynamoDB is serverless and does not have instance sizes"}]', 'API Gateway caching with cache keys based on query parameters stores and serves cached responses, eliminating backend calls for repeated queries.', 3, 'https://docs.aws.amazon.com/apigateway/latest/developerguide/api-gateway-caching.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A data analytics team runs Amazon Redshift queries that scan billions of rows. Query performance degrades as data grows. Which Redshift feature improves query performance on large tables?', '[{"id": "a", "text": "Define sort keys on frequently filtered columns and use distribution keys to co-locate joined tables", "is_correct": true, "explanation": "Sort keys enable zone map filtering and distribution keys minimize data shuffling during joins"}, {"id": "b", "text": "Increase the number of nodes", "is_correct": false, "explanation": "More nodes help but do not optimize query patterns"}, {"id": "c", "text": "Use COPY instead of INSERT for data loading", "is_correct": false, "explanation": "COPY improves load performance not query performance"}, {"id": "d", "text": "Enable concurrency scaling", "is_correct": false, "explanation": "Concurrency scaling handles more concurrent queries not individual query speed"}]', 'Redshift sort keys allow the query optimizer to skip blocks of data (zone maps) and distribution keys co-locate related data to minimize inter-node data movement.', 4, 'https://docs.aws.amazon.com/redshift/latest/dg/c_best-practices-sort-key.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company serves a mobile app backend using API Gateway and Lambda. Users in Asia experience high latency because the API is deployed in us-east-1. What is the BEST solution?', '[{"id": "a", "text": "Add CloudFront in front of API Gateway", "is_correct": false, "explanation": "CloudFront helps with caching but does not reduce Lambda execution latency"}, {"id": "b", "text": "Increase Lambda memory in us-east-1", "is_correct": false, "explanation": "More memory does not reduce network round-trip time from Asia"}, {"id": "c", "text": "Use API Gateway edge-optimized endpoint", "is_correct": false, "explanation": "Edge-optimized endpoints use CloudFront for the API but still route to us-east-1 for Lambda"}, {"id": "d", "text": "Deploy the API in multiple Regions and use Route 53 latency-based routing", "is_correct": true, "explanation": "Multi-Region deployment with latency routing directs users to the nearest API endpoint"}]', 'Deploying the API in Regions closer to Asian users and using Route 53 latency-based routing minimizes network round-trip time.', 3, 'https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/routing-policy-latency.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company uses Amazon ElastiCache for Redis to cache database query results. Cache hit rate is only 40%. How can the cache hit rate be improved?', '[{"id": "a", "text": "Increase the ElastiCache node size", "is_correct": false, "explanation": "Larger nodes provide more memory but do not improve cache hit logic"}, {"id": "b", "text": "Switch to Memcached", "is_correct": false, "explanation": "Memcached has fewer features than Redis and does not improve hit rates"}, {"id": "c", "text": "Analyze query patterns and implement a cache-aside strategy with appropriate TTLs for each query type", "is_correct": true, "explanation": "Cache-aside with tuned TTLs ensures popular queries are cached while stale data is refreshed"}, {"id": "d", "text": "Reduce the TTL to 1 second", "is_correct": false, "explanation": "Very short TTLs cause most requests to miss the cache"}]', 'A cache-aside strategy where the application checks the cache first, queries the database on miss, and stores the result with an appropriate TTL maximizes cache hit rates.', 3, 'https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/Strategies.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company processes real-time streaming data using Kinesis Data Streams. They need to run SQL queries on the streaming data. Which service enables this?', '[{"id": "a", "text": "Amazon Athena", "is_correct": false, "explanation": "Athena queries data at rest in S3, not streaming data"}, {"id": "b", "text": "Amazon Kinesis Data Analytics (Managed Service for Apache Flink)", "is_correct": true, "explanation": "Kinesis Data Analytics runs SQL or Flink queries on streaming data in real-time"}, {"id": "c", "text": "Amazon Redshift Streaming Ingestion", "is_correct": false, "explanation": "Redshift streaming ingestion loads data but does not process it in real-time"}, {"id": "d", "text": "AWS Glue Streaming ETL", "is_correct": false, "explanation": "Glue streaming ETL transforms data but uses Spark not SQL on streams"}]', 'Kinesis Data Analytics (now Managed Service for Apache Flink) enables real-time SQL and Flink processing of streaming data from Kinesis Data Streams.', 3, 'https://docs.aws.amazon.com/managed-flink/latest/java/what-is.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants to enforce MFA for all IAM users accessing the AWS Console. Which approach is MOST effective?', '[{"id": "a", "text": "Create an IAM policy that denies all actions except IAM self-service when MFA is not present", "is_correct": true, "explanation": "A deny policy with aws:MultiFactorAuthPresent condition enforces MFA"}, {"id": "b", "text": "Enable MFA on the root account only", "is_correct": false, "explanation": "Root MFA does not enforce MFA for IAM users"}, {"id": "c", "text": "Send email reminders to all users", "is_correct": false, "explanation": "Reminders are not enforceable"}, {"id": "d", "text": "Use AWS Config to detect users without MFA", "is_correct": false, "explanation": "Config detects but does not enforce MFA"}]', 'An IAM policy with a Deny effect and aws:MultiFactorAuthPresent condition effectively requires MFA for all actions except self-service MFA setup.', 3, 'https://docs.aws.amazon.com/IAM/latest/UserGuide/reference_policies_examples_aws_my-sec-creds-self-manage-mfa-only.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to encrypt data at the application layer before sending it to S3. They want AWS-managed keys. Which approach should be used?', '[{"id": "a", "text": "SSE-S3 server-side encryption", "is_correct": false, "explanation": "SSE-S3 encrypts server-side not at the application layer"}, {"id": "b", "text": "AWS Encryption SDK with an AWS KMS key", "is_correct": true, "explanation": "The Encryption SDK performs client-side encryption using KMS master keys"}, {"id": "c", "text": "SSE-KMS server-side encryption", "is_correct": false, "explanation": "SSE-KMS is also server-side encryption"}, {"id": "d", "text": "SSL/TLS for data in transit", "is_correct": false, "explanation": "TLS encrypts in transit not at the application layer for storage"}]', 'The AWS Encryption SDK provides client-side envelope encryption using KMS master keys, encrypting data before it leaves the application.', 4, 'https://docs.aws.amazon.com/encryption-sdk/latest/developer-guide/introduction.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants to detect security threats like port scanning and cryptocurrency mining on EC2 instances. Which service should be enabled?', '[{"id": "a", "text": "Amazon GuardDuty", "is_correct": true, "explanation": "GuardDuty analyzes VPC Flow Logs, DNS logs, and CloudTrail events to detect threats"}, {"id": "b", "text": "Amazon Inspector", "is_correct": false, "explanation": "Inspector assesses vulnerabilities not real-time threat detection"}, {"id": "c", "text": "AWS Shield", "is_correct": false, "explanation": "Shield protects against DDoS not general security threats"}, {"id": "d", "text": "Amazon Macie", "is_correct": false, "explanation": "Macie discovers sensitive data in S3 not EC2 threats"}]', 'Amazon GuardDuty continuously monitors for malicious activity using ML and threat intelligence feeds.', 2, 'https://docs.aws.amazon.com/guardduty/latest/ug/what-is-guardduty.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A Lambda function needs to retrieve database credentials from Secrets Manager. What is the MOST secure approach?', '[{"id": "a", "text": "Store credentials as Lambda environment variables", "is_correct": false, "explanation": "Environment variables are visible in the console and less secure"}, {"id": "b", "text": "Attach an IAM execution role with secretsmanager:GetSecretValue for the specific secret ARN", "is_correct": true, "explanation": "Least privilege access via the execution role limits access to only the needed secret"}, {"id": "c", "text": "Hard-code credentials in the Lambda code", "is_correct": false, "explanation": "Hard-coding credentials is a security anti-pattern"}, {"id": "d", "text": "Store credentials in an S3 bucket", "is_correct": false, "explanation": "S3 adds complexity and requires separate access management"}]', 'Lambda execution roles provide temporary credentials via STS. A policy scoped to the specific secret ARN follows least privilege.', 2, 'https://docs.aws.amazon.com/secretsmanager/latest/userguide/auth-and-access.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs all API calls in their AWS account logged for security auditing. Which service provides this?', '[{"id": "a", "text": "Amazon CloudWatch Logs", "is_correct": false, "explanation": "CloudWatch Logs collects application logs not API audit trails"}, {"id": "b", "text": "AWS Config", "is_correct": false, "explanation": "Config tracks resource configuration changes not individual API calls"}, {"id": "c", "text": "AWS CloudTrail with a trail enabled for all Regions", "is_correct": true, "explanation": "CloudTrail records API calls across all Regions for comprehensive auditing"}, {"id": "d", "text": "VPC Flow Logs", "is_correct": false, "explanation": "Flow Logs capture network traffic not API calls"}]', 'AWS CloudTrail records every API call including caller identity, timestamp, and source IP, providing a complete audit trail.', 2, 'https://docs.aws.amazon.com/awscloudtrail/latest/userguide/cloudtrail-user-guide.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'An architect needs network-level isolation between app tiers in a VPC. The DB tier must only accept connections from the app tier. Which configuration is correct?', '[{"id": "a", "text": "Use NACLs to block all traffic between subnets", "is_correct": false, "explanation": "NACLs blocking all inter-subnet traffic would prevent app-to-DB communication"}, {"id": "b", "text": "Place all tiers in public subnets with different security groups", "is_correct": false, "explanation": "Database instances should never be in public subnets"}, {"id": "c", "text": "Use VPC peering between tiers", "is_correct": false, "explanation": "VPC peering connects different VPCs not tiers within the same VPC"}, {"id": "d", "text": "Place web tier in public subnets and DB tier in private subnets with security group allowing inbound only from the app tier security group", "is_correct": true, "explanation": "Security group referencing restricts database access to only the application tier instances"}]', 'Security group chaining allows each tier to only accept traffic from the previous tier by referencing the source security group.', 3, 'https://docs.aws.amazon.com/vpc/latest/userguide/security-group-rules.html', 'SAA-C03-3.3', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants to discover and classify sensitive data like PII in their S3 buckets. Which service provides this?', '[{"id": "a", "text": "Amazon Inspector", "is_correct": false, "explanation": "Inspector assesses vulnerabilities not data classification"}, {"id": "b", "text": "Amazon Macie", "is_correct": true, "explanation": "Macie uses ML to automatically discover and classify sensitive data in S3"}, {"id": "c", "text": "AWS Config", "is_correct": false, "explanation": "Config tracks resource configuration not data content"}, {"id": "d", "text": "Amazon Detective", "is_correct": false, "explanation": "Detective investigates security findings not data classification"}]', 'Amazon Macie uses ML and pattern matching to discover PII, credit card numbers, and credentials stored in S3 buckets.', 2, 'https://docs.aws.amazon.com/macie/latest/user/what-is-macie.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company requires all EBS volumes encrypted with a customer managed KMS key. How can they prevent unencrypted volume creation across the Organization?', '[{"id": "a", "text": "Enable EBS encryption by default in each account", "is_correct": false, "explanation": "Default encryption can be overridden per volume"}, {"id": "b", "text": "Create an AWS Config rule", "is_correct": false, "explanation": "Config detects but does not prevent unencrypted volumes"}, {"id": "c", "text": "Apply an SCP that denies ec2:CreateVolume unless ec2:Encrypted condition is true", "is_correct": true, "explanation": "An SCP enforces encryption across all member accounts at the organization level"}, {"id": "d", "text": "Train developers to always select encryption", "is_correct": false, "explanation": "Manual processes are not enforceable"}]', 'SCPs in AWS Organizations enforce EBS encryption by denying volume creation when the ec2:Encrypted condition key is not true.', 4, 'https://docs.aws.amazon.com/organizations/latest/userguide/orgs_manage_policies_scps_examples_ec2.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs free SSL/TLS certificates for their ALB that auto-renew. Which service should be used?', '[{"id": "a", "text": "AWS Certificate Manager (ACM)", "is_correct": true, "explanation": "ACM provides free public SSL/TLS certificates with automatic renewal"}, {"id": "b", "text": "AWS Private CA", "is_correct": false, "explanation": "Private CA issues private certificates not free public ones"}, {"id": "c", "text": "Self-signed certificates uploaded to IAM", "is_correct": false, "explanation": "Self-signed certificates cause browser warnings"}, {"id": "d", "text": "Third-party CA with manual renewal", "is_correct": false, "explanation": "Manual renewal is operationally burdensome"}]', 'AWS Certificate Manager provides free public SSL/TLS certificates that automatically renew and integrate with ALB, CloudFront, and API Gateway.', 2, 'https://docs.aws.amazon.com/acm/latest/userguide/acm-overview.html', 'SAA-C03-3.3', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants row-level security in DynamoDB so users can only access their own items. Which approach is recommended?', '[{"id": "a", "text": "Use IAM policies with dynamodb:LeadingKeys condition matching the user identity", "is_correct": true, "explanation": "dynamodb:LeadingKeys restricts access to items where partition key matches the user ID"}, {"id": "b", "text": "Create separate tables per user", "is_correct": false, "explanation": "Separate tables do not scale"}, {"id": "c", "text": "Implement access control in application code only", "is_correct": false, "explanation": "Application controls can be bypassed if IAM is permissive"}, {"id": "d", "text": "Use VPC endpoints to restrict by network", "is_correct": false, "explanation": "VPC endpoints restrict network access not row-level data"}]', 'DynamoDB fine-grained access control uses IAM condition keys like dynamodb:LeadingKeys to restrict users to items matching their user ID.', 4, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/specifying-conditions.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company runs EC2 instances 24/7 for production that will operate for at least 3 years. Which purchasing option provides the MOST savings?', '[{"id": "a", "text": "1-year No Upfront Reserved Instances", "is_correct": false, "explanation": "Smaller savings than 3-year All Upfront"}, {"id": "b", "text": "Spot Instances with persistent requests", "is_correct": false, "explanation": "Spot can be interrupted, unsuitable for always-on production"}, {"id": "c", "text": "On-Demand with Savings Plans", "is_correct": false, "explanation": "Good savings but less than 3-year All Upfront RIs"}, {"id": "d", "text": "3-year All Upfront Reserved Instances", "is_correct": true, "explanation": "3-year All Upfront RIs provide up to 72% discount"}]', '3-year All Upfront Reserved Instances provide the maximum discount for steady-state workloads with a known long-term commitment.', 2, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ec2-reserved-instances.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company wants to identify underutilized EC2 instances and get right-sizing recommendations. Which service should be used?', '[{"id": "a", "text": "AWS Cost Explorer", "is_correct": false, "explanation": "Cost Explorer shows spending but not right-sizing recommendations"}, {"id": "b", "text": "AWS Compute Optimizer", "is_correct": true, "explanation": "Compute Optimizer analyzes utilization metrics and recommends optimal instance types"}, {"id": "c", "text": "AWS Trusted Advisor", "is_correct": false, "explanation": "Trusted Advisor has basic idle checks but not detailed right-sizing"}, {"id": "d", "text": "Amazon CloudWatch", "is_correct": false, "explanation": "CloudWatch provides metrics but not optimization recommendations"}]', 'AWS Compute Optimizer uses ML to analyze CloudWatch metrics and recommend optimal instance types matching actual utilization.', 2, 'https://docs.aws.amazon.com/compute-optimizer/latest/ug/what-is-compute-optimizer.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company has S3 buckets with varying access patterns. Some objects are accessed frequently for 30 days then rarely. How can costs be minimized automatically?', '[{"id": "a", "text": "Lifecycle policy to Glacier after 30 days", "is_correct": false, "explanation": "Lifecycle policies are static and may move still-accessed objects"}, {"id": "b", "text": "Enable S3 Intelligent-Tiering", "is_correct": true, "explanation": "Intelligent-Tiering automatically moves objects between tiers based on access patterns"}, {"id": "c", "text": "S3 One Zone-IA for all buckets", "is_correct": false, "explanation": "One Zone-IA reduces availability and lacks automation"}, {"id": "d", "text": "S3 analytics to manually review patterns", "is_correct": false, "explanation": "Analytics requires manual action"}]', 'S3 Intelligent-Tiering monitors access patterns and automatically moves objects between frequent and infrequent tiers with no retrieval charges.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/intelligent-tiering.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company wants budget alerts when spending exceeds thresholds. Which service should be used?', '[{"id": "a", "text": "AWS Cost Explorer forecasting", "is_correct": false, "explanation": "Cost Explorer provides forecasts but not real-time budget alerts"}, {"id": "b", "text": "AWS Budgets with alert notifications via SNS", "is_correct": true, "explanation": "AWS Budgets allows custom cost thresholds with SNS or email notifications"}, {"id": "c", "text": "CloudWatch billing alarms", "is_correct": false, "explanation": "CloudWatch billing alarms are more basic than AWS Budgets"}, {"id": "d", "text": "AWS Organizations consolidated billing", "is_correct": false, "explanation": "Consolidated billing aggregates but does not alert"}]', 'AWS Budgets supports cost, usage, and reservation budgets with configurable thresholds and automated alerts.', 2, 'https://docs.aws.amazon.com/cost-management/latest/userguide/budgets-managing-costs.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company runs Lambda functions with varying execution times. How is Lambda pricing calculated?', '[{"id": "a", "text": "Per request plus duration in 1ms increments multiplied by allocated memory", "is_correct": true, "explanation": "Lambda charges per request and per GB-second of compute time in 1ms increments"}, {"id": "b", "text": "Per request only regardless of duration", "is_correct": false, "explanation": "Lambda charges include duration"}, {"id": "c", "text": "Per hour of allocated compute capacity", "is_correct": false, "explanation": "Lambda does not charge per hour"}, {"id": "d", "text": "Per function deployment size", "is_correct": false, "explanation": "Deployment size does not directly affect pricing"}]', 'Lambda pricing includes number of requests and duration measured in 1ms increments multiplied by allocated memory (GB-seconds).', 2, 'https://docs.aws.amazon.com/lambda/latest/dg/gettingstarted-limits.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company has large data transfer costs between EC2 instances and S3 in the same Region. How can these costs be eliminated?', '[{"id": "a", "text": "Use S3 Transfer Acceleration", "is_correct": false, "explanation": "Transfer Acceleration adds cost, not reduces it"}, {"id": "b", "text": "Move instances to the same AZ as the S3 bucket", "is_correct": false, "explanation": "S3 is a regional service, not AZ-specific"}, {"id": "c", "text": "Compress all data before transfer", "is_correct": false, "explanation": "Compression reduces volume but does not eliminate charges"}, {"id": "d", "text": "Use a VPC gateway endpoint for S3 which has no data processing charges", "is_correct": true, "explanation": "Gateway endpoints for S3 are free and eliminate NAT gateway data processing charges"}]', 'VPC gateway endpoints for S3 are free and route traffic privately, eliminating NAT gateway data processing charges for S3 traffic.', 3, 'https://docs.aws.amazon.com/vpc/latest/privatelink/vpc-endpoints-s3.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company runs batch jobs that are fault-tolerant and flexible on start time. Jobs run for 2-6 hours. Which EC2 purchasing option minimizes cost?', '[{"id": "a", "text": "Spot Instances", "is_correct": true, "explanation": "Spot Instances provide up to 90% discount for fault-tolerant interruptible workloads"}, {"id": "b", "text": "On-Demand Instances", "is_correct": false, "explanation": "On-Demand is the most expensive option"}, {"id": "c", "text": "Reserved Instances", "is_correct": false, "explanation": "RIs require long-term commitment unsuitable for batch"}, {"id": "d", "text": "Dedicated Hosts", "is_correct": false, "explanation": "Dedicated Hosts are the most expensive option"}]', 'Spot Instances leverage unused EC2 capacity at up to 90% discount, ideal for fault-tolerant batch processing that can handle interruptions.', 1, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/using-spot-instances.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company has multiple AWS accounts and wants to see consolidated cost breakdown by team. Which feature enables this?', '[{"id": "a", "text": "AWS Cost Explorer with cost allocation tags", "is_correct": true, "explanation": "Cost allocation tags enable grouping and filtering costs by team, project, or any custom dimension"}, {"id": "b", "text": "AWS Budgets per account", "is_correct": false, "explanation": "Per-account budgets track spending but do not show cross-account team breakdowns"}, {"id": "c", "text": "CloudWatch billing metrics", "is_correct": false, "explanation": "Billing metrics show total spend, not team-level breakdowns"}, {"id": "d", "text": "AWS Organizations consolidated billing only", "is_correct": false, "explanation": "Consolidated billing combines invoices but does not tag-based breakdown"}]', 'Cost allocation tags (both AWS-generated and user-defined) enable detailed cost breakdown by team, project, or environment in Cost Explorer.', 2, 'https://docs.aws.amazon.com/awsaccountbilling/latest/aboutv2/cost-alloc-tags.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company wants to reduce NAT gateway costs for instances that only need to access AWS services like S3, DynamoDB, and SQS. What should they implement?', '[{"id": "a", "text": "Use public subnets for all instances", "is_correct": false, "explanation": "Public subnets expose instances to the internet"}, {"id": "b", "text": "Reduce instance count", "is_correct": false, "explanation": "Fewer instances means less work gets done"}, {"id": "c", "text": "Switch to IPv6", "is_correct": false, "explanation": "IPv6 requires an egress-only internet gateway, not a direct cost reduction"}, {"id": "d", "text": "VPC endpoints (gateway endpoints for S3/DynamoDB, interface endpoints for SQS)", "is_correct": true, "explanation": "VPC endpoints bypass NAT gateway for AWS service traffic, reducing data processing charges"}]', 'VPC gateway endpoints for S3/DynamoDB are free, and interface endpoints for SQS avoid NAT gateway data processing charges.', 3, 'https://docs.aws.amazon.com/vpc/latest/privatelink/gateway-endpoints.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company runs a development environment that is only used during business hours (8am-6pm weekdays). How can they reduce EC2 costs by 60%?', '[{"id": "a", "text": "Use Spot Instances for the dev environment", "is_correct": false, "explanation": "Spot interruptions may disrupt development work"}, {"id": "b", "text": "Right-size instances to smaller types", "is_correct": false, "explanation": "Right-sizing helps but does not achieve 60% savings alone"}, {"id": "c", "text": "Switch to Reserved Instances", "is_correct": false, "explanation": "RIs require 24/7 commitment and do not account for off-hours"}, {"id": "d", "text": "Use AWS Instance Scheduler to automatically stop and start instances based on a schedule", "is_correct": true, "explanation": "Stopping instances during off-hours eliminates compute charges for 14 hours per day plus weekends"}]', 'AWS Instance Scheduler automatically stops instances outside business hours, reducing compute costs by the percentage of time instances are stopped.', 2, 'https://docs.aws.amazon.com/solutions/latest/instance-scheduler-on-aws/solution-overview.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company wants to automate patching of their EC2 fleet across multiple accounts. Which service provides this?', '[{"id": "a", "text": "AWS CodeDeploy", "is_correct": false, "explanation": "CodeDeploy deploys application code not OS patches"}, {"id": "b", "text": "AWS Systems Manager Patch Manager", "is_correct": true, "explanation": "Patch Manager automates OS and application patching across EC2 fleets"}, {"id": "c", "text": "CloudFormation StackSets", "is_correct": false, "explanation": "StackSets deploys infrastructure not patches"}, {"id": "d", "text": "Amazon Inspector", "is_correct": false, "explanation": "Inspector identifies vulnerabilities but does not apply patches"}]', 'Systems Manager Patch Manager defines patch baselines, applies patches on schedule, and reports compliance across the entire fleet.', 2, 'https://docs.aws.amazon.com/systems-manager/latest/userguide/systems-manager-patch.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company needs to run commands on hundreds of EC2 instances without SSH access. Which Systems Manager feature should be used?', '[{"id": "a", "text": "Session Manager", "is_correct": false, "explanation": "Session Manager provides interactive shells not batch command execution"}, {"id": "b", "text": "Lambda with EC2 SDK calls", "is_correct": false, "explanation": "Lambda cannot execute commands inside instances"}, {"id": "c", "text": "Step Functions with EC2 API calls", "is_correct": false, "explanation": "Step Functions calls APIs, not in-instance commands"}, {"id": "d", "text": "Systems Manager Run Command", "is_correct": true, "explanation": "Run Command executes commands across managed instances without SSH/RDP"}]', 'Systems Manager Run Command enables batch command execution across fleets using pre-built or custom documents without SSH ports.', 2, 'https://docs.aws.amazon.com/systems-manager/latest/userguide/execute-remote-commands.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company wants automatic notification when an S3 bucket policy is changed to allow public access. Which combination of services should be used?', '[{"id": "a", "text": "AWS Config rule s3-bucket-public-read-prohibited with SNS notification", "is_correct": true, "explanation": "Config evaluates bucket policies in near real-time and sends notifications through SNS"}, {"id": "b", "text": "CloudTrail with CloudWatch Logs metric filter", "is_correct": false, "explanation": "More setup required than a managed Config rule"}, {"id": "c", "text": "S3 server access logging", "is_correct": false, "explanation": "Access logs record data access not policy changes"}, {"id": "d", "text": "Amazon GuardDuty", "is_correct": false, "explanation": "GuardDuty detects threats not configuration compliance"}]', 'AWS Config managed rules continuously evaluate S3 bucket policies and trigger SNS notifications when non-compliant changes are detected.', 3, 'https://docs.aws.amazon.com/config/latest/developerguide/s3-bucket-public-read-prohibited.html', 'SAA-C03-5.2', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company wants to manage infrastructure as code across multiple accounts and Regions from a single template. Which feature should be used?', '[{"id": "a", "text": "AWS CloudFormation StackSets", "is_correct": true, "explanation": "StackSets deploy templates across multiple accounts and Regions from a single operation"}, {"id": "b", "text": "CloudFormation nested stacks", "is_correct": false, "explanation": "Nested stacks organize templates within a single account"}, {"id": "c", "text": "AWS CDK", "is_correct": false, "explanation": "CDK generates CloudFormation but does not natively manage multi-account deployment"}, {"id": "d", "text": "Terraform workspaces", "is_correct": false, "explanation": "Terraform is third-party, not an AWS service"}]', 'CloudFormation StackSets enable deployment across multiple AWS accounts and Regions from a management account with drift detection.', 3, 'https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/what-is-cfnstacksets.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company runs containers on ECS and wants a fully managed CI/CD pipeline for automated deployments. Which services should be used?', '[{"id": "a", "text": "Jenkins on EC2", "is_correct": false, "explanation": "Jenkins requires infrastructure management"}, {"id": "b", "text": "CodePipeline with CodeBuild for image building and ECS rolling deployment", "is_correct": true, "explanation": "CodePipeline orchestrates the pipeline, CodeBuild creates images, and ECS deploys"}, {"id": "c", "text": "GitHub Actions only", "is_correct": false, "explanation": "GitHub Actions may not integrate as tightly with ECS"}, {"id": "d", "text": "AWS Batch", "is_correct": false, "explanation": "Batch is for batch computing not CI/CD"}]', 'AWS CodePipeline provides fully managed CI/CD orchestration integrating with CodeBuild for image creation and ECS for automated deployments.', 3, 'https://docs.aws.amazon.com/codepipeline/latest/userguide/welcome.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company needs to provide developers with secure shell access to EC2 instances in private subnets without opening SSH ports. Which service should be used?', '[{"id": "a", "text": "SSH via a bastion host in a public subnet", "is_correct": false, "explanation": "Bastion hosts require SSH ports and additional infrastructure"}, {"id": "b", "text": "AWS CloudShell", "is_correct": false, "explanation": "CloudShell provides a cloud-based terminal but not instance shell access"}, {"id": "c", "text": "EC2 Instance Connect", "is_correct": false, "explanation": "Instance Connect requires SSH port 22 to be open"}, {"id": "d", "text": "AWS Systems Manager Session Manager", "is_correct": true, "explanation": "Session Manager provides browser-based and CLI shell access without SSH ports or bastion hosts"}]', 'Session Manager provides encrypted shell access to instances through the SSM agent without requiring inbound SSH ports, key pairs, or bastion hosts.', 2, 'https://docs.aws.amazon.com/systems-manager/latest/userguide/session-manager.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company runs an application on oversized EC2 instances. Compute Optimizer recommends smaller types. What should the architect verify before right-sizing?', '[{"id": "a", "text": "Check if the instance uses Reserved Instance pricing", "is_correct": false, "explanation": "Pricing does not affect right-sizing suitability"}, {"id": "b", "text": "Ensure the instance has an Elastic IP", "is_correct": false, "explanation": "EIP is unrelated to instance sizing"}, {"id": "c", "text": "Verify the instance is in a placement group", "is_correct": false, "explanation": "Placement group does not affect right-sizing"}, {"id": "d", "text": "Verify peak utilization metrics fit within the recommended instance capacity including CPU, memory, and network", "is_correct": true, "explanation": "Compute Optimizer uses averages so peak usage must be validated before downsizing"}]', 'Before right-sizing, always verify that peak CPU, memory, and network utilization fit within the recommended instance capacity.', 3, 'https://docs.aws.amazon.com/compute-optimizer/latest/ug/view-ec2-recommendations.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company has a monolithic application they want to gradually decompose into microservices. Which service helps route traffic between the monolith and new services during migration?', '[{"id": "a", "text": "API Gateway with VPC link", "is_correct": false, "explanation": "API Gateway adds an extra hop for migration routing"}, {"id": "b", "text": "Application Load Balancer with path-based routing rules", "is_correct": true, "explanation": "ALB routes specific API paths to new microservices while keeping others on the monolith"}, {"id": "c", "text": "AWS App Mesh", "is_correct": false, "explanation": "App Mesh requires both services to be containerized"}, {"id": "d", "text": "Route 53 weighted routing", "is_correct": false, "explanation": "Route 53 cannot route based on URL paths"}]', 'ALB path-based routing allows incremental migration by routing specific URL paths to new microservices while the rest goes to the monolith.', 3, 'https://docs.aws.amazon.com/elasticloadbalancing/latest/application/listener-update-rules.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company wants to evaluate switching from On-Demand to Savings Plans. Which tool provides this analysis?', '[{"id": "a", "text": "AWS Pricing Calculator", "is_correct": false, "explanation": "Pricing Calculator estimates new workload costs not optimization"}, {"id": "b", "text": "AWS Trusted Advisor", "is_correct": false, "explanation": "Trusted Advisor provides RI recommendations not Savings Plans"}, {"id": "c", "text": "AWS Budgets", "is_correct": false, "explanation": "Budgets tracks spending but does not recommend Savings Plans"}, {"id": "d", "text": "AWS Cost Explorer Savings Plans recommendations", "is_correct": true, "explanation": "Cost Explorer analyzes historical usage and provides Savings Plans recommendations"}]', 'Cost Explorer analyzes historical On-Demand usage and calculates potential savings from Savings Plans with specific hourly commitment recommendations.', 2, 'https://docs.aws.amazon.com/cost-management/latest/userguide/ce-savings-plans.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company has a VPN connection that frequently drops due to internet instability. How can they improve reliability without immediate Direct Connect migration?', '[{"id": "a", "text": "Create a second VPN connection or use an accelerated Site-to-Site VPN", "is_correct": true, "explanation": "A second VPN provides redundancy and accelerated VPN uses the AWS global network"}, {"id": "b", "text": "Increase VPN tunnel bandwidth", "is_correct": false, "explanation": "VPN bandwidth is limited by the internet connection"}, {"id": "c", "text": "Switch to Client VPN", "is_correct": false, "explanation": "Client VPN is for individual user access not site-to-site"}, {"id": "d", "text": "Use VPC peering as a backup", "is_correct": false, "explanation": "VPC peering connects VPCs not on-premises to AWS"}]', 'Accelerated Site-to-Site VPN uses AWS Global Accelerator to route VPN traffic over the AWS global network instead of the public internet.', 3, 'https://docs.aws.amazon.com/vpn/latest/s2svpn/accelerated-vpn.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company is running an outdated Amazon Linux AMI. They want to upgrade to the latest AMI with minimal downtime. Which approach should they use?', '[{"id": "a", "text": "Stop each instance and change the AMI", "is_correct": false, "explanation": "Stopping instances causes downtime"}, {"id": "b", "text": "Create a new launch template version with the updated AMI and perform a rolling update via the Auto Scaling group", "is_correct": true, "explanation": "A new launch template version with rolling update gradually replaces instances with minimal downtime"}, {"id": "c", "text": "Create a CloudFormation stack update", "is_correct": false, "explanation": "Stack updates may cause full replacement depending on configuration"}, {"id": "d", "text": "Manually launch new instances and terminate old ones", "is_correct": false, "explanation": "Manual process is error-prone"}]', 'Updating the launch template AMI and performing an instance refresh via the ASG provides automated, gradual replacement with configurable minimum healthy percentage.', 3, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/asg-instance-refresh.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is migrating a workload that uses Amazon Aurora Serverless v2 which automatically scales database capacity based on application demand. They need to ensure zero data loss during the migration. Which AWS service facilitates this? The workload currently uses Amazon Aurora Serverless v2.', '[{"id": "a", "text": "AWS Database Migration Service (DMS) with change data capture", "is_correct": true, "explanation": "DMS CDC ensures ongoing replication with zero data loss during migration"}, {"id": "b", "text": "Manual database export and import", "is_correct": false, "explanation": "Manual migration causes downtime and potential data loss"}, {"id": "c", "text": "AWS DataSync", "is_correct": false, "explanation": "DataSync is for file transfer not database migration"}, {"id": "d", "text": "Amazon S3 replication", "is_correct": false, "explanation": "S3 replication does not handle database migration"}]', 'AWS DMS with CDC provides continuous replication ensuring zero data loss during database migration cutover.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/aurora-serverless-v2.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect needs to design a highly available architecture for Amazon MemoryDB for Redis. The service must survive an AZ failure. Which approach ensures this? The workload currently uses Amazon MemoryDB for Redis.', '[{"id": "a", "text": "Deploy in a single AZ with backups", "is_correct": false, "explanation": "Single AZ does not survive AZ failure"}, {"id": "b", "text": "Use a larger instance type", "is_correct": false, "explanation": "Larger instances do not provide AZ redundancy"}, {"id": "c", "text": "Enable enhanced monitoring", "is_correct": false, "explanation": "Monitoring detects but does not prevent outages"}, {"id": "d", "text": "Deploy across multiple Availability Zones with health checks and automatic failover", "is_correct": true, "explanation": "Multi-AZ deployment with failover ensures availability during AZ outages"}]', 'Multi-AZ deployment with automatic failover ensures the service remains available even when an entire Availability Zone experiences an outage.', 2, 'https://docs.aws.amazon.com/memorydb/latest/devguide/what-is-memorydb-for-redis.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to implement auto-scaling for their AWS App Runner deployment. Traffic is unpredictable with sudden spikes. Which scaling approach handles this BEST? The workload currently uses AWS App Runner.', '[{"id": "a", "text": "Manual scaling based on estimated peak", "is_correct": false, "explanation": "Manual scaling cannot react to unpredictable traffic"}, {"id": "b", "text": "Target tracking scaling based on the primary utilization metric", "is_correct": true, "explanation": "Target tracking automatically adjusts capacity to maintain the target metric value"}, {"id": "c", "text": "Scheduled scaling at fixed times", "is_correct": false, "explanation": "Scheduled scaling cannot handle unpredictable spikes"}, {"id": "d", "text": "Step scaling with 5-minute cooldown", "is_correct": false, "explanation": "Step scaling is less responsive than target tracking for variable workloads"}]', 'Target tracking Auto Scaling continuously adjusts capacity to maintain the target utilization metric, automatically handling unpredictable traffic spikes.', 3, 'https://docs.aws.amazon.com/apprunner/latest/dg/what-is-apprunner.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company stores critical data using Amazon OpenSearch Service. They need to implement a backup strategy with a 1-hour RPO. Which approach meets this requirement? The workload currently uses Amazon OpenSearch Service.', '[{"id": "a", "text": "Manual daily snapshots", "is_correct": false, "explanation": "Daily snapshots have an RPO of up to 24 hours"}, {"id": "b", "text": "Rely on the service default retention only", "is_correct": false, "explanation": "Default retention may not meet 1-hour RPO"}, {"id": "c", "text": "Export data to S3 weekly", "is_correct": false, "explanation": "Weekly exports have an RPO of up to 7 days"}, {"id": "d", "text": "Configure automated snapshots every hour using AWS Backup", "is_correct": true, "explanation": "AWS Backup schedules hourly snapshots ensuring RPO of 1 hour"}]', 'AWS Backup with hourly snapshot schedules ensures a maximum RPO of 1 hour for critical data.', 3, 'https://docs.aws.amazon.com/opensearch-service/latest/developerguide/what-is.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is evaluating AWS Proton for their workload. They need to understand the service limits and request increases before launch. Which tool helps identify current limits? The workload currently uses AWS Proton.', '[{"id": "a", "text": "AWS Trusted Advisor", "is_correct": false, "explanation": "Trusted Advisor shows some limits but Service Quotas is more comprehensive"}, {"id": "b", "text": "AWS Support tickets", "is_correct": false, "explanation": "Support tickets are for requesting increases not viewing current usage"}, {"id": "c", "text": "AWS Service Quotas dashboard with CloudWatch alarms on usage percentage", "is_correct": true, "explanation": "Service Quotas shows current limits and usage with the ability to request increases"}, {"id": "d", "text": "AWS documentation only", "is_correct": false, "explanation": "Documentation shows default limits not account-specific usage"}]', 'AWS Service Quotas provides a centralized dashboard showing current limits, usage, and the ability to request quota increases.', 2, 'https://docs.aws.amazon.com/proton/latest/userguide/Welcome.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is migrating a workload that uses Amazon EventBridge Pipes which creates point-to-point integrations between event producers and consumers. They need to ensure zero data loss during the migration. Which AWS service facilitates this? The workload currently uses Amazon EventBridge Pipes.', '[{"id": "a", "text": "Manual database export and import", "is_correct": false, "explanation": "Manual migration causes downtime and potential data loss"}, {"id": "b", "text": "AWS DataSync", "is_correct": false, "explanation": "DataSync is for file transfer not database migration"}, {"id": "c", "text": "Amazon S3 replication", "is_correct": false, "explanation": "S3 replication does not handle database migration"}, {"id": "d", "text": "AWS Database Migration Service (DMS) with change data capture", "is_correct": true, "explanation": "DMS CDC ensures ongoing replication with zero data loss during migration"}]', 'AWS DMS with CDC provides continuous replication ensuring zero data loss during database migration cutover.', 3, 'https://docs.aws.amazon.com/eventbridge/latest/userguide/eb-pipes.html', 'SAA-C03-1.3', true, true),
-- ============================================================
-- RESILIENT domain (continued) — questions 142-300
-- ============================================================
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a three-tier web application on AWS. The database tier uses Amazon RDS MySQL with a Single-AZ deployment. The company wants to improve availability with minimal changes to the application code. What should a solutions architect recommend?', '[{"id":"a","text":"Enable Multi-AZ deployment for the RDS instance","is_correct":true,"explanation":"Multi-AZ provides automatic failover to a standby replica in a different AZ with no application code changes required."},{"id":"b","text":"Create a read replica in another AZ","is_correct":false,"explanation":"Read replicas do not provide automatic failover for writes."},{"id":"c","text":"Migrate to Amazon DynamoDB","is_correct":false,"explanation":"Migrating to DynamoDB requires significant application changes."},{"id":"d","text":"Set up a cron job to snapshot the database every 5 minutes","is_correct":false,"explanation":"Frequent snapshots do not provide high availability or automatic failover."}]', 'RDS Multi-AZ creates a synchronous standby replica that automatically takes over on failure with no code changes.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/Concepts.MultiAZ.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect is designing a disaster recovery strategy for a critical application. The company requires an RPO of 1 hour and an RTO of 15 minutes. Which DR strategy meets these requirements most cost-effectively?', '[{"id":"a","text":"Backup and restore","is_correct":false,"explanation":"Backup and restore typically has an RTO of hours, not minutes."},{"id":"b","text":"Pilot light","is_correct":false,"explanation":"Pilot light typically has an RTO of tens of minutes, which may not meet the 15-minute requirement."},{"id":"c","text":"Warm standby","is_correct":true,"explanation":"Warm standby keeps a scaled-down but fully functional copy running, enabling an RTO of minutes."},{"id":"d","text":"Multi-site active-active","is_correct":false,"explanation":"Active-active meets the requirement but is not the most cost-effective option."}]', 'Warm standby maintains a scaled-down version of the environment that can be quickly scaled up, providing an RTO of minutes while being more cost-effective than active-active.', 3, 'https://docs.aws.amazon.com/whitepapers/latest/disaster-recovery-workloads-on-aws/disaster-recovery-options-in-the-cloud.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company operates an e-commerce platform with an Amazon Aurora MySQL cluster. During peak shopping events, the read queries become a bottleneck. The company wants to scale read capacity without affecting write performance. What should the architect recommend?', '[{"id":"a","text":"Increase the instance size of the primary instance","is_correct":false,"explanation":"Scaling up the primary helps writes but does not independently scale reads."},{"id":"b","text":"Add Aurora Replicas and use the reader endpoint for read queries","is_correct":true,"explanation":"Aurora Replicas share the same storage and the reader endpoint automatically load-balances read traffic."},{"id":"c","text":"Switch to Amazon RDS PostgreSQL","is_correct":false,"explanation":"Changing database engines does not solve the read scaling issue."},{"id":"d","text":"Enable Amazon ElastiCache and cache all database queries","is_correct":false,"explanation":"Caching helps but does not address all read scaling needs and requires application changes."}]', 'Aurora Replicas share the same underlying storage as the primary, so they can be added quickly. The reader endpoint automatically distributes connections across replicas.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Replication.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application stores session state in Amazon ElastiCache for Redis. The architect needs to ensure that session data survives a node failure without any data loss. Which configuration should be used?', '[{"id":"a","text":"Enable cluster mode with a single shard","is_correct":false,"explanation":"A single shard with cluster mode does not protect against node failure."},{"id":"b","text":"Enable Multi-AZ with automatic failover and AOF persistence","is_correct":true,"explanation":"Multi-AZ with auto-failover promotes a replica on failure, and AOF ensures data durability."},{"id":"c","text":"Use Memcached with multiple nodes","is_correct":false,"explanation":"Memcached does not support replication or persistence."},{"id":"d","text":"Take manual snapshots every hour","is_correct":false,"explanation":"Hourly snapshots result in up to 1 hour of data loss on failure."}]', 'ElastiCache for Redis with Multi-AZ auto-failover promotes a read replica to primary on failure. AOF (Append Only File) persistence ensures minimal data loss.', 3, 'https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/AutoFailover.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to host a static website with global low-latency access. The site must support HTTPS with a custom domain name. Which combination of AWS services should the architect use?', '[{"id":"a","text":"Amazon S3 static hosting with an S3 bucket policy for HTTPS","is_correct":false,"explanation":"S3 static hosting alone does not support HTTPS with custom domains."},{"id":"b","text":"Amazon S3 with Amazon CloudFront and AWS Certificate Manager","is_correct":true,"explanation":"CloudFront provides global CDN distribution, and ACM provides free SSL/TLS certificates for custom domains."},{"id":"c","text":"Amazon EC2 instances behind an Application Load Balancer","is_correct":false,"explanation":"EC2 is unnecessary for static content and adds cost and complexity."},{"id":"d","text":"AWS Amplify Hosting without a custom domain","is_correct":false,"explanation":"The requirement specifies a custom domain, which this option does not provide."}]', 'S3 for origin storage, CloudFront for global CDN with edge caching, and ACM for SSL/TLS certificates is the standard architecture for static websites on AWS.', 1, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/getting-started-secure-static-website-cloudformation.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application uses Amazon SQS to decouple a producer from a consumer. Some messages are processed more than once, causing duplicate orders. What should the architect do to prevent duplicate processing?', '[{"id":"a","text":"Increase the visibility timeout","is_correct":false,"explanation":"Increasing visibility timeout reduces reprocessing but does not guarantee exactly-once."},{"id":"b","text":"Switch to an SQS FIFO queue with deduplication enabled","is_correct":true,"explanation":"FIFO queues support exactly-once processing via message deduplication IDs."},{"id":"c","text":"Use Amazon SNS instead of SQS","is_correct":false,"explanation":"SNS is a pub/sub service and does not provide message deduplication."},{"id":"d","text":"Add more consumer instances","is_correct":false,"explanation":"More consumers may actually increase duplicate processing without deduplication logic."}]', 'SQS FIFO queues provide exactly-once processing by deduplicating messages using a deduplication ID within a 5-minute window.', 2, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/FIFO-queues.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to migrate a 50 TB Oracle database to Amazon Aurora PostgreSQL with minimal downtime. The database serves thousands of transactions per second. Which migration approach should the architect recommend?', '[{"id":"a","text":"Use AWS DMS with the Schema Conversion Tool for continuous replication","is_correct":true,"explanation":"DMS with SCT converts the schema and provides ongoing replication to minimize cutover downtime."},{"id":"b","text":"Export the database to CSV and import into Aurora","is_correct":false,"explanation":"CSV export/import causes extended downtime for a 50 TB database."},{"id":"c","text":"Use AWS Snowball to transfer the data","is_correct":false,"explanation":"Snowball is for bulk data transfer but does not handle ongoing replication for minimal downtime."},{"id":"d","text":"Set up Oracle GoldenGate to Aurora directly","is_correct":false,"explanation":"GoldenGate does not natively replicate to Aurora PostgreSQL without additional tooling."}]', 'AWS DMS combined with SCT handles schema conversion from Oracle to PostgreSQL and provides change data capture for continuous replication during the migration.', 4, 'https://docs.aws.amazon.com/dms/latest/userguide/Welcome.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect must design a highly available architecture for a containerized microservices application. The team wants to avoid managing the underlying infrastructure. Which service should they use?', '[{"id":"a","text":"Amazon ECS on EC2 instances","is_correct":false,"explanation":"ECS on EC2 still requires managing the underlying EC2 instances."},{"id":"b","text":"Amazon ECS on AWS Fargate","is_correct":true,"explanation":"Fargate is serverless compute for containers, eliminating the need to manage underlying infrastructure."},{"id":"c","text":"Amazon EC2 with Docker installed","is_correct":false,"explanation":"Running Docker on EC2 requires full infrastructure management."},{"id":"d","text":"AWS Elastic Beanstalk with a single instance","is_correct":false,"explanation":"Single instance deployment is not highly available."}]', 'AWS Fargate removes the need to provision and manage servers. Combined with ECS, it provides a fully managed container orchestration solution.', 2, 'https://docs.aws.amazon.com/AmazonECS/latest/developerguide/AWS_Fargate.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A company is designing a multi-region active-passive architecture for their web application. (Select TWO) Which components are required to enable automatic failover to the secondary region?', '[{"id":"a","text":"Amazon Route 53 health checks with failover routing policy","is_correct":true,"explanation":"Route 53 failover routing automatically directs traffic to the healthy region based on health checks."},{"id":"b","text":"AWS Global Accelerator with endpoint groups","is_correct":false,"explanation":"Global Accelerator helps with performance but is not required for active-passive failover."},{"id":"c","text":"Cross-region database replication","is_correct":true,"explanation":"The secondary region needs an up-to-date replica of the database to serve traffic after failover."},{"id":"d","text":"Amazon CloudFront with origin failover","is_correct":false,"explanation":"CloudFront origin failover handles origin failures, not full region failover."}]', 'Route 53 failover routing directs traffic based on health checks, and cross-region database replication ensures the standby region has current data.', 3, 'https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/routing-policy-failover.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application uses Amazon DynamoDB as its primary database. The architect must ensure the table can handle sudden spikes in traffic without throttling. The traffic pattern is unpredictable. Which capacity mode should be used?', '[{"id":"a","text":"Provisioned capacity with Auto Scaling","is_correct":false,"explanation":"Auto Scaling reacts to traffic changes but may not scale fast enough for sudden spikes."},{"id":"b","text":"On-demand capacity mode","is_correct":true,"explanation":"On-demand mode instantly accommodates any level of traffic without capacity planning."},{"id":"c","text":"Provisioned capacity with reserved capacity","is_correct":false,"explanation":"Reserved capacity is for predictable workloads and does not help with sudden spikes."},{"id":"d","text":"DAX caching layer with provisioned capacity","is_correct":false,"explanation":"DAX helps with read performance but does not solve write throttling from traffic spikes."}]', 'DynamoDB on-demand mode automatically scales to handle any level of request traffic instantly, making it ideal for unpredictable workloads.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/HowItWorks.ReadWriteCapacityMode.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company stores application logs in Amazon S3. They must ensure that log files cannot be deleted or overwritten for 7 years to comply with regulatory requirements. What should the architect implement?', '[{"id":"a","text":"S3 bucket versioning only","is_correct":false,"explanation":"Versioning preserves previous versions but does not prevent deletion."},{"id":"b","text":"S3 Object Lock in compliance mode with a 7-year retention period","is_correct":true,"explanation":"Object Lock in compliance mode prevents anyone, including the root user, from deleting objects until the retention period expires."},{"id":"c","text":"S3 bucket policy denying delete actions","is_correct":false,"explanation":"Bucket policies can be modified by administrators, so they do not provide immutable retention."},{"id":"d","text":"AWS Backup with a 7-year retention rule","is_correct":false,"explanation":"AWS Backup creates copies but does not prevent deletion of the original objects."}]', 'S3 Object Lock in compliance mode provides WORM (Write Once Read Many) protection that cannot be overridden, even by the root account.', 3, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/object-lock.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A startup wants to deploy a web application that must scale from zero to millions of requests. They want to minimize operational overhead and pay only for what they use. Which architecture should the architect recommend?', '[{"id":"a","text":"EC2 instances in an Auto Scaling group behind an ALB","is_correct":false,"explanation":"EC2 requires managing instances and has a minimum running cost even at zero traffic."},{"id":"b","text":"AWS Lambda with Amazon API Gateway","is_correct":true,"explanation":"Lambda scales automatically from zero, charges per invocation, and API Gateway handles HTTP routing."},{"id":"c","text":"Amazon ECS with Fargate and an ALB","is_correct":false,"explanation":"Fargate has minimum task charges and does not scale to zero as efficiently as Lambda."},{"id":"d","text":"Amazon Lightsail with a fixed monthly plan","is_correct":false,"explanation":"Lightsail has a fixed cost regardless of traffic and limited scalability."}]', 'Lambda with API Gateway is the most serverless option, scaling from zero to millions of concurrent requests with per-invocation pricing and no infrastructure management.', 1, 'https://docs.aws.amazon.com/lambda/latest/dg/welcome.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses an Amazon S3 bucket for data lake storage. They need to automatically transition objects to cost-effective storage classes based on access patterns without application changes. What should they configure?', '[{"id":"a","text":"S3 Lifecycle rules to transition to S3 Glacier after 30 days","is_correct":false,"explanation":"Fixed lifecycle rules do not adapt to actual access patterns."},{"id":"b","text":"S3 Intelligent-Tiering storage class","is_correct":true,"explanation":"Intelligent-Tiering automatically moves objects between access tiers based on actual usage patterns."},{"id":"c","text":"Manual monitoring and reclassification quarterly","is_correct":false,"explanation":"Manual processes are error-prone and do not scale."},{"id":"d","text":"S3 Batch Operations to change storage classes monthly","is_correct":false,"explanation":"Batch operations are manual and do not automatically adapt to access patterns."}]', 'S3 Intelligent-Tiering automatically moves objects between frequent and infrequent access tiers based on access patterns, with no retrieval fees or operational overhead.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/intelligent-tiering.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing a system where an application publishes events to multiple downstream consumers. Each consumer must receive every message independently. Which AWS service pattern should be used?', '[{"id":"a","text":"Amazon SQS with multiple consumers polling the same queue","is_correct":false,"explanation":"Multiple consumers on one SQS queue compete for messages; each message is delivered to only one consumer."},{"id":"b","text":"Amazon SNS topic with SQS subscriptions for each consumer","is_correct":true,"explanation":"SNS fan-out publishes each message to all subscribed SQS queues independently."},{"id":"c","text":"Amazon Kinesis Data Streams with a single shard","is_correct":false,"explanation":"Kinesis works but a single shard limits throughput and is more complex to set up for this use case."},{"id":"d","text":"Amazon EventBridge with a single target","is_correct":false,"explanation":"A single target does not fan out to multiple independent consumers."}]', 'The SNS-SQS fan-out pattern ensures every subscriber receives a copy of each message. Each SQS queue processes independently without affecting other consumers.', 2, 'https://docs.aws.amazon.com/sns/latest/dg/sns-sqs-as-subscriber.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a legacy application that requires a Windows file share accessible from multiple EC2 instances. The share must support Windows ACLs and Active Directory integration. Which AWS service should the architect use?', '[{"id":"a","text":"Amazon EFS with NFS mount","is_correct":false,"explanation":"EFS uses NFS protocol and does not support Windows ACLs or AD integration."},{"id":"b","text":"Amazon FSx for Windows File Server","is_correct":true,"explanation":"FSx for Windows provides fully managed Windows-native file shares with NTFS, ACLs, and AD integration."},{"id":"c","text":"Amazon S3 with a file gateway","is_correct":false,"explanation":"S3 with file gateway uses NFS/SMB but does not fully support Windows ACLs."},{"id":"d","text":"Amazon EBS volumes shared across instances","is_correct":false,"explanation":"Standard EBS volumes cannot be shared across multiple instances simultaneously."}]', 'Amazon FSx for Windows File Server provides native Windows file system features including NTFS permissions, Windows ACLs, and seamless Active Directory integration.', 2, 'https://docs.aws.amazon.com/fsx/latest/WindowsGuide/what-is.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A gaming company stores player profile data in DynamoDB. They need sub-millisecond read latency for frequently accessed items. What should the architect add?', '[{"id":"a","text":"DynamoDB Streams","is_correct":false,"explanation":"Streams capture changes but do not improve read latency."},{"id":"b","text":"Amazon DynamoDB Accelerator (DAX)","is_correct":true,"explanation":"DAX is an in-memory cache for DynamoDB that reduces read latency to microseconds."},{"id":"c","text":"A DynamoDB global secondary index","is_correct":false,"explanation":"GSIs provide alternative query patterns but do not significantly reduce read latency."},{"id":"d","text":"DynamoDB on-demand capacity","is_correct":false,"explanation":"On-demand mode handles capacity but does not reduce latency."}]', 'DAX provides a fully managed, in-memory caching layer for DynamoDB that delivers up to 10x read performance improvement with microsecond response times.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/DAX.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to replicate data from an on-premises NFS file server to Amazon S3 on a recurring schedule. The transfer must be encrypted in transit. Which service should the architect use?', '[{"id":"a","text":"AWS Transfer Family","is_correct":false,"explanation":"Transfer Family provides SFTP/FTPS endpoints but is not designed for scheduled NFS-to-S3 replication."},{"id":"b","text":"AWS DataSync","is_correct":true,"explanation":"DataSync automates and accelerates data transfer from NFS to S3 with built-in encryption and scheduling."},{"id":"c","text":"AWS Snowcone","is_correct":false,"explanation":"Snowcone is for offline data transfer not recurring scheduled replication."},{"id":"d","text":"S3 cross-region replication","is_correct":false,"explanation":"CRR replicates between S3 buckets, not from on-premises NFS."}]', 'AWS DataSync supports NFS as a source, provides automated scheduling, encrypts data in transit via TLS, and can transfer data at speeds up to 10x faster than open-source tools.', 2, 'https://docs.aws.amazon.com/datasync/latest/userguide/what-is-datasync.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing a system that processes financial transactions. Each transaction must be processed exactly once and in the exact order it was received. Which messaging service and configuration should be used?', '[{"id":"a","text":"Amazon SQS standard queue","is_correct":false,"explanation":"Standard queues provide at-least-once delivery and best-effort ordering, not strict FIFO."},{"id":"b","text":"Amazon SQS FIFO queue with message group IDs","is_correct":true,"explanation":"FIFO queues guarantee exactly-once processing and strict ordering within each message group."},{"id":"c","text":"Amazon SNS standard topic","is_correct":false,"explanation":"SNS does not guarantee message ordering."},{"id":"d","text":"Amazon MQ with ActiveMQ","is_correct":false,"explanation":"Amazon MQ supports ordering but is more complex and expensive for this use case."}]', 'SQS FIFO queues guarantee strict ordering within message groups and exactly-once processing via deduplication, making them ideal for financial transactions.', 3, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/FIFO-queues-exactly-once-processing.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A company is deploying a web application across two AWS Regions for disaster recovery. (Select TWO) Which services should the architect use to ensure the database and DNS are properly configured for failover?', '[{"id":"a","text":"Amazon Aurora Global Database","is_correct":true,"explanation":"Aurora Global Database replicates data across regions with sub-second replication lag."},{"id":"b","text":"Amazon RDS cross-region read replicas without promotion automation","is_correct":false,"explanation":"Manual promotion adds to RTO and does not provide seamless failover."},{"id":"c","text":"Amazon Route 53 with failover routing and health checks","is_correct":true,"explanation":"Route 53 failover routing automatically directs traffic to the healthy region."},{"id":"d","text":"AWS Direct Connect for inter-region connectivity","is_correct":false,"explanation":"Direct Connect is for on-premises to AWS, not inter-region failover."}]', 'Aurora Global Database provides cross-region replication with fast failover, and Route 53 failover routing directs users to the healthy region automatically.', 4, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/aurora-global-database.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A media company processes large video files uploaded to Amazon S3. Processing takes 30 minutes per file and must start automatically when a file is uploaded. Which architecture ensures reliable processing?', '[{"id":"a","text":"S3 event notification to Lambda, which processes the video directly","is_correct":false,"explanation":"Lambda has a 15-minute timeout, which is insufficient for 30-minute processing."},{"id":"b","text":"S3 event notification to SQS, with ECS Fargate tasks consuming the queue","is_correct":true,"explanation":"SQS decouples the trigger from processing, and Fargate tasks can run for as long as needed."},{"id":"c","text":"S3 event notification to SNS, which emails an operator to start processing","is_correct":false,"explanation":"Manual intervention is not automated and introduces delays."},{"id":"d","text":"CloudWatch Events polling S3 for new objects every minute","is_correct":false,"explanation":"Polling adds latency and is less efficient than event-driven architecture."}]', 'S3 events to SQS provides reliable message delivery, and ECS Fargate tasks have no time limit, making them suitable for long-running video processing.', 3, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/EventNotifications.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has a VPC with private subnets that need to access AWS services like S3 and DynamoDB without traversing the internet. What should the architect configure?', '[{"id":"a","text":"A NAT gateway in a public subnet","is_correct":false,"explanation":"NAT gateway routes traffic through the internet, which the requirement wants to avoid."},{"id":"b","text":"VPC gateway endpoints for S3 and DynamoDB","is_correct":true,"explanation":"Gateway endpoints provide private connectivity to S3 and DynamoDB without leaving the AWS network."},{"id":"c","text":"AWS PrivateLink interface endpoints for all services","is_correct":false,"explanation":"S3 and DynamoDB support gateway endpoints which are free, unlike interface endpoints."},{"id":"d","text":"A VPN connection to the AWS service endpoints","is_correct":false,"explanation":"VPN is for connecting on-premises networks, not for VPC-to-service connectivity."}]', 'VPC gateway endpoints route traffic to S3 and DynamoDB through the AWS private network at no additional cost. They are added to route tables as targets.', 2, 'https://docs.aws.amazon.com/vpc/latest/privatelink/gateway-endpoints.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application needs to store and retrieve 10 KB objects with single-digit millisecond latency. The data model uses a simple key-value pattern with no complex queries. Which database should the architect choose?', '[{"id":"a","text":"Amazon RDS PostgreSQL","is_correct":false,"explanation":"RDS is a relational database that adds overhead for simple key-value lookups."},{"id":"b","text":"Amazon DynamoDB","is_correct":true,"explanation":"DynamoDB provides single-digit millisecond latency for key-value access patterns at any scale."},{"id":"c","text":"Amazon Redshift","is_correct":false,"explanation":"Redshift is an analytical data warehouse not optimized for key-value operations."},{"id":"d","text":"Amazon Neptune","is_correct":false,"explanation":"Neptune is a graph database designed for relationship queries, not key-value patterns."}]', 'DynamoDB is purpose-built for key-value and document data models, delivering consistent single-digit millisecond performance at any scale.', 1, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/Introduction.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses AWS Lambda functions that need to access resources inside a VPC. After configuring VPC access, the Lambda functions can no longer reach the internet. What should the architect add to restore internet access?', '[{"id":"a","text":"An internet gateway attached to the VPC","is_correct":false,"explanation":"The VPC already has an internet gateway; Lambda in a private subnet cannot use it directly."},{"id":"b","text":"A NAT gateway in a public subnet with a route from the Lambda subnet","is_correct":true,"explanation":"Lambda functions in private subnets need a NAT gateway to reach the internet."},{"id":"c","text":"An Elastic IP attached to the Lambda function","is_correct":false,"explanation":"Lambda functions cannot have Elastic IPs directly attached."},{"id":"d","text":"A VPC peering connection to a public VPC","is_correct":false,"explanation":"VPC peering does not provide internet access."}]', 'When Lambda runs inside a VPC, it uses ENIs in the specified subnets. Private subnets need a NAT gateway in a public subnet for outbound internet access.', 3, 'https://docs.aws.amazon.com/lambda/latest/dg/configuration-vpc.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is building a real-time data pipeline that must ingest 1 million events per second from IoT devices. The data must be available for real-time analytics and stored for batch processing. Which architecture should the architect use?', '[{"id":"a","text":"Amazon SQS with Lambda consumers writing to S3","is_correct":false,"explanation":"SQS is not optimized for 1M events/second real-time ingestion and analytics."},{"id":"b","text":"Amazon Kinesis Data Streams for ingestion with Kinesis Data Firehose for S3 delivery","is_correct":true,"explanation":"Kinesis Data Streams handles massive real-time ingestion, and Firehose automatically delivers to S3 for batch processing."},{"id":"c","text":"Amazon SNS fan-out to multiple Lambda functions","is_correct":false,"explanation":"SNS with Lambda cannot sustain 1M events/second reliably."},{"id":"d","text":"Direct writes to Amazon S3 from each IoT device","is_correct":false,"explanation":"Direct S3 writes from millions of devices are not practical for real-time analytics."}]', 'Kinesis Data Streams can ingest millions of events per second. Firehose automatically batches and delivers to S3, while Kinesis Data Analytics can process the stream in real time.', 4, 'https://docs.aws.amazon.com/streams/latest/dev/introduction.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to use Amazon EFS for shared storage across multiple EC2 instances in different Availability Zones. They need the highest possible throughput for a data-intensive workload. Which EFS configuration should be used?', '[{"id":"a","text":"General Purpose performance mode with Bursting throughput","is_correct":false,"explanation":"Bursting throughput is limited by the file system size and may not sustain high throughput."},{"id":"b","text":"Max I/O performance mode with Provisioned throughput","is_correct":true,"explanation":"Max I/O provides the highest levels of aggregate throughput, and Provisioned ensures consistent performance."},{"id":"c","text":"General Purpose with Elastic throughput","is_correct":false,"explanation":"Elastic throughput auto-scales but General Purpose mode has lower per-operation latency at the cost of aggregate throughput."},{"id":"d","text":"One Zone storage class for lower latency","is_correct":false,"explanation":"One Zone reduces cost but does not improve throughput performance."}]', 'EFS Max I/O mode is designed for highly parallelized workloads with thousands of instances, and Provisioned throughput guarantees consistent performance regardless of storage size.', 4, 'https://docs.aws.amazon.com/efs/latest/ug/performance.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A solutions architect needs to design a decoupled architecture where a web application submits orders and a backend service processes them asynchronously. If the backend fails, orders must not be lost. Which approach is most reliable?', '[{"id":"a","text":"Write orders to a local file on the web server and poll from the backend","is_correct":false,"explanation":"Local files are not durable and are lost if the web server fails."},{"id":"b","text":"Send orders to an SQS queue and have the backend process messages from the queue","is_correct":true,"explanation":"SQS provides durable message storage with automatic retry, ensuring no orders are lost."},{"id":"c","text":"Make synchronous HTTP calls from the web app to the backend","is_correct":false,"explanation":"Synchronous calls fail when the backend is down, losing the order."},{"id":"d","text":"Store orders in ElastiCache and have the backend read from cache","is_correct":false,"explanation":"ElastiCache is in-memory and data can be lost on node failure without persistence configured."}]', 'SQS provides highly durable message storage (messages are stored redundantly across multiple AZs) with configurable retention up to 14 days.', 1, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/welcome.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a critical workload on Amazon EC2. They need to protect against hardware failures with automatic recovery while keeping the same private IP address, Elastic IP, and instance metadata. What should they use?', '[{"id":"a","text":"Auto Scaling group with min/max of 1","is_correct":false,"explanation":"A new instance from ASG gets a new private IP and does not retain the EIP automatically."},{"id":"b","text":"Amazon CloudWatch alarm with EC2 auto-recovery action","is_correct":true,"explanation":"EC2 auto-recovery moves the instance to new hardware while retaining its IP addresses, metadata, and EBS volumes."},{"id":"c","text":"Place the instance in a cluster placement group","is_correct":false,"explanation":"Placement groups optimize network performance but do not provide recovery."},{"id":"d","text":"Use a Dedicated Host with host recovery","is_correct":false,"explanation":"Dedicated Host recovery works but is significantly more expensive than standard auto-recovery."}]', 'EC2 auto-recovery powered by CloudWatch alarms recovers an instance on new hardware while preserving the instance ID, private/public IP, Elastic IP, and attached EBS volumes.', 3, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ec2-instance-recover.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An e-commerce company needs their product catalog search to return results in under 50 milliseconds with support for fuzzy matching and faceted search. Which AWS service should the architect choose?', '[{"id":"a","text":"Amazon RDS with full-text search","is_correct":false,"explanation":"RDS full-text search is limited and cannot guarantee sub-50ms for complex queries."},{"id":"b","text":"Amazon OpenSearch Service","is_correct":true,"explanation":"OpenSearch provides full-text search with fuzzy matching, faceted search, and sub-50ms response times."},{"id":"c","text":"Amazon DynamoDB with a scan operation","is_correct":false,"explanation":"DynamoDB scan is expensive and does not support fuzzy text matching."},{"id":"d","text":"Amazon Athena querying S3","is_correct":false,"explanation":"Athena is for ad-hoc SQL analytics, not low-latency search."}]', 'Amazon OpenSearch Service is optimized for full-text search workloads with features like fuzzy matching, relevance scoring, and faceted navigation.', 3, 'https://docs.aws.amazon.com/opensearch-service/latest/developerguide/what-is.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to implement blue/green deployments for their application running on Amazon ECS. They need to gradually shift traffic from the old version to the new version. Which service facilitates this?', '[{"id":"a","text":"Amazon ECS with rolling update deployment type","is_correct":false,"explanation":"Rolling updates replace tasks incrementally but do not support weighted traffic shifting."},{"id":"b","text":"AWS CodeDeploy with ECS blue/green deployment","is_correct":true,"explanation":"CodeDeploy supports ECS blue/green deployments with configurable traffic shifting (canary, linear, or all-at-once)."},{"id":"c","text":"Amazon Route 53 weighted routing","is_correct":false,"explanation":"Route 53 operates at the DNS level and is too coarse for ECS task-level traffic shifting."},{"id":"d","text":"Manual ALB listener rule updates","is_correct":false,"explanation":"Manual updates are error-prone and do not support automated rollback."}]', 'AWS CodeDeploy integrates with ECS to perform blue/green deployments, shifting traffic between target groups with automatic rollback on alarm triggers.', 3, 'https://docs.aws.amazon.com/codedeploy/latest/userguide/deployment-steps-ecs.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A healthcare application must encrypt all data at rest in Amazon S3 using keys managed by the company''s security team. The keys must be rotated annually and audit logs must show all key usage. Which encryption approach should the architect use?', '[{"id":"a","text":"S3 server-side encryption with Amazon S3 managed keys (SSE-S3)","is_correct":false,"explanation":"SSE-S3 keys are managed by AWS, not the company security team."},{"id":"b","text":"S3 server-side encryption with AWS KMS customer managed keys (SSE-KMS)","is_correct":true,"explanation":"KMS CMKs allow customer-controlled key management, annual rotation, and CloudTrail audit logs for all key usage."},{"id":"c","text":"Client-side encryption before uploading to S3","is_correct":false,"explanation":"Client-side encryption shifts key management burden to the application without centralized auditing."},{"id":"d","text":"S3 default encryption with SSE-S3 and a bucket policy","is_correct":false,"explanation":"SSE-S3 does not provide customer-managed keys or usage auditing."}]', 'SSE-KMS with customer managed keys provides centralized key management, automatic annual rotation, and CloudTrail logs for every key usage event.', 3, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/UsingKMSEncryption.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company hosts a global application and wants to route users to the nearest healthy endpoint with the lowest latency. The application is deployed in us-east-1, eu-west-1, and ap-southeast-1. Which Route 53 routing policy should be used?', '[{"id":"a","text":"Simple routing","is_correct":false,"explanation":"Simple routing does not consider latency or health."},{"id":"b","text":"Latency-based routing with health checks","is_correct":true,"explanation":"Latency-based routing directs users to the region with the lowest network latency, and health checks ensure only healthy endpoints receive traffic."},{"id":"c","text":"Geolocation routing","is_correct":false,"explanation":"Geolocation routes based on user location, not actual network latency."},{"id":"d","text":"Weighted routing with equal weights","is_correct":false,"explanation":"Weighted routing distributes traffic by percentage, not by latency."}]', 'Route 53 latency-based routing measures network latency between the user and each region, directing traffic to the lowest-latency healthy endpoint.', 2, 'https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/routing-policy-latency.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to run a batch processing workload that is fault-tolerant and can be interrupted. The workload typically takes 4 hours to complete. Which EC2 purchasing option provides the best cost savings?', '[{"id":"a","text":"On-Demand Instances","is_correct":false,"explanation":"On-Demand is the most expensive option for fault-tolerant batch workloads."},{"id":"b","text":"Spot Instances","is_correct":true,"explanation":"Spot Instances offer up to 90% savings and are ideal for fault-tolerant, interruptible workloads."},{"id":"c","text":"Reserved Instances with a 1-year term","is_correct":false,"explanation":"Reserved Instances require long-term commitment and are better for steady-state workloads."},{"id":"d","text":"Dedicated Hosts","is_correct":false,"explanation":"Dedicated Hosts are the most expensive option, used for licensing or compliance requirements."}]', 'Spot Instances provide up to 90% discount compared to On-Demand pricing. They are ideal for batch jobs that can handle interruptions by checkpointing progress.', 1, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/using-spot-instances.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application stores user-uploaded images in S3. The application must generate thumbnails immediately after upload. Which event-driven architecture should the architect implement?', '[{"id":"a","text":"Poll S3 every 30 seconds using a Lambda function","is_correct":false,"explanation":"Polling adds unnecessary latency and cost compared to event-driven design."},{"id":"b","text":"Configure S3 event notifications to trigger a Lambda function on object creation","is_correct":true,"explanation":"S3 event notifications trigger Lambda immediately when objects are created, enabling real-time thumbnail generation."},{"id":"c","text":"Use a scheduled EventBridge rule to check for new uploads hourly","is_correct":false,"explanation":"Hourly checks are not immediate processing."},{"id":"d","text":"Configure CloudTrail to detect PutObject calls and trigger SNS","is_correct":false,"explanation":"CloudTrail has delivery delays of minutes and is designed for auditing, not real-time processing."}]', 'S3 event notifications provide near-instant triggering of Lambda functions when objects are created, enabling real-time processing pipelines.', 1, 'https://docs.aws.amazon.com/lambda/latest/dg/with-s3.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company requires their Amazon RDS database to be encrypted at rest. The database is currently unencrypted with 2 TB of data. How can the architect enable encryption with minimal downtime?', '[{"id":"a","text":"Modify the existing RDS instance to enable encryption","is_correct":false,"explanation":"You cannot enable encryption on an existing unencrypted RDS instance."},{"id":"b","text":"Create an encrypted snapshot of the database and restore a new instance from it","is_correct":true,"explanation":"Create a snapshot, copy it with encryption enabled, then restore. This is the only way to encrypt an existing unencrypted RDS instance."},{"id":"c","text":"Enable transparent data encryption at the database engine level","is_correct":false,"explanation":"TDE is only available for SQL Server and Oracle on RDS, and this question asks about RDS-level encryption."},{"id":"d","text":"Attach an encrypted EBS volume to the RDS instance","is_correct":false,"explanation":"You cannot directly manage EBS volumes attached to RDS instances."}]', 'To encrypt an existing unencrypted RDS instance, take a snapshot, copy the snapshot with encryption, and restore a new encrypted instance from the encrypted snapshot.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/Overview.Encryption.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has multiple AWS accounts under AWS Organizations. They want to share a common VPC subnet with specific member accounts for resource deployment without VPC peering. Which feature should the architect use?', '[{"id":"a","text":"VPC peering between the shared VPC and each account VPC","is_correct":false,"explanation":"The requirement specifically asks for a solution without VPC peering."},{"id":"b","text":"AWS Resource Access Manager to share VPC subnets","is_correct":true,"explanation":"RAM allows sharing VPC subnets across accounts in the same Organization, letting other accounts launch resources directly in the shared subnet."},{"id":"c","text":"AWS Transit Gateway with route table associations","is_correct":false,"explanation":"Transit Gateway connects VPCs but does not share subnets for direct resource deployment."},{"id":"d","text":"AWS PrivateLink with interface endpoints in each account","is_correct":false,"explanation":"PrivateLink provides service access, not shared subnet deployment."}]', 'AWS RAM enables VPC subnet sharing across accounts, allowing resources in different accounts to communicate using private IPs in the same subnet.', 3, 'https://docs.aws.amazon.com/ram/latest/userguide/what-is.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to implement a caching strategy for their API responses. Cache entries should expire after 5 minutes, and the cache must be shared across multiple Lambda functions. Which solution should the architect use?', '[{"id":"a","text":"Lambda function local /tmp storage","is_correct":false,"explanation":"/tmp is local to a single execution environment and cannot be shared across invocations or functions."},{"id":"b","text":"Amazon ElastiCache for Redis with a TTL of 300 seconds","is_correct":true,"explanation":"ElastiCache Redis is a shared, in-memory cache that supports TTL-based expiration and can be accessed by multiple Lambda functions."},{"id":"c","text":"Amazon DynamoDB with a TTL attribute","is_correct":false,"explanation":"DynamoDB TTL deletes expired items eventually (within 48 hours) and does not guarantee 5-minute expiration."},{"id":"d","text":"Amazon S3 with a lifecycle rule","is_correct":false,"explanation":"S3 lifecycle rules have a minimum of 1 day and are not suitable for 5-minute cache expiration."}]', 'ElastiCache for Redis provides microsecond-latency shared caching with configurable TTL, accessible from any compute resource in the VPC.', 2, 'https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/Strategies.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company operates a data lake on Amazon S3. They need to enforce that all objects uploaded are encrypted with a specific KMS key. What should the architect configure?', '[{"id":"a","text":"Enable default encryption on the bucket","is_correct":false,"explanation":"Default encryption applies when no encryption is specified but does not prevent uploads with other keys."},{"id":"b","text":"A bucket policy that denies PutObject requests without the x-amz-server-side-encryption-aws-kms-key-id header matching the required key","is_correct":true,"explanation":"A bucket policy condition can enforce that only a specific KMS key is used for all uploads."},{"id":"c","text":"Enable S3 Object Lock","is_correct":false,"explanation":"Object Lock prevents deletion but does not enforce specific encryption keys."},{"id":"d","text":"Configure IAM policies to only allow KMS encrypt actions","is_correct":false,"explanation":"IAM policies control user permissions but do not enforce a specific key at the bucket level."}]', 'S3 bucket policies with conditions on the KMS key ID header ensure that every uploaded object uses the approved encryption key.', 4, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/UsingKMSEncryption.html', 'SAA-C03-1.2', true, true)
,
-- RESILIENT continued (questions 225-300)
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to migrate their on-premises Active Directory to AWS for EC2 Windows instances to join a domain. Which service provides a fully managed Microsoft AD experience?', '[{"id":"a","text":"AWS IAM Identity Center","is_correct":false,"explanation":"IAM Identity Center provides SSO but is not a managed Active Directory."},{"id":"b","text":"AWS Directory Service for Microsoft Active Directory (AWS Managed AD)","is_correct":true,"explanation":"AWS Managed AD provides a fully managed Microsoft AD in the cloud that EC2 instances can join."},{"id":"c","text":"Simple AD","is_correct":false,"explanation":"Simple AD is Samba-based and does not support all Microsoft AD features."},{"id":"d","text":"AD Connector","is_correct":false,"explanation":"AD Connector proxies requests to an existing on-premises AD but does not host a directory."}]', 'AWS Managed AD runs actual Microsoft Active Directory, supporting Group Policy, trusts, and seamless domain joining for EC2 Windows instances.', 2, 'https://docs.aws.amazon.com/directoryservice/latest/admin-guide/directory_microsoft_ad.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing a serverless workflow that orchestrates multiple Lambda functions, includes error handling and retry logic, and requires human approval at one step. Which service should be used?', '[{"id":"a","text":"Amazon SQS with dead-letter queues","is_correct":false,"explanation":"SQS handles messages but does not orchestrate multi-step workflows with human approval."},{"id":"b","text":"AWS Step Functions with a task token for human approval","is_correct":true,"explanation":"Step Functions provides visual workflow orchestration with built-in error handling, retries, and callback patterns for human approval."},{"id":"c","text":"Amazon EventBridge with multiple rules","is_correct":false,"explanation":"EventBridge routes events but does not orchestrate sequential workflows with approval steps."},{"id":"d","text":"AWS Lambda chaining via direct invocation","is_correct":false,"explanation":"Direct invocation creates tight coupling and does not support human approval patterns."}]', 'Step Functions supports callback patterns with task tokens, allowing workflows to pause and wait for human approval before continuing.', 3, 'https://docs.aws.amazon.com/step-functions/latest/dg/connect-to-resource.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to run GPU-intensive machine learning training jobs. The jobs can be interrupted and resumed from checkpoints. Each job takes 6-12 hours. Which EC2 instance strategy minimizes cost?', '[{"id":"a","text":"P4d On-Demand Instances","is_correct":false,"explanation":"On-Demand GPU instances are very expensive for interruptible workloads."},{"id":"b","text":"P4d Spot Instances with checkpointing to S3","is_correct":true,"explanation":"Spot Instances offer up to 90% savings on GPU instances, and checkpointing ensures work is not lost on interruption."},{"id":"c","text":"Reserved Instances with a 3-year term","is_correct":false,"explanation":"3-year commitment is unnecessary for interruptible batch workloads."},{"id":"d","text":"AWS Lambda with GPU support","is_correct":false,"explanation":"Lambda does not support GPU instances and has a 15-minute timeout."}]', 'Spot Instances for GPU workloads provide dramatic cost savings. Checkpointing to S3 enables resuming from the last checkpoint if an instance is reclaimed.', 3, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/spot-best-practices.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A company wants to implement a multi-tier architecture with strong network isolation between tiers. (Select TWO) Which AWS features should the architect use to control traffic between the web tier and application tier?', '[{"id":"a","text":"Security groups with rules allowing traffic only from the web tier security group","is_correct":true,"explanation":"Security groups can reference other security groups, allowing only traffic from authorized tiers."},{"id":"b","text":"Network ACLs on the application tier subnet with explicit allow/deny rules","is_correct":true,"explanation":"NACLs provide subnet-level stateless filtering as an additional layer of defense."},{"id":"c","text":"AWS WAF rules on the application tier","is_correct":false,"explanation":"WAF operates at the ALB/CloudFront level, not between VPC tiers."},{"id":"d","text":"IAM policies restricting EC2 communication","is_correct":false,"explanation":"IAM policies control API access, not network traffic between instances."}]', 'Security groups provide instance-level stateful filtering, while NACLs provide subnet-level stateless filtering. Together they provide defense in depth.', 2, 'https://docs.aws.amazon.com/vpc/latest/userguide/VPC_Security.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Amazon Aurora PostgreSQL. They need to execute read-heavy analytical queries without impacting the production OLTP workload. Which Aurora feature should the architect use?', '[{"id":"a","text":"Aurora read replicas in the same cluster","is_correct":false,"explanation":"Read replicas share cluster resources and may still impact the primary under heavy analytical load."},{"id":"b","text":"Aurora parallel query","is_correct":false,"explanation":"Parallel query optimizes queries but still runs against the same storage."},{"id":"c","text":"Aurora cloning for a separate analytical copy","is_correct":true,"explanation":"Aurora cloning creates a separate cluster using copy-on-write, allowing analytical queries on an isolated copy without affecting production."},{"id":"d","text":"Export to S3 and query with Athena","is_correct":false,"explanation":"Export adds latency and complexity, and data is not real-time."}]', 'Aurora cloning uses copy-on-write technology to create a cost-effective clone in minutes, providing complete isolation for analytical workloads.', 4, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Managing.Clone.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to transfer 80 TB of data from on-premises to S3 within 2 weeks. Their internet connection is 100 Mbps. Which method should the architect recommend?', '[{"id":"a","text":"Transfer over the internet using S3 multipart upload","is_correct":false,"explanation":"At 100 Mbps, transferring 80 TB would take approximately 74 days, exceeding the 2-week deadline."},{"id":"b","text":"Order an AWS Snowball Edge device","is_correct":true,"explanation":"Snowball Edge can store up to 80 TB and be shipped back to AWS within days, meeting the 2-week requirement."},{"id":"c","text":"Set up AWS Direct Connect","is_correct":false,"explanation":"Direct Connect provisioning takes weeks to months, exceeding the deadline."},{"id":"d","text":"Use AWS DataSync over the internet","is_correct":false,"explanation":"DataSync is limited by the 100 Mbps bandwidth and cannot meet the deadline."}]', 'AWS Snowball Edge provides 80 TB of usable storage. Physical shipping and data import typically completes within 1-2 weeks.', 2, 'https://docs.aws.amazon.com/snowball/latest/developer-guide/whatisedge.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An application uses an ALB to distribute traffic to EC2 instances. The architect needs to ensure that requests from the same user session always go to the same backend instance. What should be configured?', '[{"id":"a","text":"Enable cross-zone load balancing","is_correct":false,"explanation":"Cross-zone balancing distributes traffic evenly but does not provide session affinity."},{"id":"b","text":"Enable sticky sessions (session affinity) on the target group","is_correct":true,"explanation":"Sticky sessions use cookies to route requests from the same session to the same target instance."},{"id":"c","text":"Use a Network Load Balancer instead","is_correct":false,"explanation":"NLB does not support cookie-based sticky sessions."},{"id":"d","text":"Configure Route 53 with client-based routing","is_correct":false,"explanation":"Route 53 operates at DNS level and cannot route individual HTTP sessions."}]', 'ALB sticky sessions use cookies (application-based or duration-based) to bind a user session to a specific target, ensuring consistent routing.', 2, 'https://docs.aws.amazon.com/elasticloadbalancing/latest/application/sticky-sessions.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company stores encrypted data in S3. They need to share specific objects with a partner company for 24 hours without providing AWS credentials. What should the architect use?', '[{"id":"a","text":"Make the objects public temporarily","is_correct":false,"explanation":"Making objects public removes all access control and is a security risk."},{"id":"b","text":"Generate S3 presigned URLs with a 24-hour expiration","is_correct":true,"explanation":"Presigned URLs provide temporary, secure access to specific objects without requiring AWS credentials."},{"id":"c","text":"Create an IAM user for the partner","is_correct":false,"explanation":"Creating IAM users for external partners is a security anti-pattern."},{"id":"d","text":"Set up cross-account S3 access","is_correct":false,"explanation":"Cross-account access requires the partner to have an AWS account and IAM configuration."}]', 'S3 presigned URLs embed authentication in the URL itself, allowing anyone with the URL to access the object for a limited time without AWS credentials.', 1, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/using-presigned-url.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has a monolithic application deployed on a single EC2 instance. They want to gradually migrate to microservices while keeping both architectures running simultaneously. Which approach allows gradual migration with minimal risk?', '[{"id":"a","text":"Rewrite the entire application as microservices at once","is_correct":false,"explanation":"A complete rewrite is high risk and does not allow gradual migration."},{"id":"b","text":"Use the Strangler Fig pattern with an ALB routing specific paths to new microservices","is_correct":true,"explanation":"The Strangler Fig pattern allows gradual migration by routing specific URL paths to new microservices while the monolith handles the rest."},{"id":"c","text":"Deploy the monolith into containers without changes","is_correct":false,"explanation":"Containerizing the monolith does not achieve the goal of migrating to microservices."},{"id":"d","text":"Use AWS App Mesh to split the monolith automatically","is_correct":false,"explanation":"App Mesh provides service mesh capabilities but does not automatically decompose a monolith."}]', 'The Strangler Fig pattern uses path-based routing at the ALB to incrementally redirect functionality from the monolith to new microservices.', 3, 'https://docs.aws.amazon.com/prescriptive-guidance/latest/cloud-design-patterns/strangler-fig.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing a solution for a regulated industry where all API calls made within the AWS account must be logged and stored immutably for 5 years. Which configuration meets this requirement?', '[{"id":"a","text":"Enable AWS CloudTrail with an organization trail, deliver logs to S3 with Object Lock in compliance mode","is_correct":true,"explanation":"CloudTrail captures all API calls, and S3 Object Lock in compliance mode ensures logs cannot be deleted for 5 years."},{"id":"b","text":"Enable CloudWatch Logs for all services","is_correct":false,"explanation":"CloudWatch Logs does not capture all API calls and does not provide immutable storage."},{"id":"c","text":"Enable VPC Flow Logs","is_correct":false,"explanation":"VPC Flow Logs capture network traffic, not API calls."},{"id":"d","text":"Use AWS Config rules to detect API usage","is_correct":false,"explanation":"Config tracks resource configuration changes, not all API calls."}]', 'CloudTrail organization trails capture all management and data events across all accounts. S3 Object Lock compliance mode prevents any deletion for the retention period.', 4, 'https://docs.aws.amazon.com/awscloudtrail/latest/userguide/cloudtrail-concepts.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs Amazon EC2 instances that need to access a third-party SaaS API over the internet. The instances are in private subnets. The security team requires all outbound traffic to be inspected. What should the architect implement?', '[{"id":"a","text":"NAT gateway with VPC Flow Logs","is_correct":false,"explanation":"NAT gateway does not inspect traffic content; Flow Logs only capture metadata."},{"id":"b","text":"AWS Network Firewall in the VPC with inspection rules","is_correct":true,"explanation":"Network Firewall provides deep packet inspection for outbound traffic from private subnets."},{"id":"c","text":"Security groups with outbound rules","is_correct":false,"explanation":"Security groups allow/deny traffic but do not inspect packet contents."},{"id":"d","text":"AWS WAF on the NAT gateway","is_correct":false,"explanation":"WAF cannot be attached to a NAT gateway; it works with ALB, CloudFront, and API Gateway."}]', 'AWS Network Firewall provides stateful inspection, intrusion detection, and web filtering for traffic flowing through the VPC.', 4, 'https://docs.aws.amazon.com/network-firewall/latest/developerguide/what-is-aws-network-firewall.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs their Auto Scaling group to scale based on the number of messages in an SQS queue relative to the number of running instances. Which scaling policy type should the architect use?', '[{"id":"a","text":"Simple scaling with a CloudWatch alarm on ApproximateNumberOfMessages","is_correct":false,"explanation":"Simple scaling uses fixed steps and does not account for the ratio of messages to instances."},{"id":"b","text":"Target tracking scaling with a custom metric for backlog per instance","is_correct":true,"explanation":"Target tracking with backlog-per-instance metric scales proportionally to maintain a target processing rate."},{"id":"c","text":"Scheduled scaling based on expected traffic patterns","is_correct":false,"explanation":"Scheduled scaling is for predictable patterns, not dynamic queue-based scaling."},{"id":"d","text":"Step scaling with multiple thresholds","is_correct":false,"explanation":"Step scaling still uses absolute queue depth, not the per-instance ratio."}]', 'The backlog-per-instance metric (queue depth divided by running instances) with target tracking ensures each instance has a manageable number of messages to process.', 4, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/as-using-sqs-dead-letter-queues.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to serve private content through CloudFront. Only authenticated users of their application should access the files. Which CloudFront feature should the architect use?', '[{"id":"a","text":"S3 bucket policies allowing public read","is_correct":false,"explanation":"Public read removes all access control."},{"id":"b","text":"CloudFront signed URLs or signed cookies","is_correct":true,"explanation":"Signed URLs/cookies allow the application to control access by generating time-limited, authenticated URLs."},{"id":"c","text":"CloudFront geo-restriction","is_correct":false,"explanation":"Geo-restriction limits by country, not by user authentication."},{"id":"d","text":"S3 CORS configuration","is_correct":false,"explanation":"CORS controls cross-origin browser requests, not content access control."}]', 'CloudFront signed URLs provide time-limited access to specific files, while signed cookies grant access to multiple files. Both require a trusted key group.', 3, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/PrivateContent.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A financial services company uses RDS PostgreSQL and needs to perform point-in-time recovery to a specific second. How should the architect ensure this capability?', '[{"id":"a","text":"Create manual snapshots every hour","is_correct":false,"explanation":"Manual snapshots only allow recovery to the snapshot time, not to a specific second."},{"id":"b","text":"Enable automated backups with sufficient retention period","is_correct":true,"explanation":"RDS automated backups with transaction logs enable point-in-time recovery to any second within the retention window."},{"id":"c","text":"Use RDS read replicas as a backup","is_correct":false,"explanation":"Read replicas are not backups and do not support point-in-time recovery."},{"id":"d","text":"Export the database to S3 daily","is_correct":false,"explanation":"Daily exports only allow recovery to the export time."}]', 'RDS automated backups combine daily snapshots with transaction logs, enabling recovery to any point in time within the retention period (up to 35 days).', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_PIT.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company operates a microservices architecture where services communicate via HTTP APIs. They need centralized observability including distributed tracing to debug latency issues across services. Which service should the architect use?', '[{"id":"a","text":"Amazon CloudWatch Logs Insights","is_correct":false,"explanation":"Logs Insights queries logs but does not provide distributed tracing across services."},{"id":"b","text":"AWS X-Ray","is_correct":true,"explanation":"X-Ray provides distributed tracing, visualizing request flows and latency across microservices."},{"id":"c","text":"AWS CloudTrail","is_correct":false,"explanation":"CloudTrail logs API calls to AWS services, not application-level request tracing."},{"id":"d","text":"Amazon EventBridge","is_correct":false,"explanation":"EventBridge routes events between services but does not provide tracing."}]', 'AWS X-Ray traces requests across microservices, generating a service map that shows latency, errors, and dependencies between components.', 2, 'https://docs.aws.amazon.com/xray/latest/devguide/aws-xray.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is planning to use Amazon Aurora Serverless v2 for a new application with highly variable traffic. During peak hours, the database handles 10,000 transactions per second, but at night it drops to near zero. Why is Aurora Serverless v2 the best choice?', '[{"id":"a","text":"It provides fixed compute capacity at a lower cost","is_correct":false,"explanation":"Aurora Serverless v2 does not have fixed capacity; it scales dynamically."},{"id":"b","text":"It scales compute capacity automatically in fine-grained increments based on demand","is_correct":true,"explanation":"Aurora Serverless v2 scales in increments of 0.5 ACU, adjusting capacity in seconds to match workload demand."},{"id":"c","text":"It eliminates the need for a VPC","is_correct":false,"explanation":"Aurora Serverless v2 still requires a VPC."},{"id":"d","text":"It only supports read-heavy workloads","is_correct":false,"explanation":"Aurora Serverless v2 supports both read and write workloads."}]', 'Aurora Serverless v2 scales in 0.5 ACU increments within seconds, making it ideal for variable workloads that range from near-zero to high demand.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/aurora-serverless-v2.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an application that writes 50,000 small objects per second to S3. They are experiencing throttling. What should the architect do to resolve this?', '[{"id":"a","text":"Request an S3 service limit increase","is_correct":false,"explanation":"S3 has very high default limits (5,500 GET and 3,500 PUT per prefix per second); the issue is likely prefix design."},{"id":"b","text":"Distribute writes across multiple prefixes using randomized or hashed key prefixes","is_correct":true,"explanation":"S3 partitions data by prefix. Distributing writes across multiple prefixes increases aggregate throughput."},{"id":"c","text":"Switch to S3 Transfer Acceleration","is_correct":false,"explanation":"Transfer Acceleration speeds up transfers over long distances but does not address per-prefix throttling."},{"id":"d","text":"Use larger object sizes to reduce the number of PUT requests","is_correct":false,"explanation":"Changing object sizes requires application redesign and may not be feasible."}]', 'S3 supports 3,500 PUT/POST/DELETE and 5,500 GET per second per prefix. Distributing objects across multiple prefixes multiplies available throughput.', 4, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/optimizing-performance.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to deploy an application that requires a relational database with read replicas across 5 AWS Regions for a globally distributed user base. Which database service supports this natively?', '[{"id":"a","text":"Amazon RDS MySQL with cross-region read replicas","is_correct":false,"explanation":"RDS supports cross-region replicas but managing 5 regions is complex and replication lag can be high."},{"id":"b","text":"Amazon Aurora Global Database","is_correct":true,"explanation":"Aurora Global Database supports up to 5 secondary regions with sub-second replication lag and seamless failover."},{"id":"c","text":"Amazon DynamoDB Global Tables","is_correct":false,"explanation":"DynamoDB is a NoSQL database, not relational."},{"id":"d","text":"Amazon ElastiCache Global Datastore","is_correct":false,"explanation":"ElastiCache is a caching layer, not a relational database."}]', 'Aurora Global Database uses dedicated replication infrastructure for sub-second cross-region replication across up to 5 secondary regions with read-after-write consistency.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/aurora-global-database.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to automate the patching of their EC2 instances across multiple accounts and Regions. They need visibility into patch compliance. Which service should the architect use?', '[{"id":"a","text":"AWS Lambda with custom patching scripts","is_correct":false,"explanation":"Custom scripts are harder to manage and do not provide built-in compliance reporting."},{"id":"b","text":"AWS Systems Manager Patch Manager","is_correct":true,"explanation":"Patch Manager automates OS and software patching with compliance dashboards across accounts and Regions."},{"id":"c","text":"AWS Config with auto-remediation","is_correct":false,"explanation":"Config can detect non-compliance but does not perform the actual patching."},{"id":"d","text":"Amazon Inspector","is_correct":false,"explanation":"Inspector identifies vulnerabilities but does not perform patching."}]', 'Systems Manager Patch Manager provides automated patching with patch baselines, maintenance windows, and compliance reporting across multi-account environments.', 2, 'https://docs.aws.amazon.com/systems-manager/latest/userguide/systems-manager-patch.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses S3 for storing application data. They want to receive notifications when S3 request error rates exceed 5% over a 5-minute period. Which approach should the architect use?', '[{"id":"a","text":"S3 server access logging with manual log analysis","is_correct":false,"explanation":"Manual log analysis does not provide real-time alerting."},{"id":"b","text":"CloudWatch metrics for S3 with a math expression alarm on the error rate","is_correct":true,"explanation":"S3 request metrics in CloudWatch combined with metric math can calculate error rates and trigger alarms."},{"id":"c","text":"AWS CloudTrail data events with SNS notifications","is_correct":false,"explanation":"CloudTrail logs API calls but does not calculate error rates or trigger threshold-based alerts."},{"id":"d","text":"S3 Event Notifications for failed requests","is_correct":false,"explanation":"S3 Event Notifications do not support filtering by request errors."}]', 'CloudWatch metric math allows dividing 4xxErrors and 5xxErrors by AllRequests to calculate an error rate percentage, then alarming when it exceeds a threshold.', 3, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/metrics-configurations.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to migrate an on-premises Oracle data warehouse to AWS. The warehouse runs complex analytical queries across petabytes of data. Which AWS service is the best target?', '[{"id":"a","text":"Amazon RDS Oracle","is_correct":false,"explanation":"RDS Oracle is limited in size and not optimized for petabyte-scale analytics."},{"id":"b","text":"Amazon Redshift","is_correct":true,"explanation":"Redshift is a petabyte-scale data warehouse optimized for complex analytical queries with columnar storage."},{"id":"c","text":"Amazon Aurora PostgreSQL","is_correct":false,"explanation":"Aurora is optimized for OLTP, not petabyte-scale analytical workloads."},{"id":"d","text":"Amazon DynamoDB","is_correct":false,"explanation":"DynamoDB is a key-value store not designed for complex analytical queries."}]', 'Amazon Redshift uses columnar storage, massively parallel processing, and result caching to deliver fast query performance on petabyte-scale data.', 2, 'https://docs.aws.amazon.com/redshift/latest/mgmt/welcome.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is building a serverless application that needs to maintain WebSocket connections for real-time chat. Which service supports WebSocket APIs with serverless compute?', '[{"id":"a","text":"Amazon API Gateway REST API with Lambda","is_correct":false,"explanation":"REST APIs do not support persistent WebSocket connections."},{"id":"b","text":"Amazon API Gateway WebSocket API with Lambda","is_correct":true,"explanation":"API Gateway WebSocket APIs maintain persistent connections and invoke Lambda for connect, disconnect, and message events."},{"id":"c","text":"Application Load Balancer with Lambda targets","is_correct":false,"explanation":"ALB with Lambda does not support WebSocket connections."},{"id":"d","text":"Amazon CloudFront with Lambda@Edge","is_correct":false,"explanation":"CloudFront does not support WebSocket connections natively."}]', 'API Gateway WebSocket APIs manage persistent connections, route messages based on content, and integrate with Lambda for serverless message handling.', 3, 'https://docs.aws.amazon.com/apigateway/latest/developerguide/apigateway-websocket-api.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect needs to ensure that an Auto Scaling group launches instances with the latest approved AMI. They want to automate AMI creation and distribution. Which service should be used?', '[{"id":"a","text":"AWS Systems Manager Automation","is_correct":false,"explanation":"Automation can run workflows but is not purpose-built for AMI creation pipelines."},{"id":"b","text":"EC2 Image Builder","is_correct":true,"explanation":"Image Builder automates the creation, testing, and distribution of AMIs with configurable pipelines."},{"id":"c","text":"AWS Lambda with EC2 CreateImage API","is_correct":false,"explanation":"Custom Lambda functions add maintenance burden compared to a managed solution."},{"id":"d","text":"AWS CodePipeline with a custom build step","is_correct":false,"explanation":"CodePipeline is for application CI/CD, not AMI pipeline management."}]', 'EC2 Image Builder provides managed pipelines for building, testing, and distributing AMIs. It supports scheduled builds and automatic distribution to multiple Regions.', 2, 'https://docs.aws.amazon.com/imagebuilder/latest/userguide/what-is-image-builder.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company deploys Lambda functions that need to connect to an RDS database. Under high concurrency, the database runs out of connections. What should the architect implement?', '[{"id":"a","text":"Increase the RDS instance size for more connections","is_correct":false,"explanation":"Scaling the database is expensive and does not solve the connection management issue."},{"id":"b","text":"Use Amazon RDS Proxy","is_correct":true,"explanation":"RDS Proxy pools and shares database connections, reducing connection overhead from Lambda''s concurrent executions."},{"id":"c","text":"Reduce Lambda concurrency to 1","is_correct":false,"explanation":"Reducing concurrency to 1 defeats the purpose of serverless scaling."},{"id":"d","text":"Cache all database queries in ElastiCache","is_correct":false,"explanation":"Not all queries can be cached, and this does not solve the connection exhaustion issue."}]', 'RDS Proxy maintains a pool of database connections that are shared across Lambda invocations, dramatically reducing connection overhead and improving failover time.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/rds-proxy.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to consolidate billing across 50 AWS accounts and apply consistent security policies. Which AWS service should the architect use?', '[{"id":"a","text":"AWS IAM with cross-account roles in each account","is_correct":false,"explanation":"Cross-account roles provide access but do not consolidate billing or enforce organization-wide policies."},{"id":"b","text":"AWS Organizations with Service Control Policies","is_correct":true,"explanation":"Organizations provides consolidated billing and SCPs enforce security guardrails across all member accounts."},{"id":"c","text":"AWS Control Tower without Organizations","is_correct":false,"explanation":"Control Tower requires Organizations; it cannot work independently."},{"id":"d","text":"AWS Trusted Advisor for policy enforcement","is_correct":false,"explanation":"Trusted Advisor provides recommendations but does not enforce policies."}]', 'AWS Organizations enables consolidated billing for cost management and SCPs provide preventive guardrails that restrict what actions are allowed in member accounts.', 2, 'https://docs.aws.amazon.com/organizations/latest/userguide/orgs_introduction.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has strict data residency requirements. All data must remain within a specific country. They need compute capacity in that country but AWS does not have a Region there. Which option can the architect use?', '[{"id":"a","text":"Use the nearest AWS Region with encryption","is_correct":false,"explanation":"Data would still be stored in another country, violating the residency requirement."},{"id":"b","text":"AWS Outposts deployed in the company''s on-premises data center in that country","is_correct":true,"explanation":"Outposts brings AWS infrastructure and services to the customer''s premises, keeping data within the required country."},{"id":"c","text":"AWS Local Zones","is_correct":false,"explanation":"Local Zones are AWS-managed and only exist in specific metro areas, not in every country."},{"id":"d","text":"Amazon CloudFront edge locations","is_correct":false,"explanation":"Edge locations cache content but do not provide compute or persistent storage with data residency guarantees."}]', 'AWS Outposts extends AWS infrastructure to any on-premises location, enabling data residency compliance while using familiar AWS services and APIs.', 3, 'https://docs.aws.amazon.com/outposts/latest/userguide/what-is-outposts.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs an application that needs to send transactional emails (order confirmations, password resets). They need high deliverability with bounce and complaint tracking. Which service should the architect use?', '[{"id":"a","text":"Amazon SNS with email subscriptions","is_correct":false,"explanation":"SNS email is for notifications, not transactional emails with deliverability management."},{"id":"b","text":"Amazon SES (Simple Email Service)","is_correct":true,"explanation":"SES provides high-deliverability transactional email with bounce/complaint tracking, DKIM signing, and reputation management."},{"id":"c","text":"AWS Lambda sending emails via SMTP relay","is_correct":false,"explanation":"Managing SMTP relays adds complexity without deliverability management features."},{"id":"d","text":"Amazon Pinpoint for all email types","is_correct":false,"explanation":"Pinpoint focuses on marketing campaigns; SES is purpose-built for transactional email."}]', 'Amazon SES provides a scalable email sending service with bounce/complaint handling, DKIM authentication, and deliverability dashboards.', 2, 'https://docs.aws.amazon.com/ses/latest/dg/Welcome.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect is designing a solution where EC2 instances in a private subnet need to resolve domain names for external services. The VPC does not have a NAT gateway. How should DNS resolution be configured?', '[{"id":"a","text":"Install a custom DNS server on an EC2 instance","is_correct":false,"explanation":"Custom DNS servers add management overhead and single points of failure."},{"id":"b","text":"Use the Amazon-provided DNS server (VPC DNS resolver at .2 address)","is_correct":true,"explanation":"The VPC DNS resolver at the VPC CIDR +2 address resolves both public and private DNS names without internet access."},{"id":"c","text":"Configure each instance to use Google public DNS (8.8.8.8)","is_correct":false,"explanation":"Without a NAT gateway, instances in private subnets cannot reach public DNS servers."},{"id":"d","text":"Use Route 53 Resolver outbound endpoints","is_correct":false,"explanation":"Outbound endpoints are for forwarding DNS queries to on-premises resolvers, not for basic resolution."}]', 'The Amazon-provided DNS server at the VPC CIDR base +2 address resolves public hostnames and Route 53 private hosted zones without requiring internet connectivity.', 2, 'https://docs.aws.amazon.com/vpc/latest/userguide/vpc-dns.html', 'SAA-C03-1.2', true, true)
,
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a legacy TCP-based application that requires static IP addresses for firewall whitelisting by their partners. The application runs on EC2 instances behind a load balancer. Which load balancer type supports static IP addresses?', '[{"id":"a","text":"Application Load Balancer","is_correct":false,"explanation":"ALB does not support static IP addresses; it uses dynamic IPs."},{"id":"b","text":"Network Load Balancer","is_correct":true,"explanation":"NLB supports static IP addresses (one per AZ) and can also use Elastic IPs."},{"id":"c","text":"Classic Load Balancer","is_correct":false,"explanation":"Classic Load Balancers do not support static IP addresses."},{"id":"d","text":"Gateway Load Balancer","is_correct":false,"explanation":"GWLB is for deploying third-party virtual appliances, not for general-purpose static IP load balancing."}]', 'NLB provides a static IP per Availability Zone and can optionally use Elastic IPs, making it ideal for clients that need to whitelist specific IP addresses.', 2, 'https://docs.aws.amazon.com/elasticloadbalancing/latest/network/introduction.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs a managed graph database to store and query highly connected data for a social networking application. Which service should the architect use?', '[{"id":"a","text":"Amazon DynamoDB","is_correct":false,"explanation":"DynamoDB is a key-value/document database not optimized for graph traversals."},{"id":"b","text":"Amazon Neptune","is_correct":true,"explanation":"Neptune is a fully managed graph database that supports Gremlin and SPARQL for querying highly connected datasets."},{"id":"c","text":"Amazon Redshift","is_correct":false,"explanation":"Redshift is a data warehouse for analytical queries, not graph traversals."},{"id":"d","text":"Amazon DocumentDB","is_correct":false,"explanation":"DocumentDB is a document database compatible with MongoDB, not a graph database."}]', 'Amazon Neptune supports Property Graph (Gremlin) and RDF (SPARQL) models, making it ideal for use cases like social networks, fraud detection, and knowledge graphs.', 2, 'https://docs.aws.amazon.com/neptune/latest/userguide/intro.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A company wants to improve the resilience of their Lambda-based application. (Select TWO) Which practices should the architect implement to handle partial failures gracefully?', '[{"id":"a","text":"Configure dead-letter queues for asynchronous invocations","is_correct":true,"explanation":"DLQs capture failed events that exceeded retry limits, preventing data loss."},{"id":"b","text":"Set reserved concurrency to 0","is_correct":false,"explanation":"Setting reserved concurrency to 0 disables the function entirely."},{"id":"c","text":"Implement idempotency in function logic with a DynamoDB lock table","is_correct":true,"explanation":"Idempotency ensures retried invocations produce the same result, preventing duplicate processing."},{"id":"d","text":"Increase the function timeout to 15 minutes for all functions","is_correct":false,"explanation":"Maximum timeout does not improve resilience; it just delays failure detection."}]', 'DLQs ensure failed events are preserved for investigation, and idempotent function design handles retries safely without side effects.', 3, 'https://docs.aws.amazon.com/lambda/latest/dg/invocation-async.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is using Amazon S3 Cross-Region Replication for disaster recovery. They discover that delete markers are not being replicated to the destination bucket. What should the architect do?', '[{"id":"a","text":"Enable delete marker replication in the replication rule configuration","is_correct":true,"explanation":"By default, delete markers are not replicated. This must be explicitly enabled in the replication configuration."},{"id":"b","text":"Use S3 Batch Operations to sync deletions","is_correct":false,"explanation":"Batch Operations is not automatic and adds manual overhead."},{"id":"c","text":"Switch to Same-Region Replication","is_correct":false,"explanation":"Changing the replication type does not affect delete marker behavior."},{"id":"d","text":"Enable versioning on the destination bucket only","is_correct":false,"explanation":"Versioning must be enabled on both buckets for replication, but this does not affect delete marker replication."}]', 'S3 replication rules have an optional DeleteMarkerReplication setting. When enabled, delete markers created by user actions are replicated to the destination.', 3, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/delete-marker-replication.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to deploy a highly available NAT solution for their VPC. A single NAT gateway failure should not disrupt internet access for private subnets. What architecture should the architect implement?', '[{"id":"a","text":"One NAT gateway in a single AZ with routes from all private subnets","is_correct":false,"explanation":"A single NAT gateway is a single point of failure."},{"id":"b","text":"A NAT gateway in each AZ with each private subnet routing to its local AZ NAT gateway","is_correct":true,"explanation":"Deploying a NAT gateway per AZ ensures that an AZ failure only affects resources in that AZ."},{"id":"c","text":"A NAT instance with Auto Scaling across AZs","is_correct":false,"explanation":"NAT instances require more management and are less performant than NAT gateways."},{"id":"d","text":"An internet gateway directly attached to private subnets","is_correct":false,"explanation":"Internet gateways cannot be directly used by resources in private subnets."}]', 'Placing a NAT gateway in each AZ creates an AZ-independent architecture. If one AZ goes down, other AZs maintain internet connectivity independently.', 2, 'https://docs.aws.amazon.com/vpc/latest/userguide/vpc-nat-gateway.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses DynamoDB with provisioned capacity. They want to protect against accidentally exceeding capacity and causing throttling, while having the ability to absorb short bursts. Which feature provides this?', '[{"id":"a","text":"DynamoDB Auto Scaling only","is_correct":false,"explanation":"Auto Scaling adjusts capacity but has a delay that may not absorb sudden short bursts."},{"id":"b","text":"DynamoDB burst capacity combined with Auto Scaling","is_correct":true,"explanation":"DynamoDB reserves unused capacity for 5 minutes of burst, and Auto Scaling adjusts provisioned capacity for sustained changes."},{"id":"c","text":"DAX caching for all operations","is_correct":false,"explanation":"DAX only caches reads and does not help with write capacity throttling."},{"id":"d","text":"Switching to on-demand mode permanently","is_correct":false,"explanation":"On-demand mode may be more expensive for predictable workloads with occasional bursts."}]', 'DynamoDB burst capacity absorbs short traffic spikes using reserved unused capacity, while Auto Scaling handles sustained capacity changes by adjusting provisioned throughput.', 3, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/bp-partition-key-design.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to run a High Performance Computing (HPC) workload that requires low-latency inter-node communication between EC2 instances. Which placement strategy and network feature should the architect use?', '[{"id":"a","text":"Spread placement group with standard networking","is_correct":false,"explanation":"Spread groups place instances on separate hardware, increasing inter-node latency."},{"id":"b","text":"Cluster placement group with Elastic Fabric Adapter (EFA)","is_correct":true,"explanation":"Cluster placement packs instances close together, and EFA provides OS-bypass networking for minimal inter-node latency."},{"id":"c","text":"Partition placement group with enhanced networking","is_correct":false,"explanation":"Partition groups isolate partitions on separate racks, which is designed for large distributed workloads not tight HPC coupling."},{"id":"d","text":"Default placement with jumbo frames","is_correct":false,"explanation":"Default placement does not optimize for low-latency inter-node communication."}]', 'Cluster placement groups colocate instances for lowest latency, and EFA enables HPC applications to use OS-bypass for direct hardware communication.', 4, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/efa.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company hosts a web application that serves users globally. They need to accelerate TCP connections from users to the application running in us-east-1. CloudFront is not suitable because the content is dynamic and not cacheable. Which service should the architect use?', '[{"id":"a","text":"Amazon Route 53 with latency-based routing","is_correct":false,"explanation":"Route 53 optimizes DNS resolution but does not accelerate the TCP connection itself."},{"id":"b","text":"AWS Global Accelerator","is_correct":true,"explanation":"Global Accelerator uses the AWS global network to optimize TCP connections, reducing latency for dynamic content."},{"id":"c","text":"Amazon CloudFront with cache TTL of 0","is_correct":false,"explanation":"CloudFront with no caching still adds an extra hop without providing significant benefit for TCP acceleration."},{"id":"d","text":"VPC peering across regions","is_correct":false,"explanation":"VPC peering connects VPCs but does not help end users connect faster."}]', 'Global Accelerator routes traffic through the AWS backbone network from the nearest edge location, reducing internet hops and improving TCP connection performance.', 3, 'https://docs.aws.amazon.com/global-accelerator/latest/dg/what-is-global-accelerator.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to create an exact copy of a production database for testing without incurring the full storage cost. The copy should be available within minutes. Which Aurora feature meets this requirement?', '[{"id":"a","text":"Aurora read replica promotion","is_correct":false,"explanation":"Promoting a read replica creates a standalone database but is slower and costs the same as a full copy."},{"id":"b","text":"Aurora fast cloning","is_correct":true,"explanation":"Aurora cloning uses copy-on-write, creating an exact copy in minutes with no additional storage cost until data diverges."},{"id":"c","text":"Aurora snapshot restore","is_correct":false,"explanation":"Snapshot restore creates a full copy of the data, which is slower and costs full storage immediately."},{"id":"d","text":"Aurora backtrack","is_correct":false,"explanation":"Backtrack rewinds the database to a prior point in time but does not create a separate copy."}]', 'Aurora fast cloning uses copy-on-write technology where the clone shares the same underlying data pages. You only pay for additional storage as data changes.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Managing.Clone.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to deploy an application across 3 Availability Zones using an Auto Scaling group. They need to ensure instances are evenly distributed across AZs even when scaling events occur. Which Auto Scaling feature ensures this?', '[{"id":"a","text":"Predictive scaling","is_correct":false,"explanation":"Predictive scaling forecasts demand but does not control AZ distribution."},{"id":"b","text":"AZ rebalancing (default behavior)","is_correct":true,"explanation":"Auto Scaling automatically rebalances instances across specified AZs, launching new instances in the AZ with the fewest instances."},{"id":"c","text":"Scheduled scaling actions per AZ","is_correct":false,"explanation":"Scheduled scaling sets capacity at specific times but does not control AZ distribution."},{"id":"d","text":"Launch templates with AZ-specific AMIs","is_correct":false,"explanation":"AMIs are region-scoped, not AZ-specific, and this does not control distribution."}]', 'Auto Scaling groups automatically attempt to distribute instances evenly across the configured AZs and perform AZ rebalancing when the distribution becomes uneven.', 2, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/auto-scaling-benefits.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'An architect needs to design a solution for processing credit card payments that meets PCI DSS compliance. The cardholder data must be isolated from other workloads. Which approach should they take?', '[{"id":"a","text":"Deploy the payment service in the same VPC as other services with security groups","is_correct":false,"explanation":"Sharing a VPC increases the PCI compliance scope unnecessarily."},{"id":"b","text":"Deploy the payment service in a dedicated VPC with strict NACLs, encryption, and limited access","is_correct":true,"explanation":"A dedicated VPC minimizes the PCI compliance scope by isolating cardholder data environment from other workloads."},{"id":"c","text":"Use AWS Shield Advanced for PCI compliance","is_correct":false,"explanation":"Shield provides DDoS protection but does not address PCI DSS data isolation requirements."},{"id":"d","text":"Encrypt data in transit only","is_correct":false,"explanation":"PCI DSS requires both encryption at rest and in transit, plus network segmentation."}]', 'PCI DSS requires a segmented cardholder data environment. A dedicated VPC with strict access controls minimizes the scope of PCI compliance.', 4, 'https://docs.aws.amazon.com/whitepapers/latest/pci-dss-scoping-on-aws/pci-dss-scoping-on-aws.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to stream changes from a DynamoDB table to trigger real-time analytics and update a search index in OpenSearch. Which feature should the architect use?', '[{"id":"a","text":"DynamoDB point-in-time recovery","is_correct":false,"explanation":"PITR provides backup/restore, not real-time change streaming."},{"id":"b","text":"DynamoDB Streams with Lambda triggers","is_correct":true,"explanation":"DynamoDB Streams captures item-level changes in near real-time, and Lambda triggers can process them to update OpenSearch."},{"id":"c","text":"DynamoDB export to S3","is_correct":false,"explanation":"Export to S3 is a batch operation, not real-time streaming."},{"id":"d","text":"CloudTrail data events for DynamoDB","is_correct":false,"explanation":"CloudTrail captures API calls, not item-level data changes with before/after images."}]', 'DynamoDB Streams provides an ordered, time-sequenced log of item-level changes. Lambda triggers process each change record to update downstream systems in near real-time.', 3, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/Streams.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company hosts their application on EC2 behind an ALB. They want to protect against common web exploits like SQL injection and cross-site scripting. Which service provides this protection?', '[{"id":"a","text":"AWS Shield Standard","is_correct":false,"explanation":"Shield Standard protects against DDoS attacks but not application-layer exploits like SQLi or XSS."},{"id":"b","text":"AWS WAF with managed rule groups","is_correct":true,"explanation":"WAF inspects HTTP requests and AWS managed rules provide protection against common web exploits including SQLi and XSS."},{"id":"c","text":"Security groups with strict inbound rules","is_correct":false,"explanation":"Security groups filter by IP and port but do not inspect HTTP request content."},{"id":"d","text":"Amazon GuardDuty","is_correct":false,"explanation":"GuardDuty detects threats through log analysis but does not actively block web exploits."}]', 'AWS WAF integrates with ALB and CloudFront. AWS Managed Rules provide pre-configured protection against OWASP Top 10 vulnerabilities including SQLi and XSS.', 2, 'https://docs.aws.amazon.com/waf/latest/developerguide/what-is-aws-waf.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to set up a hybrid DNS resolution between their on-premises network and AWS VPCs. On-premises servers need to resolve AWS private hosted zone records. Which Route 53 feature should the architect configure?', '[{"id":"a","text":"Route 53 public hosted zones","is_correct":false,"explanation":"Public hosted zones resolve over the internet, not over private hybrid connections."},{"id":"b","text":"Route 53 Resolver inbound endpoints in the VPC","is_correct":true,"explanation":"Inbound endpoints allow on-premises DNS resolvers to forward queries to Route 53 Resolver for AWS private hosted zone resolution."},{"id":"c","text":"Route 53 health checks","is_correct":false,"explanation":"Health checks monitor endpoint health but do not handle DNS resolution forwarding."},{"id":"d","text":"VPC DHCP option sets with on-premises DNS servers","is_correct":false,"explanation":"DHCP option sets configure VPC DNS, not on-premises to AWS DNS resolution."}]', 'Route 53 Resolver inbound endpoints accept DNS queries from on-premises over VPN/Direct Connect and resolve them against VPC private hosted zones.', 4, 'https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/resolver.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Amazon EKS for their containerized applications. They need pods to access AWS services securely without storing long-lived credentials. What should the architect implement?', '[{"id":"a","text":"Store AWS access keys in Kubernetes secrets","is_correct":false,"explanation":"Long-lived credentials in secrets is a security anti-pattern."},{"id":"b","text":"IAM Roles for Service Accounts (IRSA)","is_correct":true,"explanation":"IRSA allows Kubernetes pods to assume IAM roles via OIDC federation, providing temporary credentials scoped to each service account."},{"id":"c","text":"EC2 instance profile on the worker nodes","is_correct":false,"explanation":"Instance profiles give all pods on a node the same permissions, violating least privilege."},{"id":"d","text":"AWS Secrets Manager with a sidecar container","is_correct":false,"explanation":"Secrets Manager stores secrets but is not the standard way to provide AWS API credentials to pods."}]', 'IRSA uses an OIDC identity provider to federate Kubernetes service accounts with IAM roles, providing fine-grained, temporary credentials per pod.', 3, 'https://docs.aws.amazon.com/eks/latest/userguide/iam-roles-for-service-accounts.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has an Auto Scaling group that needs to perform cleanup operations before instances are terminated. Scripts must run on the instance before it is removed. Which feature supports this?', '[{"id":"a","text":"User data scripts","is_correct":false,"explanation":"User data runs at launch, not at termination."},{"id":"b","text":"Auto Scaling lifecycle hooks with a termination hook","is_correct":true,"explanation":"Lifecycle hooks pause the instance in a Terminating:Wait state, allowing scripts to run before the instance is terminated."},{"id":"c","text":"CloudWatch alarms that trigger Lambda on termination","is_correct":false,"explanation":"Lambda can respond to events but cannot run scripts on the instance itself."},{"id":"d","text":"EC2 instance metadata tags","is_correct":false,"explanation":"Metadata tags do not trigger any actions on termination."}]', 'Lifecycle hooks place the instance in a wait state during termination. Custom scripts (via SSM Run Command or a local agent) can perform cleanup before completing the hook.', 3, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/lifecycle-hooks.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has a workload that processes messages from SQS but occasionally a message causes the consumer to crash. After multiple retries the poison message blocks other messages. What should the architect configure?', '[{"id":"a","text":"Increase the visibility timeout to avoid retries","is_correct":false,"explanation":"Increasing visibility timeout delays retries but does not remove the poison message."},{"id":"b","text":"A dead-letter queue with a maxReceiveCount threshold","is_correct":true,"explanation":"After the message exceeds maxReceiveCount, it is automatically moved to the DLQ, unblocking the main queue."},{"id":"c","text":"Delete the SQS queue and recreate it","is_correct":false,"explanation":"Deleting the queue loses all messages."},{"id":"d","text":"Use SNS instead of SQS","is_correct":false,"explanation":"SNS does not solve the poison message problem."}]', 'A dead-letter queue captures messages that fail processing after a configured number of receives, preventing a single bad message from blocking the entire queue.', 2, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/sqs-dead-letter-queues.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is designing a backup strategy for their AWS resources across multiple services (EC2, RDS, EFS, DynamoDB). They want a centralized backup management solution with cross-region copy. Which service should the architect use?', '[{"id":"a","text":"Custom Lambda functions with scheduled CloudWatch Events","is_correct":false,"explanation":"Custom solutions add maintenance burden and lack centralized management."},{"id":"b","text":"AWS Backup with backup plans and cross-region copy rules","is_correct":true,"explanation":"AWS Backup provides centralized policy-based backup management across multiple AWS services with cross-region copy."},{"id":"c","text":"Individual service backup features configured separately","is_correct":false,"explanation":"Separate configurations lack centralized governance and cross-service reporting."},{"id":"d","text":"AWS Storage Gateway for backup","is_correct":false,"explanation":"Storage Gateway is for hybrid storage, not native AWS resource backup management."}]', 'AWS Backup provides a centralized console to configure and audit backup policies across EC2, RDS, EFS, DynamoDB, and more, with built-in cross-region and cross-account copy.', 2, 'https://docs.aws.amazon.com/aws-backup/latest/devguide/whatisbackup.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a stateful application on EC2 instances. They use an ALB for load balancing and need to drain existing connections gracefully before terminating an instance during a scale-in event. What should the architect configure?', '[{"id":"a","text":"Connection draining on the ALB target group with a deregistration delay","is_correct":true,"explanation":"Deregistration delay (connection draining) allows in-flight requests to complete before the target is removed."},{"id":"b","text":"Cross-zone load balancing","is_correct":false,"explanation":"Cross-zone balancing distributes traffic evenly but does not handle graceful termination."},{"id":"c","text":"Slow start mode on the target group","is_correct":false,"explanation":"Slow start gradually increases traffic to new targets but does not handle draining from removed targets."},{"id":"d","text":"Lambda as a target for graceful shutdown","is_correct":false,"explanation":"Lambda targets do not help with draining connections from EC2 instances."}]', 'ALB deregistration delay keeps the target in draining state for a configurable period (default 300 seconds), allowing in-flight requests to complete before removal.', 2, 'https://docs.aws.amazon.com/elasticloadbalancing/latest/application/load-balancer-target-groups.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Amazon S3 for storing application data with versioning enabled. Storage costs are growing due to accumulated old versions. How can the architect reduce costs while keeping versioning enabled?', '[{"id":"a","text":"Disable versioning to stop creating new versions","is_correct":false,"explanation":"Disabling versioning loses the ability to recover from accidental deletions."},{"id":"b","text":"Configure a lifecycle rule to expire noncurrent versions after a specified number of days","is_correct":true,"explanation":"Lifecycle rules can automatically delete noncurrent versions after a retention period, controlling storage growth."},{"id":"c","text":"Manually delete old versions monthly","is_correct":false,"explanation":"Manual deletion does not scale and is error-prone."},{"id":"d","text":"Move the bucket to S3 One Zone-IA","is_correct":false,"explanation":"Changing storage class reduces per-GB cost but does not address the accumulation of old versions."}]', 'S3 lifecycle rules with NoncurrentVersionExpiration automatically remove old object versions after a configured retention period while keeping versioning active.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/lifecycle-expire-general-considerations.html', 'SAA-C03-1.2', true, true)
,
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to implement a message queue that supports message priority so that urgent messages are processed before normal ones. Which approach should the architect use?', '[{"id":"a","text":"A single SQS standard queue with message attributes for priority","is_correct":false,"explanation":"SQS does not support native priority-based ordering."},{"id":"b","text":"Separate SQS queues for each priority level with consumers polling high-priority first","is_correct":true,"explanation":"Using separate queues per priority with weighted polling logic ensures high-priority messages are consumed first."},{"id":"c","text":"SQS FIFO queue with message group IDs per priority","is_correct":false,"explanation":"FIFO message groups ensure ordering within a group but do not provide cross-group priority."},{"id":"d","text":"Amazon MQ with a single queue and JMS priority headers","is_correct":false,"explanation":"Amazon MQ supports JMS priority but adds unnecessary complexity and cost for this use case."}]', 'Using separate SQS queues per priority level is the recommended pattern. Consumers poll the high-priority queue first and fall back to lower-priority queues.', 3, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/sqs-best-practices.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs an application on EC2 that stores temporary data on instance store volumes. After an instance stop/start cycle, all temporary data is lost. Why does this happen?', '[{"id":"a","text":"The EBS volume was not attached correctly","is_correct":false,"explanation":"Instance store is not EBS; it is physically attached to the host."},{"id":"b","text":"Instance store data is ephemeral and is lost when the instance stops because the instance moves to new hardware","is_correct":true,"explanation":"Instance store is physically attached to the host. Stopping an instance releases the host, and data is lost."},{"id":"c","text":"The instance store volume was too small","is_correct":false,"explanation":"Volume size does not affect data persistence."},{"id":"d","text":"A security group rule blocked the data","is_correct":false,"explanation":"Security groups control network traffic, not storage."}]', 'Instance store volumes are ephemeral. Data persists only during the lifetime of the associated instance on that specific host. Stop/terminate loses all data.', 1, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/InstanceStorage.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to ensure that their RDS database automatically fails over to a standby in under 60 seconds. Which RDS engine and configuration provides the fastest automatic failover?', '[{"id":"a","text":"RDS MySQL Multi-AZ","is_correct":false,"explanation":"RDS MySQL Multi-AZ failover typically takes 60-120 seconds."},{"id":"b","text":"Amazon Aurora with Multi-AZ replicas","is_correct":true,"explanation":"Aurora failover completes in typically under 30 seconds by promoting an existing replica."},{"id":"c","text":"RDS PostgreSQL with a read replica","is_correct":false,"explanation":"Read replica promotion is manual and does not provide automatic failover."},{"id":"d","text":"RDS Oracle with Data Guard","is_correct":false,"explanation":"Data Guard is an Oracle feature that requires additional configuration and is not as fast as Aurora."}]', 'Aurora maintains replicas that share the same storage volume. Failover simply changes the DNS endpoint to point to the replica, completing in under 30 seconds typically.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Concepts.AuroraHighAvailability.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is migrating to AWS and needs to connect their on-premises data center with consistent, low-latency network performance. The connection must support 10 Gbps throughput. Which service should the architect use?', '[{"id":"a","text":"AWS Site-to-Site VPN","is_correct":false,"explanation":"VPN runs over the public internet and cannot guarantee consistent low latency at 10 Gbps."},{"id":"b","text":"AWS Direct Connect with a 10 Gbps dedicated connection","is_correct":true,"explanation":"Direct Connect provides a dedicated private network connection with consistent performance at up to 100 Gbps."},{"id":"c","text":"AWS Transit Gateway with VPN attachments","is_correct":false,"explanation":"Transit Gateway with VPN still uses public internet and has VPN bandwidth limitations."},{"id":"d","text":"VPC peering with the on-premises network","is_correct":false,"explanation":"VPC peering connects VPCs, not on-premises networks."}]', 'AWS Direct Connect establishes a dedicated network connection from on-premises to AWS, bypassing the public internet for consistent latency and bandwidth up to 100 Gbps.', 2, 'https://docs.aws.amazon.com/directconnect/latest/UserGuide/Welcome.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A company wants to implement defense-in-depth for their VPC. (Select TWO) Which AWS features provide network security at different layers?', '[{"id":"a","text":"Security groups at the instance level (stateful)","is_correct":true,"explanation":"Security groups provide stateful instance-level filtering of inbound and outbound traffic."},{"id":"b","text":"Network ACLs at the subnet level (stateless)","is_correct":true,"explanation":"NACLs provide stateless subnet-level filtering as an additional security layer."},{"id":"c","text":"IAM policies for network control","is_correct":false,"explanation":"IAM controls API access, not network packet filtering."},{"id":"d","text":"S3 bucket policies for VPC traffic","is_correct":false,"explanation":"S3 bucket policies control S3 access, not VPC network security."}]', 'Security groups (stateful, instance-level) and NACLs (stateless, subnet-level) provide defense-in-depth for VPC networking.', 1, 'https://docs.aws.amazon.com/vpc/latest/userguide/VPC_Security.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Lambda functions triggered by API Gateway. They want to reduce cold start latency for Java-based functions. Which Lambda feature should the architect enable?', '[{"id":"a","text":"Provisioned Concurrency","is_correct":false,"explanation":"Provisioned Concurrency eliminates cold starts but is more expensive. SnapStart is the cost-effective alternative for Java."},{"id":"b","text":"Lambda SnapStart for Java","is_correct":true,"explanation":"SnapStart takes a snapshot of the initialized execution environment, reducing Java cold start latency by up to 10x."},{"id":"c","text":"Increase function memory to 10 GB","is_correct":false,"explanation":"More memory gives more CPU but does not significantly reduce JVM initialization time."},{"id":"d","text":"Use Lambda Layers for dependencies","is_correct":false,"explanation":"Layers organize code but do not reduce cold start latency."}]', 'Lambda SnapStart caches a snapshot of the initialized Java execution environment. When invoked, it restores from the snapshot instead of cold-starting the JVM.', 3, 'https://docs.aws.amazon.com/lambda/latest/dg/snapstart.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to host a relational database for a read-heavy analytics workload. The database must support standard SQL and scale read capacity across multiple nodes. Which AWS service is best suited?', '[{"id":"a","text":"Amazon RDS MySQL with a single read replica","is_correct":false,"explanation":"A single read replica provides limited read scaling."},{"id":"b","text":"Amazon Aurora with up to 15 read replicas and the reader endpoint","is_correct":true,"explanation":"Aurora supports up to 15 read replicas with automatic load balancing via the reader endpoint."},{"id":"c","text":"Amazon DynamoDB","is_correct":false,"explanation":"DynamoDB is NoSQL and does not support standard SQL."},{"id":"d","text":"Amazon ElastiCache","is_correct":false,"explanation":"ElastiCache is an in-memory cache, not a relational database."}]', 'Aurora supports up to 15 low-latency read replicas that share the same storage volume. The reader endpoint automatically distributes connections across available replicas.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/Aurora.Replication.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to set up a connection between two VPCs in different AWS accounts. The VPCs have non-overlapping CIDR ranges. They need to minimize costs for occasional data transfer. Which connectivity option is most cost-effective?', '[{"id":"a","text":"AWS Transit Gateway","is_correct":false,"explanation":"Transit Gateway has hourly charges and per-GB data processing fees, which is overkill for two VPCs."},{"id":"b","text":"VPC peering","is_correct":true,"explanation":"VPC peering is free to set up and only charges standard data transfer rates, making it the most cost-effective for connecting two VPCs."},{"id":"c","text":"AWS PrivateLink","is_correct":false,"explanation":"PrivateLink is for service-to-service connectivity, not full VPC-to-VPC networking."},{"id":"d","text":"AWS Site-to-Site VPN between the VPCs","is_correct":false,"explanation":"VPN has hourly charges and is designed for on-premises connectivity, not VPC-to-VPC."}]', 'VPC peering has no setup fee or hourly charge. Data transfer is billed at standard rates, making it the cheapest option for connecting two VPCs.', 2, 'https://docs.aws.amazon.com/vpc/latest/peering/what-is-vpc-peering.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is building a data pipeline where events arrive at variable rates. They need to buffer events and deliver them to S3 in batches. The solution should require minimal operational overhead. Which service should the architect use?', '[{"id":"a","text":"Amazon Kinesis Data Streams with Lambda consumers writing to S3","is_correct":false,"explanation":"This approach requires managing shard scaling and Lambda code for S3 writes."},{"id":"b","text":"Amazon Kinesis Data Firehose (Amazon Data Firehose)","is_correct":true,"explanation":"Firehose automatically buffers, batches, and delivers data to S3 with no servers to manage."},{"id":"c","text":"Amazon SQS with a scheduled Lambda writing to S3","is_correct":false,"explanation":"This requires custom code for batching and S3 delivery."},{"id":"d","text":"Direct PutObject calls to S3 from the producers","is_correct":false,"explanation":"Direct writes create many small files without batching, increasing costs and complicating downstream processing."}]', 'Kinesis Data Firehose (now Amazon Data Firehose) provides fully managed data delivery to S3 with configurable buffering by size or time interval.', 2, 'https://docs.aws.amazon.com/firehose/latest/dev/what-is-this-service.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company stores sensitive configuration values like database passwords and API keys. They need automatic rotation every 30 days and integration with RDS for seamless credential rotation. Which service should the architect use?', '[{"id":"a","text":"AWS Systems Manager Parameter Store with SecureString","is_correct":false,"explanation":"Parameter Store supports encryption but does not provide built-in automatic rotation with RDS integration."},{"id":"b","text":"AWS Secrets Manager with automatic rotation","is_correct":true,"explanation":"Secrets Manager provides built-in automatic rotation with native RDS integration that updates both the secret and the database credentials."},{"id":"c","text":"AWS KMS for storing secrets","is_correct":false,"explanation":"KMS manages encryption keys, not secrets like passwords."},{"id":"d","text":"Environment variables in Lambda","is_correct":false,"explanation":"Environment variables are not rotated automatically and are visible in the Lambda console."}]', 'Secrets Manager provides managed rotation using Lambda functions. For RDS, it includes pre-built rotation templates that update both the secret and database credentials.', 2, 'https://docs.aws.amazon.com/secretsmanager/latest/userguide/rotating-secrets.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Amazon CloudFront to serve their web application. They need to run lightweight authentication logic at the edge before requests reach the origin. The logic must execute in under 5 milliseconds. Which CloudFront feature should they use?', '[{"id":"a","text":"Lambda@Edge","is_correct":false,"explanation":"Lambda@Edge runs at edge locations but has higher cold start latency, not ideal for sub-5ms execution."},{"id":"b","text":"CloudFront Functions","is_correct":true,"explanation":"CloudFront Functions execute in under 1ms at the edge, ideal for lightweight request/response manipulation like auth checks."},{"id":"c","text":"Origin Access Control","is_correct":false,"explanation":"OAC secures the connection to S3 origins but does not run custom authentication logic."},{"id":"d","text":"AWS WAF with custom rules","is_correct":false,"explanation":"WAF provides security rules but cannot run custom authentication logic."}]', 'CloudFront Functions are lightweight JavaScript functions that execute in under 1ms at all CloudFront edge locations, ideal for URL rewrites, header manipulation, and simple auth.', 3, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/cloudfront-functions.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company has a monolithic application using a single RDS instance for both OLTP and reporting queries. The reporting queries are slowing down transaction processing. What should the architect do?', '[{"id":"a","text":"Increase the RDS instance size","is_correct":false,"explanation":"Scaling up addresses symptoms but does not solve the resource contention between OLTP and reporting."},{"id":"b","text":"Create a read replica and direct reporting queries to it","is_correct":true,"explanation":"Read replicas offload reporting queries from the primary instance, eliminating contention with OLTP workloads."},{"id":"c","text":"Add ElastiCache in front of the database","is_correct":false,"explanation":"Caching helps with repeated reads but reporting queries are typically ad-hoc and not cacheable."},{"id":"d","text":"Enable RDS Performance Insights","is_correct":false,"explanation":"Performance Insights helps diagnose issues but does not resolve resource contention."}]', 'RDS read replicas receive asynchronous replication from the primary. Directing reporting queries to replicas eliminates resource contention on the primary OLTP instance.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_ReadRepl.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to detect configuration drift and non-compliant resources across their AWS accounts. They need automated remediation when resources deviate from the desired configuration. Which service should the architect use?', '[{"id":"a","text":"AWS CloudTrail with SNS notifications","is_correct":false,"explanation":"CloudTrail logs API calls but does not evaluate resource configuration compliance."},{"id":"b","text":"AWS Config with managed rules and auto-remediation actions","is_correct":true,"explanation":"Config continuously evaluates resource configurations against rules and can trigger automatic remediation via SSM Automation documents."},{"id":"c","text":"Amazon GuardDuty","is_correct":false,"explanation":"GuardDuty detects security threats, not configuration compliance drift."},{"id":"d","text":"AWS Trusted Advisor","is_correct":false,"explanation":"Trusted Advisor provides best-practice checks but does not support automated remediation."}]', 'AWS Config rules continuously evaluate resource configurations. Auto-remediation triggers SSM Automation documents to automatically fix non-compliant resources.', 3, 'https://docs.aws.amazon.com/config/latest/developerguide/remediation.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Transit Gateway to connect 20 VPCs. They need to ensure that VPCs in the production environment cannot communicate with VPCs in the development environment. How should the architect configure this?', '[{"id":"a","text":"Use separate route tables for production and development VPC attachments","is_correct":true,"explanation":"Transit Gateway route tables control routing between attachments. Separate tables with no cross-routes isolate environments."},{"id":"b","text":"Use security groups on the Transit Gateway","is_correct":false,"explanation":"Transit Gateway does not use security groups."},{"id":"c","text":"Create separate Transit Gateways for each environment","is_correct":false,"explanation":"Separate TGWs work but are unnecessary when route table isolation achieves the same result more cost-effectively."},{"id":"d","text":"Use NACLs on VPC subnets to block cross-environment traffic","is_correct":false,"explanation":"NACLs require managing IP ranges and do not scale well with many VPCs."}]', 'Transit Gateway route tables provide network segmentation. Associating production VPCs with one route table and development with another prevents inter-environment routing.', 4, 'https://docs.aws.amazon.com/vpc/latest/tgw/tgw-route-tables.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company runs a containerized application on ECS Fargate. They need to store sensitive environment variables like database credentials securely. Which approach should the architect use?', '[{"id":"a","text":"Hard-code credentials in the Docker image","is_correct":false,"explanation":"Hard-coding credentials in images is a critical security risk."},{"id":"b","text":"Reference AWS Secrets Manager secrets in the ECS task definition","is_correct":true,"explanation":"ECS task definitions can reference Secrets Manager secrets, which are injected as environment variables at runtime."},{"id":"c","text":"Store credentials in an S3 bucket and download at startup","is_correct":false,"explanation":"S3 storage of credentials adds complexity and potential security exposure."},{"id":"d","text":"Pass credentials via ECS service environment variables in plaintext","is_correct":false,"explanation":"Plaintext environment variables are visible in the ECS console and API responses."}]', 'ECS integrates with Secrets Manager to inject secrets as environment variables. The task execution role provides the necessary permissions to retrieve the secrets.', 2, 'https://docs.aws.amazon.com/AmazonECS/latest/developerguide/specifying-sensitive-data-secrets.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to process streaming data and join it with reference data stored in S3. The processing must happen in real time with SQL-like queries. Which service should the architect use?', '[{"id":"a","text":"Amazon Athena","is_correct":false,"explanation":"Athena is for batch queries on S3 data, not real-time stream processing."},{"id":"b","text":"Amazon Managed Service for Apache Flink (formerly Kinesis Data Analytics)","is_correct":true,"explanation":"Managed Flink processes streaming data in real time using SQL or Apache Flink applications and can join with reference data in S3."},{"id":"c","text":"Amazon EMR with Spark batch jobs","is_correct":false,"explanation":"EMR Spark batch jobs are not real-time stream processing."},{"id":"d","text":"AWS Glue ETL jobs","is_correct":false,"explanation":"Glue ETL is for batch processing, not real-time streaming."}]', 'Amazon Managed Service for Apache Flink provides real-time stream processing with SQL support and the ability to enrich streaming data with reference data from S3.', 4, 'https://docs.aws.amazon.com/managed-flink/latest/java/what-is.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses Amazon S3 and needs to be alerted whenever a bucket''s public access settings are changed. Which service can detect this change and send an alert?', '[{"id":"a","text":"S3 Event Notifications","is_correct":false,"explanation":"S3 Event Notifications trigger on object-level events, not bucket configuration changes."},{"id":"b","text":"AWS Config with the s3-bucket-public-read-prohibited rule","is_correct":true,"explanation":"AWS Config monitors bucket configuration changes and the managed rule detects when public access is enabled."},{"id":"c","text":"Amazon Macie","is_correct":false,"explanation":"Macie discovers sensitive data in S3 but does not monitor bucket policy changes."},{"id":"d","text":"S3 Storage Lens","is_correct":false,"explanation":"Storage Lens provides storage metrics and analytics, not configuration change detection."}]', 'AWS Config continuously monitors S3 bucket configurations. The s3-bucket-public-read-prohibited managed rule evaluates compliance and can trigger SNS alerts on violations.', 3, 'https://docs.aws.amazon.com/config/latest/developerguide/s3-bucket-public-read-prohibited.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs a managed Apache Kafka service for their event streaming platform. They want to minimize operational overhead for cluster management. Which service should the architect use?', '[{"id":"a","text":"Self-managed Apache Kafka on EC2","is_correct":false,"explanation":"Self-managed Kafka requires significant operational overhead for cluster management, patching, and scaling."},{"id":"b","text":"Amazon MSK (Managed Streaming for Apache Kafka)","is_correct":true,"explanation":"MSK provides fully managed Apache Kafka clusters with automated provisioning, patching, and monitoring."},{"id":"c","text":"Amazon Kinesis Data Streams","is_correct":false,"explanation":"Kinesis is a similar streaming service but is not Apache Kafka compatible."},{"id":"d","text":"Amazon MQ","is_correct":false,"explanation":"Amazon MQ provides managed ActiveMQ and RabbitMQ, not Apache Kafka."}]', 'Amazon MSK manages Kafka broker infrastructure, including provisioning, configuration, patching, and monitoring, while maintaining full Kafka API compatibility.', 2, 'https://docs.aws.amazon.com/msk/latest/developerguide/what-is-msk.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to deploy a pilot light DR architecture for their web application. Which components should be kept running in the DR region at all times?', '[{"id":"a","text":"Full-size web and application servers","is_correct":false,"explanation":"Full-size servers in DR is a warm standby or active-active pattern, not pilot light."},{"id":"b","text":"A continuously replicated database with minimal infrastructure for quick scaling","is_correct":true,"explanation":"Pilot light keeps only the core data replication running. Compute resources are provisioned and scaled up only during failover."},{"id":"c","text":"Nothing — all resources are provisioned from backups during failover","is_correct":false,"explanation":"Provisioning from backups is the backup-and-restore pattern, which has a higher RTO than pilot light."},{"id":"d","text":"Load balancers and Auto Scaling groups at full capacity","is_correct":false,"explanation":"Running full capacity in DR is multi-site active-active, the most expensive DR option."}]', 'Pilot light maintains only the critical core components (database replication) in the DR region. Other resources are provisioned rapidly during a disaster event.', 3, 'https://docs.aws.amazon.com/whitepapers/latest/disaster-recovery-workloads-on-aws/disaster-recovery-options-in-the-cloud.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company operates a multi-account AWS environment. They need to share Amazon Machine Images (AMIs) with specific accounts while preventing public access. How should the architect configure this?', '[{"id":"a","text":"Make the AMI public","is_correct":false,"explanation":"Public AMIs are accessible by anyone, violating the private sharing requirement."},{"id":"b","text":"Modify the AMI launch permissions to add specific account IDs","is_correct":true,"explanation":"AMI launch permissions allow sharing with specific AWS account IDs while keeping the AMI private."},{"id":"c","text":"Copy the AMI to each target account","is_correct":false,"explanation":"Copying creates duplicates and increases storage costs unnecessarily."},{"id":"d","text":"Use AWS Organizations to share all AMIs automatically","is_correct":false,"explanation":"Organizations does not automatically share AMIs across accounts."}]', 'AMI launch permissions allow granular sharing by adding specific account IDs. The AMI remains private and is only visible to the specified accounts.', 2, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/sharing-amis.html', 'SAA-C03-1.2', true, true)
,
-- Final 8 RESILIENT to reach 300
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to use Amazon Aurora for their database but needs the ability to rewind the database to a point up to 72 hours in the past without restoring from a backup. Which feature should they enable?', '[{"id":"a","text":"Aurora point-in-time recovery","is_correct":false,"explanation":"PITR creates a new database instance; it does not rewind the existing one."},{"id":"b","text":"Aurora Backtrack","is_correct":true,"explanation":"Backtrack rewinds the Aurora cluster to a specific point in time without creating a new instance, within the configured backtrack window."},{"id":"c","text":"Aurora snapshot restore","is_correct":false,"explanation":"Snapshot restore creates a new instance, it does not rewind the existing cluster."},{"id":"d","text":"Aurora fast cloning","is_correct":false,"explanation":"Cloning creates a copy, it does not rewind the original database."}]', 'Aurora Backtrack rewinds the database to a specified time within the backtrack window (up to 72 hours) in seconds, without needing to restore from a backup.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/AuroraMySQL.Managing.Backtrack.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company is evaluating whether to use EBS Multi-Attach for their clustered application. Which EBS volume type supports Multi-Attach?', '[{"id":"a","text":"gp3 (General Purpose SSD)","is_correct":false,"explanation":"gp3 does not support Multi-Attach."},{"id":"b","text":"io2 Block Express (Provisioned IOPS SSD)","is_correct":true,"explanation":"Only io1 and io2 volume types support Multi-Attach for simultaneous attachment to multiple instances in the same AZ."},{"id":"c","text":"st1 (Throughput Optimized HDD)","is_correct":false,"explanation":"HDD volume types do not support Multi-Attach."},{"id":"d","text":"sc1 (Cold HDD)","is_correct":false,"explanation":"sc1 does not support Multi-Attach."}]', 'EBS Multi-Attach is only supported on io1 and io2 volume types and allows up to 16 instances in the same AZ to attach the volume simultaneously.', 3, 'https://docs.aws.amazon.com/ebs/latest/userguide/ebs-volumes-multi.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company uses AWS Storage Gateway in file gateway mode. They want to ensure that frequently accessed files are cached locally while all data is stored durably in S3. What does file gateway provide?', '[{"id":"a","text":"Block storage presented as iSCSI volumes","is_correct":false,"explanation":"iSCSI volumes are provided by Volume Gateway, not File Gateway."},{"id":"b","text":"A local NFS/SMB file share backed by S3 with local caching of frequently accessed data","is_correct":true,"explanation":"File Gateway presents an NFS/SMB interface, caches frequently accessed data locally, and stores all data in S3."},{"id":"c","text":"Virtual tape library for backup software","is_correct":false,"explanation":"Virtual tape libraries are provided by Tape Gateway."},{"id":"d","text":"Direct S3 API access from on-premises","is_correct":false,"explanation":"File Gateway provides file protocol access (NFS/SMB), not direct S3 API."}]', 'File Gateway provides a seamless bridge between on-premises file systems and S3, with local caching for low-latency access to frequently used files.', 2, 'https://docs.aws.amazon.com/filegateway/latest/files3/what-is-file-s3.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company wants to use a serverless database that automatically scales capacity based on demand and supports standard SQL. The workload is unpredictable with occasional heavy bursts. Which option fits best?', '[{"id":"a","text":"Amazon RDS with Auto Scaling","is_correct":false,"explanation":"RDS does not natively auto-scale compute; you must manually change instance sizes."},{"id":"b","text":"Amazon Aurora Serverless v2","is_correct":true,"explanation":"Aurora Serverless v2 automatically scales compute in fine-grained ACU increments based on demand while supporting standard SQL."},{"id":"c","text":"Amazon DynamoDB with on-demand mode","is_correct":false,"explanation":"DynamoDB scales automatically but is NoSQL, not SQL."},{"id":"d","text":"Amazon Redshift Serverless","is_correct":false,"explanation":"Redshift Serverless is for analytical workloads, not transactional SQL."}]', 'Aurora Serverless v2 adjusts capacity in 0.5 ACU increments within seconds, supporting standard MySQL/PostgreSQL SQL with truly on-demand scaling.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/aurora-serverless-v2.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to ensure that their EC2 instances are launched only from approved, hardened AMIs. How should the architect enforce this?', '[{"id":"a","text":"Use a naming convention for AMIs","is_correct":false,"explanation":"Naming conventions are advisory and cannot be enforced programmatically."},{"id":"b","text":"Create an SCP or IAM policy with a condition key restricting ec2:RunInstances to specific AMI IDs","is_correct":true,"explanation":"IAM/SCP condition keys can restrict instance launches to only approved AMI IDs."},{"id":"c","text":"Use AWS Config after launch to detect non-compliant instances","is_correct":false,"explanation":"Config detects after the fact but does not prevent non-compliant launches."},{"id":"d","text":"Restrict IAM users from accessing the AMI catalog","is_correct":false,"explanation":"Restricting catalog access does not prevent using an AMI ID directly."}]', 'IAM policies with conditions on the ec2:ImageId key preventatively block instance launches from unapproved AMIs at the API level.', 4, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/iam-policies-ec2-console.html', 'SAA-C03-1.2', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs a fully managed ETL service to discover, prepare, and combine data for analytics from multiple sources. Which service should the architect use?', '[{"id":"a","text":"Amazon EMR","is_correct":false,"explanation":"EMR provides Hadoop/Spark clusters but requires more management than a serverless ETL service."},{"id":"b","text":"AWS Glue","is_correct":true,"explanation":"Glue is a fully managed, serverless ETL service with crawlers for schema discovery and a Data Catalog for metadata management."},{"id":"c","text":"AWS Data Pipeline","is_correct":false,"explanation":"Data Pipeline is an older service with more operational overhead than Glue."},{"id":"d","text":"Amazon Kinesis Data Firehose","is_correct":false,"explanation":"Firehose is for real-time data delivery, not ETL transformation and cataloging."}]', 'AWS Glue provides serverless ETL with automatic schema discovery (crawlers), a centralized Data Catalog, and support for Spark-based transformations.', 2, 'https://docs.aws.amazon.com/glue/latest/dg/what-is-glue.html', 'SAA-C03-1.3', true, true),
('b1000000-0000-4000-8000-000000000001', 'multi_select', 'A company is designing a solution to protect their web application from DDoS attacks. (Select TWO) Which AWS services provide DDoS protection at different layers?', '[{"id":"a","text":"AWS Shield Standard for infrastructure layer (L3/L4) protection","is_correct":true,"explanation":"Shield Standard is automatically included and protects against common L3/L4 DDoS attacks."},{"id":"b","text":"AWS WAF for application layer (L7) protection","is_correct":true,"explanation":"WAF inspects HTTP/HTTPS traffic and can block L7 DDoS patterns like HTTP floods."},{"id":"c","text":"Amazon Inspector for DDoS detection","is_correct":false,"explanation":"Inspector scans for software vulnerabilities, not DDoS attacks."},{"id":"d","text":"AWS Trusted Advisor for DDoS monitoring","is_correct":false,"explanation":"Trusted Advisor provides best-practice recommendations, not DDoS protection."}]', 'Shield Standard provides automatic L3/L4 protection at no extra cost. WAF provides L7 protection with customizable rules. Together they provide comprehensive DDoS defense.', 2, 'https://docs.aws.amazon.com/waf/latest/developerguide/ddos-overview.html', 'SAA-C03-1.1', true, true),
('b1000000-0000-4000-8000-000000000001', 'single_choice', 'A company needs to run a time-sensitive batch job that must complete within 2 hours. They want to use Spot Instances but need a fallback if Spot capacity is unavailable. Which strategy should the architect use?', '[{"id":"a","text":"Request only Spot Instances and retry if interrupted","is_correct":false,"explanation":"If Spot capacity is unavailable, the job may never start or complete on time."},{"id":"b","text":"Use a mixed instances policy in an Auto Scaling group with both Spot and On-Demand instances","is_correct":true,"explanation":"Mixed instances policy prioritizes Spot but falls back to On-Demand, ensuring the job runs regardless of Spot availability."},{"id":"c","text":"Use Reserved Instances as a fallback","is_correct":false,"explanation":"Reserved Instances require long-term commitment and cannot be used as on-demand fallback."},{"id":"d","text":"Wait for Spot capacity to become available","is_correct":false,"explanation":"Waiting is not acceptable for time-sensitive workloads."}]', 'Mixed instances policies in Auto Scaling groups allow specifying a base of On-Demand instances with additional Spot capacity, ensuring availability for time-critical jobs.', 3, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/ec2-auto-scaling-mixed-instances-groups.html', 'SAA-C03-1.3', true, true),
