-- PERFORMANCE domain — 20 questions
-- ============================================================
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company runs a high-traffic API that receives 50,000 requests per second. They need to cache API responses at the edge to reduce origin load. Which service provides edge caching for API responses?', '[{"id":"a","text":"Amazon ElastiCache","is_correct":false,"explanation":"ElastiCache is a VPC-based cache, not an edge cache."},{"id":"b","text":"Amazon CloudFront with API Gateway as origin and caching enabled","is_correct":true,"explanation":"CloudFront caches API responses at edge locations worldwide, reducing latency and origin load."},{"id":"c","text":"Amazon Route 53","is_correct":false,"explanation":"Route 53 is a DNS service and does not cache API responses."},{"id":"d","text":"AWS Global Accelerator","is_correct":false,"explanation":"Global Accelerator improves connection performance but does not cache responses."}]', 'CloudFront can cache API Gateway responses at 400+ edge locations globally, dramatically reducing latency and origin request volume.', 3, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/DownloadDistS3AndCustomOrigins.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company needs to choose between Amazon EBS gp3 and io2 for their database workload. The database requires 64,000 IOPS with consistent sub-millisecond latency. Which volume type should they use?', '[{"id":"a","text":"gp3 with maximum IOPS","is_correct":false,"explanation":"gp3 supports a maximum of 16,000 IOPS, which is insufficient for 64,000 IOPS."},{"id":"b","text":"io2 Block Express","is_correct":true,"explanation":"io2 Block Express supports up to 256,000 IOPS with sub-millisecond latency for demanding database workloads."},{"id":"c","text":"gp2 with a large volume size","is_correct":false,"explanation":"gp2 maxes out at 16,000 IOPS regardless of volume size."},{"id":"d","text":"st1 with high throughput","is_correct":false,"explanation":"st1 is an HDD type optimized for throughput, not IOPS."}]', 'io2 Block Express volumes deliver up to 256,000 IOPS with sub-millisecond latency and 99.999% durability, designed for the most demanding database workloads.', 3, 'https://docs.aws.amazon.com/ebs/latest/userguide/provisioned-iops.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company uses Amazon DynamoDB for their application. They need to run complex aggregation queries across multiple tables efficiently. Which approach should the architect recommend?', '[{"id":"a","text":"Use DynamoDB Scan operations with filter expressions","is_correct":false,"explanation":"Scan reads the entire table and is inefficient for complex aggregations."},{"id":"b","text":"Export DynamoDB data to S3 and use Amazon Athena for SQL aggregations","is_correct":true,"explanation":"Exporting to S3 and querying with Athena provides efficient SQL-based aggregations without impacting DynamoDB performance."},{"id":"c","text":"Create multiple Global Secondary Indexes","is_correct":false,"explanation":"GSIs support alternative access patterns but do not enable complex cross-table aggregations."},{"id":"d","text":"Increase read capacity units","is_correct":false,"explanation":"More capacity does not make complex aggregation queries possible in DynamoDB."}]', 'DynamoDB zero-ETL integration with S3 or DynamoDB export combined with Athena enables running complex SQL queries without consuming DynamoDB read capacity.', 3, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/S3DataExport.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company runs an application that makes thousands of small reads per second from S3. They need to maximize read throughput. Which S3 feature should the architect use?', '[{"id":"a","text":"S3 Transfer Acceleration","is_correct":false,"explanation":"Transfer Acceleration speeds up uploads over long distances, not high-frequency reads."},{"id":"b","text":"S3 Express One Zone storage class","is_correct":true,"explanation":"S3 Express One Zone provides single-digit millisecond read latency and up to 10x faster performance for frequently accessed data."},{"id":"c","text":"S3 Intelligent-Tiering","is_correct":false,"explanation":"Intelligent-Tiering optimizes cost, not read throughput performance."},{"id":"d","text":"S3 Batch Operations","is_correct":false,"explanation":"Batch Operations perform bulk operations, not high-frequency individual reads."}]', 'S3 Express One Zone uses a directory-bucket architecture optimized for single-digit millisecond latency, ideal for high-frequency access patterns.', 4, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/s3-express-one-zone.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company uses an ALB with target groups. During deployments, new instances need time to warm up before receiving full traffic. Which ALB feature helps prevent overloading new instances?', '[{"id":"a","text":"Connection draining","is_correct":false,"explanation":"Connection draining handles deregistration, not new instance warm-up."},{"id":"b","text":"Slow start mode on the target group","is_correct":true,"explanation":"Slow start gradually increases the number of requests sent to a newly registered target over a configurable period."},{"id":"c","text":"Sticky sessions","is_correct":false,"explanation":"Sticky sessions bind users to targets but do not control traffic ramp-up for new instances."},{"id":"d","text":"Cross-zone load balancing","is_correct":false,"explanation":"Cross-zone balancing distributes evenly across AZs, not gradually to new targets."}]', 'ALB slow start mode linearly increases the share of requests to a new target from 0 to its full share over a configurable duration (30-900 seconds).', 3, 'https://docs.aws.amazon.com/elasticloadbalancing/latest/application/load-balancer-target-groups.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company needs to deliver large media files (10 GB+) to users worldwide with high transfer speeds. Which CloudFront feature optimizes delivery of large files?', '[{"id":"a","text":"CloudFront signed URLs","is_correct":false,"explanation":"Signed URLs control access but do not optimize large file delivery performance."},{"id":"b","text":"CloudFront with range-based requests and origin shield","is_correct":true,"explanation":"Range requests allow parallel downloads of file segments, and Origin Shield reduces origin load by providing a centralized cache layer."},{"id":"c","text":"CloudFront with Lambda@Edge","is_correct":false,"explanation":"Lambda@Edge runs custom code but does not directly optimize large file transfer speeds."},{"id":"d","text":"S3 Transfer Acceleration","is_correct":false,"explanation":"Transfer Acceleration is for uploads to S3, not for downloads to end users."}]', 'CloudFront automatically uses range requests to fetch large files in parallel chunks. Origin Shield adds an extra caching layer that reduces origin fetches.', 3, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/origin-shield.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company needs to run ad-hoc SQL queries against petabytes of data stored in S3 without provisioning any infrastructure. Which service should the architect recommend?', '[{"id":"a","text":"Amazon Redshift","is_correct":false,"explanation":"Redshift requires provisioning clusters (unless using Serverless, but it is designed for regular warehousing)."},{"id":"b","text":"Amazon Athena","is_correct":true,"explanation":"Athena is serverless and queries data directly in S3 using standard SQL with no infrastructure to manage."},{"id":"c","text":"Amazon EMR with Hive","is_correct":false,"explanation":"EMR requires provisioning and managing Hadoop clusters."},{"id":"d","text":"Amazon RDS","is_correct":false,"explanation":"RDS requires provisioning a database instance and importing data."}]', 'Amazon Athena is serverless, charges per query based on data scanned, and queries data in-place in S3 using standard SQL via the Presto engine.', 1, 'https://docs.aws.amazon.com/athena/latest/ug/what-is.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company runs a read-heavy application using RDS PostgreSQL. They want to add a caching layer that supports complex data structures like sorted sets and geospatial indexes. Which caching service should the architect use?', '[{"id":"a","text":"Amazon ElastiCache for Memcached","is_correct":false,"explanation":"Memcached supports simple key-value caching only, not complex data structures."},{"id":"b","text":"Amazon ElastiCache for Redis","is_correct":true,"explanation":"Redis supports sorted sets, geospatial indexes, streams, and other complex data structures in addition to simple caching."},{"id":"c","text":"Amazon DynamoDB as a cache","is_correct":false,"explanation":"DynamoDB is a database, not an in-memory cache with sub-millisecond latency."},{"id":"d","text":"Amazon CloudFront","is_correct":false,"explanation":"CloudFront caches HTTP responses at the edge, not application data structures."}]', 'ElastiCache for Redis provides in-memory data structures including strings, hashes, lists, sorted sets, and geospatial indexes with sub-millisecond latency.', 2, 'https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/WhatIs.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company uses EC2 instances for compute-intensive scientific simulations. They need the highest possible clock speed per core. Which EC2 instance family is optimized for this?', '[{"id":"a","text":"M6i (General Purpose)","is_correct":false,"explanation":"M-family instances are balanced, not optimized for maximum clock speed."},{"id":"b","text":"Hpc7g or C7i with high-frequency processors","is_correct":true,"explanation":"Compute-optimized C-family and HPC instances offer the highest sustained clock speeds for compute-intensive workloads."},{"id":"c","text":"R6i (Memory Optimized)","is_correct":false,"explanation":"R-family instances are optimized for memory capacity, not CPU clock speed."},{"id":"d","text":"T3 (Burstable)","is_correct":false,"explanation":"Burstable instances provide variable CPU credits, not sustained high-frequency compute."}]', 'Compute-optimized (C-family) and HPC instances use high-frequency Intel or Graviton processors optimized for sustained computational performance.', 2, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/compute-optimized-instances.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company has an Athena workload that scans terabytes of data but only needs a few columns from each row. How should the architect optimize query performance and cost?', '[{"id":"a","text":"Use CSV format for all data files","is_correct":false,"explanation":"CSV is a row-based format that requires scanning entire rows even when only a few columns are needed."},{"id":"b","text":"Convert data to Apache Parquet format with column-based storage","is_correct":true,"explanation":"Parquet is columnar, allowing Athena to read only the needed columns, dramatically reducing data scanned and cost."},{"id":"c","text":"Compress data with gzip","is_correct":false,"explanation":"Compression reduces storage but gzip-compressed CSV still requires reading all columns."},{"id":"d","text":"Use larger file sizes","is_correct":false,"explanation":"Larger files help reduce S3 request overhead but do not address columnar read optimization."}]', 'Parquet columnar format allows Athena to skip unneeded columns entirely. Combined with partitioning, this can reduce data scanned by 90%+ and proportionally reduce costs.', 3, 'https://docs.aws.amazon.com/athena/latest/ug/columnar-storage.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company uses Amazon Redshift for their data warehouse. Queries that join large tables are slow. Which Redshift feature should the architect use to optimize join performance?', '[{"id":"a","text":"Concurrency Scaling","is_correct":false,"explanation":"Concurrency Scaling adds clusters for concurrent queries, not join optimization."},{"id":"b","text":"Choose appropriate distribution keys so that joined tables are co-located on the same nodes","is_correct":true,"explanation":"KEY distribution on the join column co-locates related rows on the same node, eliminating data shuffling during joins."},{"id":"c","text":"Enable short query acceleration","is_correct":false,"explanation":"Short query acceleration prioritizes quick queries, not large table joins."},{"id":"d","text":"Increase the number of nodes","is_correct":false,"explanation":"More nodes may help throughput but poor distribution still causes data shuffling."}]', 'Redshift distribution keys determine how data is distributed across nodes. Using KEY distribution on join columns co-locates data, eliminating costly network shuffles.', 4, 'https://docs.aws.amazon.com/redshift/latest/dg/c_best-practices-best-dist-key.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company needs to process millions of small images using Lambda. Each invocation processes one image and takes 3 seconds. They need to maximize throughput. What should the architect configure?', '[{"id":"a","text":"Increase Lambda timeout to 15 minutes","is_correct":false,"explanation":"Increasing timeout does not increase throughput; each invocation still processes one image."},{"id":"b","text":"Increase Lambda reserved concurrency and use SQS as an event source with a high batch size","is_correct":true,"explanation":"Higher concurrency allows more parallel executions, and SQS ensures reliable delivery with backpressure handling."},{"id":"c","text":"Use Lambda Layers for the image library","is_correct":false,"explanation":"Layers organize dependencies but do not increase processing throughput."},{"id":"d","text":"Use provisioned concurrency","is_correct":false,"explanation":"Provisioned concurrency reduces cold starts but does not increase the maximum concurrent executions."}]', 'Lambda scales by running many concurrent executions. SQS automatically triggers Lambda with configurable concurrency, and reserved concurrency guarantees capacity.', 3, 'https://docs.aws.amazon.com/lambda/latest/dg/with-sqs.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company has a global application with users in Asia, Europe, and North America. They use a single RDS instance in us-east-1. Users in Asia experience high latency. What should the architect do to reduce read latency for Asian users?', '[{"id":"a","text":"Move the RDS instance to an Asian region","is_correct":false,"explanation":"Moving the instance helps Asian users but increases latency for other regions."},{"id":"b","text":"Create a cross-region read replica in an Asian region","is_correct":true,"explanation":"Cross-region read replicas serve read traffic locally, reducing latency for Asian users while keeping the primary in us-east-1."},{"id":"c","text":"Use CloudFront to cache database queries","is_correct":false,"explanation":"CloudFront caches HTTP responses, not database query results directly."},{"id":"d","text":"Increase the RDS instance size","is_correct":false,"explanation":"A larger instance does not reduce network latency caused by geographic distance."}]', 'RDS cross-region read replicas serve read queries from the local region, reducing latency from hundreds of milliseconds to single-digit milliseconds for nearby users.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_ReadRepl.XRgn.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'multi_select', 'A company wants to optimize their EC2-based application for network performance. (Select TWO) Which features should the architect enable for maximum network throughput between instances?', '[{"id":"a","text":"Enhanced Networking with Elastic Network Adapter (ENA)","is_correct":true,"explanation":"ENA provides up to 100 Gbps networking with higher PPS and lower latency than standard networking."},{"id":"b","text":"Placement group (cluster) for instances that communicate frequently","is_correct":true,"explanation":"Cluster placement groups provide the lowest latency and highest throughput between instances."},{"id":"c","text":"Elastic IP addresses on all instances","is_correct":false,"explanation":"Elastic IPs provide static public addresses but do not improve network performance."},{"id":"d","text":"Multiple ENIs per instance","is_correct":false,"explanation":"Multiple ENIs provide network segmentation but do not inherently increase throughput between instances."}]', 'Enhanced Networking (ENA) provides high-bandwidth, low-latency networking. Cluster placement groups co-locate instances for optimal inter-instance communication.', 3, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/enhanced-networking.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company needs to optimize their DynamoDB table for a workload where 80% of requests access 20% of items. Which feature provides the best read performance improvement?', '[{"id":"a","text":"DynamoDB on-demand capacity","is_correct":false,"explanation":"On-demand mode handles scaling but does not improve read latency for hot items."},{"id":"b","text":"DynamoDB Accelerator (DAX)","is_correct":true,"explanation":"DAX caches frequently accessed items in memory, providing microsecond read latency for the hot 20% of items."},{"id":"c","text":"Global Secondary Index","is_correct":false,"explanation":"GSIs provide alternative query patterns but do not cache hot items."},{"id":"d","text":"DynamoDB Streams","is_correct":false,"explanation":"Streams capture changes for downstream processing, not read performance."}]', 'DAX maintains an in-memory cache that automatically handles the hot key problem, serving repeated reads in microseconds instead of single-digit milliseconds.', 2, 'https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/DAX.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company uses Kinesis Data Streams and needs to support multiple consumers reading the same stream independently without affecting each other''s throughput. Which feature should the architect enable?', '[{"id":"a","text":"Increase the number of shards","is_correct":false,"explanation":"More shards increase total capacity but consumers still share the per-shard read throughput."},{"id":"b","text":"Enhanced fan-out with dedicated throughput per consumer","is_correct":true,"explanation":"Enhanced fan-out provides each consumer with a dedicated 2 MB/s per shard read throughput via HTTP/2 push."},{"id":"c","text":"Kinesis Client Library with multiple applications","is_correct":false,"explanation":"KCL applications share the shard read throughput without enhanced fan-out."},{"id":"d","text":"Increase the data retention period","is_correct":false,"explanation":"Retention period affects how long data is kept, not consumer throughput."}]', 'Enhanced fan-out uses HTTP/2 push to deliver records to each consumer independently with dedicated 2 MB/s per shard, eliminating read contention between consumers.', 4, 'https://docs.aws.amazon.com/streams/latest/dev/enhanced-consumers.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company wants to enable their EC2-based application to access S3 at the highest possible throughput for large file transfers. The instances are in a VPC. What network configuration maximizes S3 transfer speed?', '[{"id":"a","text":"Use a NAT gateway for S3 access","is_correct":false,"explanation":"NAT gateway adds a hop and has per-GB processing charges, limiting throughput."},{"id":"b","text":"Use a VPC gateway endpoint for S3 combined with S3 multipart upload","is_correct":true,"explanation":"Gateway endpoints provide direct, high-throughput connectivity to S3 through the AWS network, and multipart upload parallelizes large transfers."},{"id":"c","text":"Use an internet gateway with public subnets","is_correct":false,"explanation":"Internet gateway routes through the public internet, which is slower and less secure than a gateway endpoint."},{"id":"d","text":"Use AWS PrivateLink for S3","is_correct":false,"explanation":"PrivateLink interface endpoints have per-hour and per-GB charges, and gateway endpoints are sufficient for S3."}]', 'VPC gateway endpoints for S3 route traffic through the AWS backbone at no additional charge. Combined with multipart upload, this maximizes transfer throughput.', 2, 'https://docs.aws.amazon.com/vpc/latest/privatelink/vpc-endpoints-s3.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company runs a web application that makes many small database queries. They want to reduce the overhead of establishing new database connections for each query. What pattern should the architect implement?', '[{"id":"a","text":"Open and close a new connection for each query","is_correct":false,"explanation":"Creating connections for each query adds significant overhead in terms of latency and resource usage."},{"id":"b","text":"Use connection pooling with Amazon RDS Proxy","is_correct":true,"explanation":"RDS Proxy maintains a pool of warm connections that are reused across requests, eliminating connection establishment overhead."},{"id":"c","text":"Increase the database instance size","is_correct":false,"explanation":"A larger instance handles more connections but does not reduce per-connection overhead."},{"id":"d","text":"Use DynamoDB instead of RDS","is_correct":false,"explanation":"Switching databases is a major change and may not be suitable for relational data."}]', 'RDS Proxy pools database connections and multiplexes application connections over fewer database connections, reducing overhead and improving application responsiveness.', 2, 'https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/rds-proxy.html', 'SAA-C03-2.1', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company uses API Gateway REST API with Lambda integration. API responses are mostly the same for a given path and query parameters. Response times are 500ms. How can the architect reduce response times to under 50ms for repeated requests?', '[{"id":"a","text":"Enable Lambda provisioned concurrency","is_correct":false,"explanation":"Provisioned concurrency reduces cold starts but Lambda execution time remains the same."},{"id":"b","text":"Enable API Gateway caching on the stage","is_correct":true,"explanation":"API Gateway caching stores responses for matching requests, returning cached results in under 50ms without invoking Lambda."},{"id":"c","text":"Use Lambda@Edge instead","is_correct":false,"explanation":"Lambda@Edge still requires execution for each request."},{"id":"d","text":"Increase Lambda memory to 10 GB","is_correct":false,"explanation":"More memory speeds up execution but cannot achieve consistent sub-50ms without caching."}]', 'API Gateway caching stores backend responses for a configurable TTL. Subsequent identical requests return the cached response without invoking the backend integration.', 2, 'https://docs.aws.amazon.com/apigateway/latest/developerguide/api-gateway-caching.html', 'SAA-C03-2.2', true, true),
('b1000000-0000-4000-8000-000000000002', 'single_choice', 'A company runs an Auto Scaling group behind an ALB. During sudden traffic spikes, new instances take 5 minutes to warm up and pass health checks. Users experience errors during this period. What should the architect implement?', '[{"id":"a","text":"Increase the health check interval to 10 minutes","is_correct":false,"explanation":"Longer health check intervals delay detection of unhealthy instances, not warm-up handling."},{"id":"b","text":"Configure a warm pool with pre-initialized instances in the Auto Scaling group","is_correct":true,"explanation":"Warm pools keep pre-initialized instances in a stopped or running state, ready to serve traffic in seconds instead of minutes."},{"id":"c","text":"Use larger instance types that boot faster","is_correct":false,"explanation":"Instance type does not determine application warm-up time."},{"id":"d","text":"Increase the desired capacity permanently","is_correct":false,"explanation":"Over-provisioning wastes resources during normal traffic periods."}]', 'Auto Scaling warm pools maintain pre-initialized instances that can be brought into service much faster than launching and configuring new instances from scratch.', 3, 'https://docs.aws.amazon.com/autoscaling/ec2/userguide/ec2-auto-scaling-warm-pools.html', 'SAA-C03-2.1', true, true),
-- ============================================================
-- SECURITY domain — 20 questions
-- ============================================================
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to allow a mobile application to authenticate users and provide temporary AWS credentials for accessing S3. Users should be able to sign in with Google or Facebook. Which service should the architect use?', '[{"id":"a","text":"IAM users with long-term access keys","is_correct":false,"explanation":"Creating IAM users for mobile app users is an anti-pattern and does not support social identity providers."},{"id":"b","text":"Amazon Cognito with User Pools and Identity Pools","is_correct":true,"explanation":"Cognito User Pools handle authentication including social IdP federation, and Identity Pools provide temporary AWS credentials."},{"id":"c","text":"AWS IAM Identity Center","is_correct":false,"explanation":"IAM Identity Center is for workforce SSO, not mobile app user authentication."},{"id":"d","text":"AWS STS AssumeRole directly from the mobile app","is_correct":false,"explanation":"Direct STS calls require existing AWS credentials, which mobile apps should not have."}]', 'Cognito User Pools provide managed authentication with social IdP support. Identity Pools exchange Cognito tokens for temporary AWS credentials scoped to an IAM role.', 2, 'https://docs.aws.amazon.com/cognito/latest/developerguide/what-is-amazon-cognito.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to implement envelope encryption for application data. They want AWS to manage the master key but encrypt data locally. Which KMS approach should the architect use?', '[{"id":"a","text":"Use KMS Encrypt API to encrypt all data directly","is_correct":false,"explanation":"Direct encryption with KMS is limited to 4 KB of data and adds API call overhead for each operation."},{"id":"b","text":"Use KMS GenerateDataKey to get a data key, encrypt locally with the plaintext key, store the encrypted key alongside the ciphertext","is_correct":true,"explanation":"Envelope encryption uses a data key for local encryption and wraps the data key with the KMS CMK for secure storage."},{"id":"c","text":"Store the KMS key material locally","is_correct":false,"explanation":"KMS key material cannot be exported and should never leave the HSM."},{"id":"d","text":"Use S3 SSE-KMS for all application data","is_correct":false,"explanation":"SSE-KMS only works for S3 objects, not arbitrary application data."}]', 'Envelope encryption generates a unique data key per encryption operation. The plaintext key encrypts the data locally, and KMS encrypts the data key for safe storage.', 4, 'https://docs.aws.amazon.com/kms/latest/developerguide/concepts.html#enveloping', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants to restrict all IAM users in a child account from creating resources outside of eu-west-1. They use AWS Organizations. What should the architect configure?', '[{"id":"a","text":"IAM policies on each user denying actions outside eu-west-1","is_correct":false,"explanation":"Per-user policies are hard to manage and can be overridden by administrators."},{"id":"b","text":"A Service Control Policy (SCP) on the organizational unit denying actions outside eu-west-1","is_correct":true,"explanation":"SCPs apply to all principals in the account and cannot be overridden, even by account administrators."},{"id":"c","text":"AWS Config rules to detect non-compliant resources","is_correct":false,"explanation":"Config detects after creation but does not prevent resource creation in other regions."},{"id":"d","text":"VPC configuration limiting network to eu-west-1","is_correct":false,"explanation":"VPCs are region-specific but do not prevent creating resources in other regions."}]', 'SCPs define maximum permissions for an account. A deny policy on actions outside a specific region prevents any principal from creating resources there.', 3, 'https://docs.aws.amazon.com/organizations/latest/userguide/orgs_manage_policies_scps.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to enable cross-account access so that a Lambda function in Account A can read from a DynamoDB table in Account B. What is the recommended approach?', '[{"id":"a","text":"Share the DynamoDB table credentials via email","is_correct":false,"explanation":"Sharing credentials is a critical security anti-pattern."},{"id":"b","text":"Create an IAM role in Account B with DynamoDB read permissions and a trust policy allowing Account A, then have Lambda assume that role","is_correct":true,"explanation":"Cross-account IAM roles with trust policies provide secure, temporary credential-based access."},{"id":"c","text":"Make the DynamoDB table public","is_correct":false,"explanation":"DynamoDB tables cannot be made public, and this would be a security risk."},{"id":"d","text":"Replicate the table to Account A","is_correct":false,"explanation":"Replication adds cost and complexity for what can be solved with IAM roles."}]', 'Cross-account access via IAM roles uses STS AssumeRole to provide temporary credentials. The trust policy controls which principals in the source account can assume the role.', 3, 'https://docs.aws.amazon.com/IAM/latest/UserGuide/tutorial_cross-account-with-roles.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants to enforce MFA for all API calls that delete S3 objects. Which feature should the architect enable?', '[{"id":"a","text":"S3 Object Lock","is_correct":false,"explanation":"Object Lock prevents deletion entirely for a retention period, it does not add MFA to delete operations."},{"id":"b","text":"S3 MFA Delete on the bucket","is_correct":true,"explanation":"MFA Delete requires authentication with an MFA device to delete object versions or change versioning state."},{"id":"c","text":"IAM policy with MFA condition on all actions","is_correct":false,"explanation":"IAM MFA conditions work for console/API sessions but MFA Delete specifically protects S3 versioned deletions."},{"id":"d","text":"S3 bucket policy denying delete actions","is_correct":false,"explanation":"A blanket deny prevents all deletions, not just unauthenticated ones."}]', 'MFA Delete requires the bucket owner to include MFA authentication in requests that delete object versions or change the bucket versioning configuration.', 3, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/MultiFactorAuthenticationDelete.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to manage SSL/TLS certificates for their ALB and CloudFront distributions. They want automatic certificate renewal with no operational overhead. Which service should the architect use?', '[{"id":"a","text":"Self-signed certificates managed manually","is_correct":false,"explanation":"Self-signed certificates are not trusted by browsers and require manual renewal."},{"id":"b","text":"AWS Certificate Manager (ACM)","is_correct":true,"explanation":"ACM provides free SSL/TLS certificates for ALB and CloudFront with automatic renewal and zero operational overhead."},{"id":"c","text":"Import certificates from a third-party CA and track expiration manually","is_correct":false,"explanation":"Manual tracking of certificate expiration is error-prone."},{"id":"d","text":"AWS Secrets Manager for certificate storage","is_correct":false,"explanation":"Secrets Manager can store certificates but does not provide automatic issuance or renewal."}]', 'ACM issues free public SSL/TLS certificates that automatically renew. They integrate directly with ALB, CloudFront, and API Gateway.', 1, 'https://docs.aws.amazon.com/acm/latest/userguide/acm-overview.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants to detect unusual API activity in their AWS accounts, such as cryptocurrency mining or compromised credentials. Which service provides intelligent threat detection?', '[{"id":"a","text":"AWS CloudTrail","is_correct":false,"explanation":"CloudTrail logs API calls but does not analyze them for threats."},{"id":"b","text":"Amazon GuardDuty","is_correct":true,"explanation":"GuardDuty uses machine learning and threat intelligence to detect suspicious activity across CloudTrail, VPC Flow Logs, and DNS logs."},{"id":"c","text":"AWS Config","is_correct":false,"explanation":"Config monitors configuration compliance, not security threats."},{"id":"d","text":"Amazon Inspector","is_correct":false,"explanation":"Inspector scans for software vulnerabilities, not account-level threat detection."}]', 'GuardDuty continuously analyzes CloudTrail events, VPC Flow Logs, and DNS queries using ML and threat intelligence to detect compromised instances and accounts.', 2, 'https://docs.aws.amazon.com/guardduty/latest/ug/what-is-guardduty.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company stores sensitive PII data in S3. They need to automatically discover and classify sensitive data across all their buckets. Which service should the architect use?', '[{"id":"a","text":"AWS Config with S3 rules","is_correct":false,"explanation":"Config monitors bucket configuration, not the content of objects."},{"id":"b","text":"Amazon Macie","is_correct":true,"explanation":"Macie uses machine learning to automatically discover, classify, and protect sensitive data like PII in S3."},{"id":"c","text":"S3 Storage Lens","is_correct":false,"explanation":"Storage Lens provides storage metrics, not data classification."},{"id":"d","text":"AWS CloudTrail data events","is_correct":false,"explanation":"CloudTrail logs access events but does not scan or classify data content."}]', 'Amazon Macie automatically scans S3 buckets to discover sensitive data like PII, PHI, and financial data, providing alerts and detailed findings.', 2, 'https://docs.aws.amazon.com/macie/latest/user/what-is-macie.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to restrict S3 bucket access so that objects can only be accessed from within a specific VPC. No internet-based access should be allowed. Which mechanism should the architect use?', '[{"id":"a","text":"S3 Block Public Access","is_correct":false,"explanation":"Block Public Access prevents public access but does not restrict to a specific VPC."},{"id":"b","text":"S3 bucket policy with a condition restricting access to a VPC endpoint","is_correct":true,"explanation":"A bucket policy with aws:sourceVpce condition restricts access to requests originating from the specified VPC endpoint."},{"id":"c","text":"Security group attached to the S3 bucket","is_correct":false,"explanation":"S3 does not use security groups; it is a managed service."},{"id":"d","text":"S3 access points without VPC configuration","is_correct":false,"explanation":"Access points without VPC restrictions do not limit access to a specific VPC."}]', 'Bucket policies with the aws:sourceVpce or aws:sourceVpc condition key ensure that only requests through the specified VPC endpoint can access the bucket.', 4, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/example-bucket-policies-vpc-endpoint.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to implement row-level security in their data lake so that different departments can only see their own data when querying with Athena. Which service provides this capability?', '[{"id":"a","text":"S3 bucket policies per department","is_correct":false,"explanation":"S3 policies work at the object level, not at the row level within files."},{"id":"b","text":"AWS Lake Formation with data filters","is_correct":true,"explanation":"Lake Formation provides fine-grained access control including row-level and column-level security for data lake queries."},{"id":"c","text":"Athena workgroups","is_correct":false,"explanation":"Workgroups control query costs and settings but not row-level data access."},{"id":"d","text":"IAM policies on Athena","is_correct":false,"explanation":"IAM policies control which Athena resources can be used, not row-level data visibility."}]', 'Lake Formation data filters allow defining cell-level security policies that control which rows and columns specific principals can access when querying the data lake.', 4, 'https://docs.aws.amazon.com/lake-formation/latest/dg/data-filtering.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to rotate their RDS database master password automatically every 30 days. The application must seamlessly use the new password without downtime. Which approach should the architect implement?', '[{"id":"a","text":"Write a Lambda function that changes the password and updates application configuration files","is_correct":false,"explanation":"Custom rotation adds complexity and risk of application downtime during the update."},{"id":"b","text":"Use Secrets Manager with automatic rotation and have the application retrieve the secret at runtime","is_correct":true,"explanation":"Secrets Manager rotates the password and the application retrieves the current secret value at runtime, ensuring seamless transitions."},{"id":"c","text":"Use Parameter Store with a scheduled rotation script","is_correct":false,"explanation":"Parameter Store does not have built-in rotation capability with RDS integration."},{"id":"d","text":"Manually change the password and restart the application monthly","is_correct":false,"explanation":"Manual rotation causes downtime and is error-prone."}]', 'Secrets Manager rotation Lambda functions update both the secret and the RDS password atomically. Applications retrieve the current secret value on each connection.', 3, 'https://docs.aws.amazon.com/secretsmanager/latest/userguide/rotating-secrets_strategies.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants to limit the maximum permissions that any IAM role in their account can have, regardless of the policies attached to the role. Which IAM feature provides this boundary?', '[{"id":"a","text":"IAM role trust policy","is_correct":false,"explanation":"Trust policies control who can assume the role, not the maximum permissions of the role."},{"id":"b","text":"IAM permissions boundary","is_correct":true,"explanation":"Permissions boundaries set the maximum permissions an IAM entity can have. The effective permissions are the intersection of the boundary and identity policies."},{"id":"c","text":"Resource-based policies","is_correct":false,"explanation":"Resource-based policies control access to the resource, not the maximum permissions of a role."},{"id":"d","text":"IAM access advisor","is_correct":false,"explanation":"Access advisor shows last-accessed information but does not limit permissions."}]', 'Permissions boundaries define the maximum permissions. Even if an identity policy grants broader access, the effective permissions cannot exceed the boundary.', 3, 'https://docs.aws.amazon.com/IAM/latest/UserGuide/access_policies_boundaries.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to encrypt data in Amazon RDS but wants to manage the encryption keys using their own key material imported into AWS. Which KMS feature supports this?', '[{"id":"a","text":"AWS managed keys","is_correct":false,"explanation":"AWS managed keys use key material generated and managed by AWS, not customer-imported material."},{"id":"b","text":"KMS customer managed key with imported key material (BYOK)","is_correct":true,"explanation":"KMS supports importing your own key material into a CMK, giving you control over the key material while using KMS for key management."},{"id":"c","text":"CloudHSM for all KMS operations","is_correct":false,"explanation":"CloudHSM is a separate service; importing key material into KMS does not require CloudHSM."},{"id":"d","text":"S3 SSE-C","is_correct":false,"explanation":"SSE-C is for S3 customer-provided encryption keys, not RDS."}]', 'KMS BYOK (Bring Your Own Key) allows importing externally generated key material into a CMK. This provides control over key material while leveraging KMS key management.', 4, 'https://docs.aws.amazon.com/kms/latest/developerguide/importing-keys.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'multi_select', 'A company wants to implement a Zero Trust security model for their VPC-based application. (Select TWO) Which AWS features support Zero Trust principles?', '[{"id":"a","text":"AWS Verified Access for application access without VPN","is_correct":true,"explanation":"Verified Access evaluates each request against security policies based on identity and device posture, a core Zero Trust principle."},{"id":"b","text":"Security groups allowing all internal VPC traffic","is_correct":false,"explanation":"Allowing all internal traffic is the opposite of Zero Trust, which requires verifying every request."},{"id":"c","text":"AWS PrivateLink for service-to-service communication without exposing traffic to the VPC network","is_correct":true,"explanation":"PrivateLink provides private connectivity between services without traversing the broader network, limiting lateral movement."},{"id":"d","text":"Public subnets for all workloads","is_correct":false,"explanation":"Public subnets increase the attack surface, contradicting Zero Trust principles."}]', 'Zero Trust verifies every request regardless of network location. Verified Access evaluates trust per-request, and PrivateLink limits network exposure between services.', 4, 'https://docs.aws.amazon.com/verified-access/latest/ug/what-is-verified-access.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to scan their EC2 instances and container images for software vulnerabilities automatically. Which service provides managed vulnerability scanning?', '[{"id":"a","text":"AWS GuardDuty","is_correct":false,"explanation":"GuardDuty detects account and network threats, not software vulnerabilities on instances."},{"id":"b","text":"Amazon Inspector","is_correct":true,"explanation":"Inspector automatically scans EC2 instances and ECR container images for software vulnerabilities and unintended network exposure."},{"id":"c","text":"AWS Config","is_correct":false,"explanation":"Config monitors resource configuration, not software package vulnerabilities."},{"id":"d","text":"AWS Trusted Advisor","is_correct":false,"explanation":"Trusted Advisor provides general best-practice checks, not detailed vulnerability scanning."}]', 'Amazon Inspector continuously scans workloads for software vulnerabilities using CVE databases. It integrates with ECR for container image scanning and Systems Manager for EC2.', 2, 'https://docs.aws.amazon.com/inspector/latest/user/what-is-inspector.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company uses CloudFront to serve their application. They need to ensure that users can only access the application through CloudFront and not directly via the ALB origin. How should the architect configure this?', '[{"id":"a","text":"Use a security group on the ALB that allows only CloudFront IP ranges","is_correct":false,"explanation":"CloudFront IP ranges change and managing them in security groups is complex, though AWS does publish them."},{"id":"b","text":"Configure CloudFront to add a custom header and create an ALB listener rule that validates the header","is_correct":true,"explanation":"A custom origin header set by CloudFront and validated by the ALB ensures only CloudFront traffic reaches the origin."},{"id":"c","text":"Remove the ALB public IP","is_correct":false,"explanation":"ALBs in public subnets always have public IPs; you cannot remove them selectively."},{"id":"d","text":"Use Route 53 to point only to CloudFront","is_correct":false,"explanation":"DNS configuration does not prevent direct access to the ALB if its DNS name is known."}]', 'Adding a custom secret header in CloudFront and validating it at the ALB ensures only CloudFront-routed requests are accepted, blocking direct ALB access.', 3, 'https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/restrict-access-to-load-balancer.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants to centrally manage firewall rules across multiple AWS accounts and VPCs. They need to enforce that all accounts use the approved WAF rules. Which service should the architect use?', '[{"id":"a","text":"AWS WAF with individual configurations per account","is_correct":false,"explanation":"Individual configurations are inconsistent and hard to manage at scale."},{"id":"b","text":"AWS Firewall Manager","is_correct":true,"explanation":"Firewall Manager centrally configures and manages WAF rules, Shield Advanced, security groups, and Network Firewall policies across accounts."},{"id":"c","text":"AWS Organizations SCPs","is_correct":false,"explanation":"SCPs restrict API actions but do not manage WAF rule configurations."},{"id":"d","text":"AWS Config with custom rules","is_correct":false,"explanation":"Config can detect non-compliant configurations but does not enforce WAF rules."}]', 'Firewall Manager provides centralized management of WAF rules across accounts in an Organization, automatically applying policies to new resources as they are created.', 3, 'https://docs.aws.amazon.com/waf/latest/developerguide/fms-chapter.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company needs to implement end-to-end encryption for their ECS application. Data must be encrypted from the client browser to the container. The ALB currently terminates SSL. What should the architect change?', '[{"id":"a","text":"Keep ALB SSL termination as-is","is_correct":false,"explanation":"SSL termination at the ALB means traffic between ALB and containers is unencrypted."},{"id":"b","text":"Configure ALB to use HTTPS listeners with TLS re-encryption to the target containers","is_correct":true,"explanation":"HTTPS target groups re-encrypt traffic from ALB to containers, providing end-to-end encryption."},{"id":"c","text":"Replace ALB with a Network Load Balancer using TCP listeners","is_correct":false,"explanation":"NLB TCP passthrough works but loses ALB L7 features like path-based routing."},{"id":"d","text":"Use CloudFront for SSL termination instead","is_correct":false,"explanation":"Moving SSL termination to CloudFront still leaves the ALB-to-container segment unencrypted."}]', 'ALB supports HTTPS target groups that re-encrypt traffic to backends. This provides end-to-end encryption while preserving L7 features like path-based routing.', 3, 'https://docs.aws.amazon.com/elasticloadbalancing/latest/application/load-balancer-target-groups.html', 'SAA-C03-3.2', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company wants to use AWS CloudHSM for their application''s encryption keys. What is the primary advantage of CloudHSM over KMS?', '[{"id":"a","text":"Lower cost","is_correct":false,"explanation":"CloudHSM is significantly more expensive than KMS."},{"id":"b","text":"Single-tenant HSM hardware where only you control the keys, meeting FIPS 140-2 Level 3 compliance","is_correct":true,"explanation":"CloudHSM provides dedicated, single-tenant HSMs where AWS has no access to the key material, meeting FIPS 140-2 Level 3."},{"id":"c","text":"Automatic key rotation","is_correct":false,"explanation":"KMS provides automatic key rotation; CloudHSM requires manual rotation."},{"id":"d","text":"Simpler integration with AWS services","is_correct":false,"explanation":"KMS has broader native integration with AWS services compared to CloudHSM."}]', 'CloudHSM provides dedicated FIPS 140-2 Level 3 validated HSMs where only you control the keys. AWS cannot access or recover key material on your CloudHSM.', 4, 'https://docs.aws.amazon.com/cloudhsm/latest/userguide/introduction.html', 'SAA-C03-3.1', true, true),
('b1000000-0000-4000-8000-000000000003', 'single_choice', 'A company has an API Gateway API that should only accept requests from known IP addresses. How should the architect restrict access?', '[{"id":"a","text":"Configure CORS to allow only specific origins","is_correct":false,"explanation":"CORS is a browser-enforced policy that does not restrict server-side API access by IP."},{"id":"b","text":"Create a resource policy on API Gateway that allows only specific IP CIDR ranges","is_correct":true,"explanation":"API Gateway resource policies can whitelist IP ranges using aws:SourceIp conditions."},{"id":"c","text":"Use API keys for IP filtering","is_correct":false,"explanation":"API keys identify callers for throttling/metering but do not filter by IP address."},{"id":"d","text":"Configure VPC endpoints for the API","is_correct":false,"explanation":"VPC endpoints restrict to VPC access, not specific public IPs."}]', 'API Gateway resource policies support IP-based access control using aws:SourceIp conditions, allowing you to whitelist specific IP ranges for API access.', 2, 'https://docs.aws.amazon.com/apigateway/latest/developerguide/apigateway-resource-policies.html', 'SAA-C03-3.2', true, true),
-- ============================================================
-- COST domain — 20 questions
-- ============================================================
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company runs a steady-state production workload on EC2 instances 24/7 for the next 3 years. They want to minimize compute costs. Which purchasing option provides the greatest savings?', '[{"id":"a","text":"On-Demand Instances","is_correct":false,"explanation":"On-Demand is the most expensive option for predictable, long-running workloads."},{"id":"b","text":"Reserved Instances with All Upfront payment for 3 years","is_correct":true,"explanation":"3-year All Upfront Reserved Instances provide the maximum discount (up to 72%) compared to On-Demand."},{"id":"c","text":"Spot Instances","is_correct":false,"explanation":"Spot Instances can be interrupted and are not suitable for steady-state production workloads."},{"id":"d","text":"Savings Plans with No Upfront for 1 year","is_correct":false,"explanation":"1-year No Upfront provides less savings than 3-year All Upfront."}]', 'Reserved Instances with 3-year All Upfront payment provide the deepest discount. For steady-state workloads with known instance types, RIs offer maximum savings.', 2, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ec2-reserved-instances.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company wants to reduce their S3 storage costs. They have 100 TB of data where 10% is accessed frequently, 30% is accessed monthly, and 60% has not been accessed in over a year. Which S3 strategy minimizes cost?', '[{"id":"a","text":"Store everything in S3 Standard","is_correct":false,"explanation":"Standard is the most expensive tier for infrequently accessed data."},{"id":"b","text":"Use S3 Intelligent-Tiering for all data","is_correct":true,"explanation":"Intelligent-Tiering automatically moves objects to the most cost-effective tier based on actual access patterns with no retrieval fees."},{"id":"c","text":"Manually classify and move data to different storage classes","is_correct":false,"explanation":"Manual classification is labor-intensive and does not adapt to changing access patterns."},{"id":"d","text":"Store everything in S3 Glacier","is_correct":false,"explanation":"Glacier adds retrieval latency and costs for the 10% frequently accessed data."}]', 'S3 Intelligent-Tiering automatically moves objects between Frequent, Infrequent, Archive Instant, Archive, and Deep Archive tiers based on access patterns.', 2, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/intelligent-tiering.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company has multiple AWS accounts and wants to identify cost optimization opportunities across all accounts. Which service provides organization-wide cost recommendations?', '[{"id":"a","text":"AWS Budgets","is_correct":false,"explanation":"Budgets track spending against targets but do not provide optimization recommendations."},{"id":"b","text":"AWS Cost Explorer with rightsizing recommendations","is_correct":true,"explanation":"Cost Explorer provides rightsizing recommendations across accounts, identifying underutilized instances and suggesting downsizing."},{"id":"c","text":"AWS CloudWatch billing metrics","is_correct":false,"explanation":"CloudWatch billing shows spend but does not recommend optimizations."},{"id":"d","text":"AWS Organizations consolidated billing only","is_correct":false,"explanation":"Consolidated billing aggregates invoices but does not provide optimization insights."}]', 'Cost Explorer rightsizing recommendations analyze EC2 usage patterns and recommend instance size changes or terminations to reduce costs.', 2, 'https://docs.aws.amazon.com/cost-management/latest/userguide/ce-rightsizing.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company runs Lambda functions that are invoked millions of times per day with an average duration of 100ms. They want to reduce Lambda costs. Which optimization should the architect implement?', '[{"id":"a","text":"Increase memory to maximum (10 GB)","is_correct":false,"explanation":"Maximum memory is unnecessary and increases per-invocation cost."},{"id":"b","text":"Right-size memory allocation using AWS Lambda Power Tuning and use Graviton (arm64) architecture","is_correct":true,"explanation":"Power Tuning finds the optimal memory/cost balance, and Graviton provides up to 20% better price-performance."},{"id":"c","text":"Use provisioned concurrency for all functions","is_correct":false,"explanation":"Provisioned concurrency adds fixed costs and is only beneficial for latency-sensitive cold starts."},{"id":"d","text":"Migrate to EC2 instances","is_correct":false,"explanation":"EC2 adds operational overhead and may not be cost-effective at variable scales."}]', 'Lambda Power Tuning tests functions at different memory levels to find the cost-optimal configuration. Graviton (arm64) provides 20% lower cost with comparable performance.', 3, 'https://docs.aws.amazon.com/lambda/latest/dg/foundation-arch.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company has development and test environments that run only during business hours (8 AM - 6 PM, Monday to Friday). What should the architect implement to reduce costs?', '[{"id":"a","text":"Use Reserved Instances for dev/test","is_correct":false,"explanation":"Reserved Instances provide savings for 24/7 workloads; dev/test runs only 50 hours/week."},{"id":"b","text":"Use Instance Scheduler or scheduled Auto Scaling to start/stop instances during business hours only","is_correct":true,"explanation":"Stopping instances outside business hours saves approximately 70% compared to running 24/7."},{"id":"c","text":"Move dev/test to a cheaper AWS Region","is_correct":false,"explanation":"Cheaper regions help marginally but do not address the 70% idle time."},{"id":"d","text":"Use t3.micro for all dev/test workloads","is_correct":false,"explanation":"Smaller instances reduce cost but still waste money running outside business hours."}]', 'Scheduling instances to run only during business hours (50 of 168 weekly hours) saves approximately 70% on compute costs for non-production environments.', 1, 'https://docs.aws.amazon.com/solutions/latest/instance-scheduler-on-aws/solution-overview.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company wants to commit to a specific dollar amount of compute usage per hour rather than specific instance types. Which pricing model provides this flexibility?', '[{"id":"a","text":"Standard Reserved Instances","is_correct":false,"explanation":"Standard RIs lock in specific instance types and cannot be easily changed."},{"id":"b","text":"Compute Savings Plans","is_correct":true,"explanation":"Compute Savings Plans provide savings in exchange for a commitment to a consistent dollar amount per hour, with flexibility across instance families, regions, and compute services."},{"id":"c","text":"Convertible Reserved Instances","is_correct":false,"explanation":"Convertible RIs allow changing instance attributes but are still instance-based commitments."},{"id":"d","text":"Spot Instances","is_correct":false,"explanation":"Spot has no commitment but can be interrupted."}]', 'Compute Savings Plans offer up to 66% savings and automatically apply to any EC2, Fargate, or Lambda usage, regardless of instance family, size, OS, or Region.', 2, 'https://docs.aws.amazon.com/savingsplans/latest/userguide/what-is-savings-plans.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company has a data lake with 500 TB in S3. Most data is queried with Athena but only a few columns are read per query. How should the architect optimize Athena costs?', '[{"id":"a","text":"Use S3 Standard-IA storage class","is_correct":false,"explanation":"Storage class affects storage cost, not Athena query cost which is based on data scanned."},{"id":"b","text":"Convert data to Parquet format and partition by frequently filtered columns","is_correct":true,"explanation":"Parquet columnar format reduces data scanned per query, and partitioning eliminates scanning irrelevant data. Athena charges per TB scanned."},{"id":"c","text":"Increase Athena query timeout","is_correct":false,"explanation":"Query timeout does not affect cost; Athena charges based on data scanned."},{"id":"d","text":"Use larger file sizes only","is_correct":false,"explanation":"Larger files reduce S3 request overhead but do not significantly reduce data scanned."}]', 'Athena charges $5 per TB scanned. Parquet can reduce scanned data by 90%+ (columnar skip), and partitioning eliminates scanning entire partitions.', 3, 'https://docs.aws.amazon.com/athena/latest/ug/partitions.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company runs NAT gateways in their VPC. The monthly data processing charges are very high. Which approach can reduce NAT gateway costs?', '[{"id":"a","text":"Use a larger NAT gateway","is_correct":false,"explanation":"NAT gateways do not come in sizes; they scale automatically and charge per GB processed."},{"id":"b","text":"Use VPC gateway endpoints for S3 and DynamoDB traffic to bypass the NAT gateway","is_correct":true,"explanation":"Gateway endpoints route S3/DynamoDB traffic directly without NAT gateway processing charges, which are $0.045/GB."},{"id":"c","text":"Add more NAT gateways","is_correct":false,"explanation":"More NAT gateways increase availability but do not reduce per-GB costs."},{"id":"d","text":"Compress all outbound traffic","is_correct":false,"explanation":"Compression at the NAT gateway level is not possible; it depends on the application protocol."}]', 'VPC gateway endpoints for S3 and DynamoDB are free and bypass NAT gateways. Since S3 traffic often dominates NAT costs, this can significantly reduce expenses.', 2, 'https://docs.aws.amazon.com/vpc/latest/privatelink/gateway-endpoints.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company uses CloudWatch and has thousands of custom metrics. They want to reduce monitoring costs. Which approach is most effective?', '[{"id":"a","text":"Delete all custom metrics","is_correct":false,"explanation":"Removing all monitoring eliminates visibility and is not practical."},{"id":"b","text":"Use CloudWatch Embedded Metric Format to publish metrics via logs, and remove unused custom metrics","is_correct":true,"explanation":"EMF allows publishing metrics through log data at lower cost than PutMetricData API, and auditing unused metrics reduces waste."},{"id":"c","text":"Switch to a third-party monitoring tool","is_correct":false,"explanation":"Third-party tools may have their own costs and do not necessarily reduce overall spending."},{"id":"d","text":"Reduce the metric resolution from 1-second to 1-minute","is_correct":false,"explanation":"Standard resolution is already 1-minute; high-resolution metrics should only be used where needed."}]', 'CloudWatch EMF publishes custom metrics through structured log events, which can be more cost-effective than individual PutMetricData calls for high-volume metrics.', 3, 'https://docs.aws.amazon.com/AmazonCloudWatch/latest/monitoring/CloudWatch_Embedded_Metric_Format.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company uses Amazon RDS but their database CPU utilization averages only 10%. Which service can identify that the instance is oversized and recommend a smaller instance?', '[{"id":"a","text":"AWS CloudTrail","is_correct":false,"explanation":"CloudTrail logs API calls, not resource utilization."},{"id":"b","text":"AWS Compute Optimizer","is_correct":true,"explanation":"Compute Optimizer analyzes utilization metrics and recommends optimal instance types, including RDS, for cost and performance."},{"id":"c","text":"AWS Config","is_correct":false,"explanation":"Config monitors configuration compliance, not resource utilization patterns."},{"id":"d","text":"Amazon CloudWatch dashboards","is_correct":false,"explanation":"CloudWatch shows metrics but does not provide rightsizing recommendations."}]', 'Compute Optimizer uses machine learning to analyze utilization patterns and recommend optimal instance types for EC2, EBS, Lambda, and ECS on Fargate.', 1, 'https://docs.aws.amazon.com/compute-optimizer/latest/ug/what-is-compute-optimizer.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'multi_select', 'A company wants to reduce data transfer costs between AWS services. (Select TWO) Which practices minimize inter-service data transfer charges?', '[{"id":"a","text":"Keep communicating services in the same Availability Zone","is_correct":true,"explanation":"Data transfer within the same AZ is free for most services, while cross-AZ transfer costs $0.01/GB each way."},{"id":"b","text":"Use VPC endpoints for AWS service communication","is_correct":true,"explanation":"Gateway endpoints (S3, DynamoDB) are free and avoid NAT gateway data processing charges."},{"id":"c","text":"Use public IPs for all inter-service communication","is_correct":false,"explanation":"Public IP traffic can incur additional data transfer charges compared to private IP communication."},{"id":"d","text":"Replicate data across all regions","is_correct":false,"explanation":"Cross-region data transfer adds significant costs."}]', 'Same-AZ communication is free, and VPC gateway endpoints eliminate NAT gateway processing fees. These are two of the most effective ways to reduce data transfer costs.', 2, 'https://docs.aws.amazon.com/cur/latest/userguide/cur-data-transfers-charges.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company processes large batch jobs nightly. The jobs can tolerate delays of up to 6 hours. They currently use On-Demand instances. Which approach reduces cost while meeting the time requirement?', '[{"id":"a","text":"Reserved Instances","is_correct":false,"explanation":"RIs are for steady-state workloads, not nightly batch jobs."},{"id":"b","text":"Spot Instances with a Spot Fleet using diversified allocation strategy","is_correct":true,"explanation":"Diversified Spot Fleet spreads across instance types/AZs, reducing interruption risk while saving up to 90% vs On-Demand."},{"id":"c","text":"Dedicated Instances","is_correct":false,"explanation":"Dedicated Instances cost more than On-Demand."},{"id":"d","text":"Lambda functions","is_correct":false,"explanation":"Lambda has a 15-minute timeout, which may not suit long-running batch processing."}]', 'Spot Fleet with diversified allocation uses multiple instance types and AZs to minimize interruption probability while providing up to 90% savings.', 3, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/spot-fleet.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company wants to set up alerts when their monthly AWS bill is forecasted to exceed $50,000. Which service should the architect configure?', '[{"id":"a","text":"AWS Cost Explorer","is_correct":false,"explanation":"Cost Explorer provides analysis and visualization but not automated budget alerts."},{"id":"b","text":"AWS Budgets with a forecasted cost budget and SNS notification","is_correct":true,"explanation":"AWS Budgets supports forecasted cost thresholds and can send SNS notifications or trigger automated actions when thresholds are breached."},{"id":"c","text":"CloudWatch billing alarms","is_correct":false,"explanation":"CloudWatch billing alarms trigger on actual spend, not forecasted spend."},{"id":"d","text":"AWS Trusted Advisor cost checks","is_correct":false,"explanation":"Trusted Advisor provides one-time checks, not continuous forecasting with alerts."}]', 'AWS Budgets supports actual and forecasted cost budgets with email, SNS, and Chatbot notifications, plus automated actions like stopping instances.', 1, 'https://docs.aws.amazon.com/cost-management/latest/userguide/budgets-managing-costs.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company uses EBS gp2 volumes for their application. They notice they are paying for provisioned IOPS they do not use. What should the architect recommend to reduce costs?', '[{"id":"a","text":"Switch to io2 volumes","is_correct":false,"explanation":"io2 volumes are more expensive and designed for high-IOPS workloads."},{"id":"b","text":"Migrate to gp3 volumes with baseline IOPS and only provision additional IOPS if needed","is_correct":true,"explanation":"gp3 provides 3,000 baseline IOPS at a lower per-GB price than gp2, and you only pay for additional IOPS if needed."},{"id":"c","text":"Reduce volume size","is_correct":false,"explanation":"With gp2, reducing size also reduces IOPS (3 IOPS/GB), which may impact performance."},{"id":"d","text":"Use instance store volumes instead","is_correct":false,"explanation":"Instance store is ephemeral and unsuitable for persistent data."}]', 'gp3 decouples IOPS from storage size, providing 3,000 IOPS baseline at 20% lower cost per GB than gp2. Additional IOPS can be provisioned independently as needed.', 2, 'https://docs.aws.amazon.com/ebs/latest/userguide/general-purpose.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company uses Amazon Aurora MySQL for production. The database runs 24/7 but has minimal traffic between midnight and 6 AM. How can they reduce costs during low-traffic periods?', '[{"id":"a","text":"Stop the Aurora cluster at midnight and start it at 6 AM","is_correct":false,"explanation":"Stopping Aurora has a cold start delay and may not be suitable for production availability requirements."},{"id":"b","text":"Use Aurora Serverless v2 which scales down to a minimum ACU during low-traffic periods","is_correct":true,"explanation":"Aurora Serverless v2 automatically scales capacity down to the minimum ACU during low traffic, reducing costs during off-peak hours."},{"id":"c","text":"Delete read replicas at night","is_correct":false,"explanation":"Deleting and recreating replicas is complex and time-consuming."},{"id":"d","text":"Switch to RDS MySQL at night","is_correct":false,"explanation":"Switching database engines nightly is not practical."}]', 'Aurora Serverless v2 scales in 0.5 ACU increments. During low traffic, it scales down to the configured minimum, potentially saving 80%+ compared to a fixed-size instance.', 3, 'https://docs.aws.amazon.com/AmazonRDS/latest/AuroraUserGuide/aurora-serverless-v2.how-it-works.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company wants to analyze their AWS spending by team, project, and environment (dev/staging/prod). What should the architect implement?', '[{"id":"a","text":"Separate AWS accounts for each combination","is_correct":false,"explanation":"Too many accounts creates management overhead."},{"id":"b","text":"Cost allocation tags (e.g., Team, Project, Environment) with activation in the Billing console","is_correct":true,"explanation":"Cost allocation tags appear in Cost Explorer and billing reports, enabling cost attribution by team, project, or environment."},{"id":"c","text":"CloudWatch custom metrics for costs","is_correct":false,"explanation":"Custom metrics cannot track AWS billing by tag."},{"id":"d","text":"AWS Config resource grouping","is_correct":false,"explanation":"Config tracks configuration, not cost attribution."}]', 'Cost allocation tags enable granular cost tracking. User-defined tags must be activated in the Billing console to appear in cost reports and Cost Explorer.', 1, 'https://docs.aws.amazon.com/awsaccountbilling/latest/aboutv2/cost-alloc-tags.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company stores 50 TB of log data in S3 that must be retained for 7 years but is almost never accessed. Retrieval time of 12 hours is acceptable when needed. Which storage class minimizes cost?', '[{"id":"a","text":"S3 Standard-IA","is_correct":false,"explanation":"Standard-IA is cheaper than Standard but much more expensive than archive tiers for rarely accessed data."},{"id":"b","text":"S3 Glacier Deep Archive","is_correct":true,"explanation":"Glacier Deep Archive is the lowest-cost S3 storage class at ~$1/TB/month, with retrieval within 12 hours."},{"id":"c","text":"S3 One Zone-IA","is_correct":false,"explanation":"One Zone-IA is cheaper than Standard-IA but still far more expensive than archive tiers."},{"id":"d","text":"S3 Glacier Instant Retrieval","is_correct":false,"explanation":"Instant Retrieval provides millisecond access but at a higher cost than Deep Archive."}]', 'S3 Glacier Deep Archive costs as low as $0.00099/GB/month (~$1/TB/month), making it ideal for rarely accessed data where 12-hour retrieval is acceptable.', 1, 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/storage-class-intro.html', 'SAA-C03-4.2', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company runs a fleet of EC2 instances and wants to identify which instances are idle or underutilized. Which tool should the architect use?', '[{"id":"a","text":"Amazon CloudWatch standard metrics only","is_correct":false,"explanation":"Standard metrics show utilization but do not provide specific rightsizing or idle instance recommendations."},{"id":"b","text":"AWS Trusted Advisor with the idle/underutilized EC2 checks","is_correct":true,"explanation":"Trusted Advisor checks identify EC2 instances with low CPU and network utilization, recommending termination or downsizing."},{"id":"c","text":"AWS CloudTrail","is_correct":false,"explanation":"CloudTrail logs API calls, not instance utilization."},{"id":"d","text":"AWS Config","is_correct":false,"explanation":"Config monitors configuration compliance, not instance utilization patterns."}]', 'Trusted Advisor cost optimization checks identify EC2 instances with average CPU utilization below 10% and low network I/O, flagging them as candidates for downsizing.', 1, 'https://docs.aws.amazon.com/awssupport/latest/user/cost-optimization-checks.html', 'SAA-C03-4.1', true, true),
('b1000000-0000-4000-8000-000000000004', 'single_choice', 'A company has EC2 instances running in us-east-1 and us-west-2. They want to minimize data transfer costs between the two regions. What should the architect recommend?', '[{"id":"a","text":"Use VPC peering between regions","is_correct":false,"explanation":"VPC peering enables connectivity but does not reduce cross-region data transfer rates."},{"id":"b","text":"Minimize cross-region data transfer by caching data locally in each region and only syncing changes","is_correct":true,"explanation":"Reducing the volume of cross-region transfer by caching locally and syncing deltas minimizes the per-GB transfer charges."},{"id":"c","text":"Use AWS Direct Connect between regions","is_correct":false,"explanation":"Direct Connect connects on-premises to AWS, not between AWS regions."},{"id":"d","text":"Route all traffic through CloudFront","is_correct":false,"explanation":"CloudFront is for user-facing content delivery, not inter-region application traffic."}]', 'Cross-region data transfer costs $0.02/GB. Reducing transfer volume through local caching, delta syncs, and data compression is the most effective cost optimization.', 3, 'https://docs.aws.amazon.com/cur/latest/userguide/cur-data-transfers-charges.html', 'SAA-C03-4.2', true, true),
-- ============================================================
-- OPERATIONS domain — 20 questions
-- ============================================================
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company wants to implement infrastructure as code for their AWS environment. They need to define resources in JSON or YAML templates and manage stack lifecycle. Which service should they use?', '[{"id":"a","text":"AWS CLI scripts","is_correct":false,"explanation":"CLI scripts are imperative and lack state management and drift detection."},{"id":"b","text":"AWS CloudFormation","is_correct":true,"explanation":"CloudFormation uses declarative templates (JSON/YAML) to provision and manage resources as stacks with lifecycle management."},{"id":"c","text":"AWS CodeDeploy","is_correct":false,"explanation":"CodeDeploy handles application deployment, not infrastructure provisioning."},{"id":"d","text":"AWS Systems Manager","is_correct":false,"explanation":"Systems Manager manages operations on existing resources, not infrastructure provisioning."}]', 'CloudFormation provides declarative infrastructure as code with stack management, drift detection, change sets, and rollback capabilities.', 1, 'https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/Welcome.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company needs to centralize logs from EC2 instances, Lambda functions, and ECS containers for analysis and alerting. Which service provides a unified logging solution?', '[{"id":"a","text":"Amazon S3 with manual log uploads","is_correct":false,"explanation":"S3 stores logs but does not provide real-time analysis or alerting."},{"id":"b","text":"Amazon CloudWatch Logs with Logs Insights for querying","is_correct":true,"explanation":"CloudWatch Logs centralizes logs from multiple AWS services and Logs Insights provides interactive SQL-like querying."},{"id":"c","text":"AWS CloudTrail","is_correct":false,"explanation":"CloudTrail logs API calls, not application logs."},{"id":"d","text":"Amazon Kinesis Data Streams","is_correct":false,"explanation":"Kinesis processes streaming data but is not a log analysis solution."}]', 'CloudWatch Logs collects logs from all AWS compute services. Logs Insights provides fast, interactive querying with a SQL-like syntax for analysis and troubleshooting.', 1, 'https://docs.aws.amazon.com/AmazonCloudWatch/latest/logs/WhatIsCloudWatchLogs.html', 'SAA-C03-5.2', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company wants to automate the remediation of unencrypted EBS volumes. When a non-compliant volume is detected, it should automatically be encrypted. Which combination of services should the architect use?', '[{"id":"a","text":"AWS Config rule + Lambda function for remediation","is_correct":false,"explanation":"This works but requires custom Lambda code."},{"id":"b","text":"AWS Config rule with auto-remediation using SSM Automation documents","is_correct":true,"explanation":"Config auto-remediation triggers SSM Automation documents to automatically fix non-compliant resources without custom code."},{"id":"c","text":"CloudWatch alarms with SNS notifications","is_correct":false,"explanation":"Alarms and SNS provide alerting but not automated remediation."},{"id":"d","text":"AWS Trusted Advisor with manual remediation","is_correct":false,"explanation":"Trusted Advisor does not support automated remediation actions."}]', 'AWS Config auto-remediation integrates with SSM Automation to run predefined or custom remediation actions when non-compliant resources are detected.', 3, 'https://docs.aws.amazon.com/config/latest/developerguide/remediation.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company needs to provide their operations team with secure shell access to EC2 instances in private subnets without opening SSH ports or managing bastion hosts. Which service should the architect use?', '[{"id":"a","text":"EC2 Instance Connect","is_correct":false,"explanation":"Instance Connect requires SSH port 22 to be open."},{"id":"b","text":"AWS Systems Manager Session Manager","is_correct":true,"explanation":"Session Manager provides browser-based or CLI shell access through the SSM agent without opening inbound ports or managing SSH keys."},{"id":"c","text":"AWS Cloud9","is_correct":false,"explanation":"Cloud9 is an IDE, not a general-purpose remote access solution."},{"id":"d","text":"VPN connection to the private subnet","is_correct":false,"explanation":"VPN provides network access but still requires SSH port management and key management."}]', 'Session Manager provides encrypted shell access through the SSM agent, logging all sessions to S3/CloudWatch. No inbound ports, bastion hosts, or SSH keys needed.', 2, 'https://docs.aws.amazon.com/systems-manager/latest/userguide/session-manager.html', 'SAA-C03-5.2', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company wants to deploy the same infrastructure across multiple AWS accounts and regions using CloudFormation. What feature simplifies this multi-account, multi-region deployment?', '[{"id":"a","text":"CloudFormation nested stacks","is_correct":false,"explanation":"Nested stacks deploy within a single account and region."},{"id":"b","text":"CloudFormation StackSets","is_correct":true,"explanation":"StackSets deploy CloudFormation stacks across multiple accounts and regions from a single template."},{"id":"c","text":"CloudFormation change sets","is_correct":false,"explanation":"Change sets preview changes before applying them, but only to a single stack."},{"id":"d","text":"AWS CDK with multiple environments","is_correct":false,"explanation":"CDK still requires synthesizing and deploying individually to each account/region without StackSets."}]', 'CloudFormation StackSets deploy from a management account to target accounts/regions. They support automatic deployment to new accounts added to an OU.', 3, 'https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/what-is-cfnstacksets.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company wants to automatically respond to security findings in their AWS environment. When GuardDuty detects a compromised EC2 instance, they want to automatically isolate it. Which integration should the architect implement?', '[{"id":"a","text":"GuardDuty with SNS email notifications only","is_correct":false,"explanation":"Email notifications require manual intervention, not automated response."},{"id":"b","text":"GuardDuty findings via EventBridge triggering a Lambda function that modifies the security group","is_correct":true,"explanation":"EventBridge captures GuardDuty findings and triggers Lambda to automatically apply an isolation security group with no inbound/outbound rules."},{"id":"c","text":"GuardDuty with CloudWatch Logs","is_correct":false,"explanation":"Logging findings does not trigger automated remediation."},{"id":"d","text":"GuardDuty with AWS Config","is_correct":false,"explanation":"Config monitors compliance but does not respond to GuardDuty findings."}]', 'GuardDuty publishes findings to EventBridge. A Lambda function can automatically isolate a compromised instance by replacing its security group with one that blocks all traffic.', 4, 'https://docs.aws.amazon.com/guardduty/latest/ug/guardduty_findings_cloudwatch.html', 'SAA-C03-5.2', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company uses CloudFormation to manage their infrastructure. They want to preview changes before applying an update to ensure no critical resources are accidentally replaced. Which feature should they use?', '[{"id":"a","text":"CloudFormation drift detection","is_correct":false,"explanation":"Drift detection identifies differences between the template and live resources, not upcoming changes from an update."},{"id":"b","text":"CloudFormation change sets","is_correct":true,"explanation":"Change sets show exactly which resources will be added, modified, or replaced before executing the update."},{"id":"c","text":"CloudFormation stack policies","is_correct":false,"explanation":"Stack policies prevent updates to specific resources but do not preview changes."},{"id":"d","text":"CloudFormation rollback configuration","is_correct":false,"explanation":"Rollback configuration defines when to roll back, not how to preview changes."}]', 'Change sets create a preview of proposed changes, showing which resources will be added, modified (in-place), or replaced. This prevents accidental data loss from replacements.', 2, 'https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/using-cfn-updating-stacks-changesets.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company needs to create a composite alarm that triggers only when both CPU utilization exceeds 80% AND memory utilization exceeds 90%. Which CloudWatch feature supports this?', '[{"id":"a","text":"CloudWatch metric math","is_correct":false,"explanation":"Metric math creates derived metrics but cannot create conditional alarm logic combining multiple alarms."},{"id":"b","text":"CloudWatch composite alarms","is_correct":true,"explanation":"Composite alarms combine multiple alarms using AND/OR logic, triggering only when the specified combination of alarm states is met."},{"id":"c","text":"CloudWatch anomaly detection","is_correct":false,"explanation":"Anomaly detection creates alarms based on expected patterns, not multi-metric conditions."},{"id":"d","text":"Multiple individual alarms with the same SNS topic","is_correct":false,"explanation":"Individual alarms trigger independently, not based on combined conditions."}]', 'Composite alarms use rule expressions (AND, OR, NOT) to combine multiple alarm states, reducing alarm noise and enabling more sophisticated alerting logic.', 3, 'https://docs.aws.amazon.com/AmazonCloudWatch/latest/monitoring/Create_Composite_Alarm.html', 'SAA-C03-5.2', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company wants to set up a landing zone with multi-account governance including guardrails, automated account provisioning, and SSO. Which service provides this?', '[{"id":"a","text":"AWS Organizations alone","is_correct":false,"explanation":"Organizations provides the foundation but lacks automated landing zone setup and guardrails."},{"id":"b","text":"AWS Control Tower","is_correct":true,"explanation":"Control Tower automates landing zone setup with Organizations, SSO, guardrails, and a centralized dashboard for multi-account governance."},{"id":"c","text":"AWS Service Catalog alone","is_correct":false,"explanation":"Service Catalog manages product portfolios, not full landing zone governance."},{"id":"d","text":"AWS CloudFormation StackSets alone","is_correct":false,"explanation":"StackSets deploy infrastructure but do not provide governance guardrails or SSO setup."}]', 'Control Tower sets up a multi-account environment with best-practice guardrails, Account Factory for provisioning, and centralized governance using Organizations and IAM Identity Center.', 2, 'https://docs.aws.amazon.com/controltower/latest/userguide/what-is-control-tower.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company needs to implement a CI/CD pipeline for their application deployed on ECS Fargate. Which set of AWS services provides a complete CI/CD pipeline?', '[{"id":"a","text":"CodeCommit, CodeBuild, and manual ECS deployment","is_correct":false,"explanation":"Manual deployment breaks the continuous deployment pipeline."},{"id":"b","text":"CodePipeline with CodeCommit as source, CodeBuild for building container images, and CodeDeploy for ECS blue/green deployment","is_correct":true,"explanation":"CodePipeline orchestrates the pipeline, CodeBuild creates the container image, and CodeDeploy performs blue/green deployments to ECS."},{"id":"c","text":"Jenkins on EC2 for everything","is_correct":false,"explanation":"Jenkins requires managing EC2 infrastructure and does not integrate natively with ECS deployment."},{"id":"d","text":"Lambda functions triggered by S3 uploads","is_correct":false,"explanation":"This is not a CI/CD pipeline architecture."}]', 'CodePipeline orchestrates the workflow: CodeCommit triggers the pipeline, CodeBuild creates and pushes container images to ECR, and CodeDeploy handles ECS blue/green deployments.', 3, 'https://docs.aws.amazon.com/codepipeline/latest/userguide/welcome.html', 'SAA-C03-5.2', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company needs to store configuration parameters for their application across multiple environments (dev, staging, prod). They need hierarchical organization with environment-specific overrides. Which service should the architect use?', '[{"id":"a","text":"S3 with JSON configuration files per environment","is_correct":false,"explanation":"S3 lacks hierarchical parameter management and environment-specific override semantics."},{"id":"b","text":"AWS Systems Manager Parameter Store with hierarchical paths","is_correct":true,"explanation":"Parameter Store supports hierarchical paths (e.g., /app/prod/db-url) with versioning, encryption, and granular IAM access control."},{"id":"c","text":"AWS Secrets Manager","is_correct":false,"explanation":"Secrets Manager is for sensitive credentials with rotation, not general configuration parameters."},{"id":"d","text":"Environment variables in the application code","is_correct":false,"explanation":"Hard-coded environment variables require code changes for each environment."}]', 'Parameter Store hierarchical paths allow organizing parameters by environment (/app/prod/..., /app/dev/...) with IAM policies controlling access per path level.', 2, 'https://docs.aws.amazon.com/systems-manager/latest/userguide/systems-manager-parameter-store.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company needs to track all changes to their AWS resource configurations over time for audit and compliance purposes. Which service provides a configuration history timeline?', '[{"id":"a","text":"AWS CloudTrail","is_correct":false,"explanation":"CloudTrail records who made API calls and when, but not the resulting resource configuration state over time."},{"id":"b","text":"AWS Config with configuration timeline","is_correct":true,"explanation":"Config records the configuration state of resources over time, providing a timeline of all configuration changes."},{"id":"c","text":"Amazon CloudWatch Logs","is_correct":false,"explanation":"CloudWatch Logs captures application and system logs, not resource configuration history."},{"id":"d","text":"AWS Trusted Advisor","is_correct":false,"explanation":"Trusted Advisor provides point-in-time best-practice checks, not historical configuration tracking."}]', 'AWS Config continuously records resource configurations and maintains a timeline showing every configuration change, who made it, and the before/after state.', 2, 'https://docs.aws.amazon.com/config/latest/developerguide/WhatIsConfig.html', 'SAA-C03-5.2', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company wants to implement canary deployments for their Lambda functions. They want to gradually shift traffic from the old version to the new version. Which feature supports this?', '[{"id":"a","text":"Lambda function versioning only","is_correct":false,"explanation":"Versioning creates immutable versions but does not split traffic between them."},{"id":"b","text":"Lambda aliases with weighted traffic shifting","is_correct":true,"explanation":"Lambda aliases can point to two versions simultaneously with configurable weights for gradual traffic shifting."},{"id":"c","text":"Lambda layers","is_correct":false,"explanation":"Layers provide shared code dependencies, not deployment strategies."},{"id":"d","text":"Lambda provisioned concurrency","is_correct":false,"explanation":"Provisioned concurrency pre-initializes execution environments, not traffic routing."}]', 'Lambda aliases with routing configuration split traffic between two versions. Combined with CodeDeploy, this enables automated canary and linear deployment strategies.', 3, 'https://docs.aws.amazon.com/lambda/latest/dg/configuration-aliases.html', 'SAA-C03-5.1', true, true),
('b1000000-0000-4000-8000-000000000005', 'single_choice', 'A company uses EventBridge to route events between their microservices. They need to track event flow and debug failed event deliveries. Which approach should the architect implement?', '[{"id":"a","text":"Enable CloudTrail for all EventBridge API calls","is_correct":false,"explanation":"CloudTrail logs API calls to EventBridge, not the event delivery flow between services."},{"id":"b","text":"Enable EventBridge event replay and dead-letter queues on rules, with CloudWatch Logs for matched events","is_correct":true,"explanation":"DLQs capture undeliverable events, event replay allows reprocessing, and CloudWatch Logs provide visibility into matched events."},{"id":"c","text":"Use X-Ray tracing on EventBridge","is_correct":false,"explanation":"EventBridge has limited native X-Ray integration for event flow tracing."},{"id":"d","text":"Log all events to S3","is_correct":false,"explanation":"S3 logging does not provide delivery failure debugging or event replay capability."}]', 'EventBridge DLQs capture events that fail delivery, event archives enable replay for reprocessing, and CloudWatch Logs targets can log all matched events for debugging.', 3, 'https://docs.aws.amazon.com/eventbridge/latest/userguide/eb-debug-event-delivery.html', 'SAA-C03-5.2', true, true),
-- ============================================================
-- IMPROVEMENT domain — 20 questions
-- ============================================================
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company has a legacy application that uses hardcoded database connection strings. They want to improve the architecture to support credential rotation without application downtime. What should the architect implement?', '[{"id":"a","text":"Update the connection strings in the application code with each rotation","is_correct":false,"explanation":"Code changes require redeployment and cause downtime."},{"id":"b","text":"Use AWS Secrets Manager with the application fetching credentials at runtime through the Secrets Manager API","is_correct":true,"explanation":"Fetching credentials at runtime allows transparent rotation without application changes or downtime."},{"id":"c","text":"Store credentials in environment variables","is_correct":false,"explanation":"Environment variables require restart to pick up new values."},{"id":"d","text":"Use IAM database authentication only","is_correct":false,"explanation":"IAM DB auth is not supported by all database engines and may require application changes."}]', 'Retrieving credentials from Secrets Manager at runtime (or connection time) ensures the application always uses the current credentials, even after rotation.', 2, 'https://docs.aws.amazon.com/secretsmanager/latest/userguide/intro.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company uses a monolithic application with a single large database. They want to improve scalability by decomposing into microservices. What database pattern should the architect recommend?', '[{"id":"a","text":"Keep the shared database for all microservices","is_correct":false,"explanation":"A shared database creates tight coupling between services and limits independent scaling."},{"id":"b","text":"Database per service pattern where each microservice owns its data store","is_correct":true,"explanation":"Each microservice having its own database enables independent scaling, technology choice, and deployment."},{"id":"c","text":"Single large DynamoDB table for all services","is_correct":false,"explanation":"A single table shared by all services is just a shared database in NoSQL form."},{"id":"d","text":"Replicate the entire database for each service","is_correct":false,"explanation":"Full replication wastes resources and creates data consistency challenges."}]', 'The database-per-service pattern is a fundamental microservices principle. Each service encapsulates its data, communicating with other services only through APIs.', 3, 'https://docs.aws.amazon.com/prescriptive-guidance/latest/modernization-decomposing-monoliths/database-per-service.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company wants to migrate from a self-managed RabbitMQ cluster on EC2 to a managed service to reduce operational overhead. Which AWS service should the architect recommend?', '[{"id":"a","text":"Amazon SQS","is_correct":false,"explanation":"SQS is AWS-native and does not support the AMQP protocol used by RabbitMQ."},{"id":"b","text":"Amazon MQ for RabbitMQ","is_correct":true,"explanation":"Amazon MQ provides fully managed RabbitMQ brokers, maintaining protocol compatibility while eliminating infrastructure management."},{"id":"c","text":"Amazon Kinesis","is_correct":false,"explanation":"Kinesis is a streaming service with a different API and paradigm than RabbitMQ."},{"id":"d","text":"Amazon SNS","is_correct":false,"explanation":"SNS is a pub/sub notification service, not a message broker compatible with AMQP."}]', 'Amazon MQ for RabbitMQ provides managed RabbitMQ brokers with AMQP support, allowing migration from self-managed clusters with minimal application code changes.', 2, 'https://docs.aws.amazon.com/amazon-mq/latest/developer-guide/welcome.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company has an application that writes logs to local disk on EC2. When instances are terminated, logs are lost. How should the architect improve log durability?', '[{"id":"a","text":"Use larger EBS volumes","is_correct":false,"explanation":"Larger EBS volumes do not solve the problem of instance termination log loss."},{"id":"b","text":"Install the CloudWatch Logs agent to stream logs to CloudWatch Logs in real-time","is_correct":true,"explanation":"The CloudWatch Logs agent streams logs continuously to CloudWatch, ensuring they persist regardless of instance lifecycle."},{"id":"c","text":"Take EBS snapshots before termination","is_correct":false,"explanation":"Snapshots before termination are not always possible, especially with Auto Scaling."},{"id":"d","text":"Use instance store for faster writes","is_correct":false,"explanation":"Instance store is even more ephemeral than EBS."}]', 'The unified CloudWatch agent streams logs in near real-time to CloudWatch Logs, providing durable, searchable log storage decoupled from instance lifecycle.', 1, 'https://docs.aws.amazon.com/AmazonCloudWatch/latest/logs/UseCloudWatchUnifiedAgent.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company uses polling to check for updates from an SQS queue every 5 seconds. They want to reduce empty responses and API costs. What should the architect change?', '[{"id":"a","text":"Reduce polling interval to 1 second","is_correct":false,"explanation":"More frequent polling increases API calls and costs, not reduces them."},{"id":"b","text":"Enable SQS long polling by setting WaitTimeSeconds to 20 seconds","is_correct":true,"explanation":"Long polling waits up to 20 seconds for messages, reducing empty responses and API calls by up to 90%."},{"id":"c","text":"Use SNS instead of SQS","is_correct":false,"explanation":"SNS is push-based but changes the architecture pattern."},{"id":"d","text":"Increase the batch size of ReceiveMessage","is_correct":false,"explanation":"Larger batches reduce calls when messages exist but do not help with empty responses."}]', 'SQS long polling (WaitTimeSeconds up to 20s) holds the connection open until messages arrive, virtually eliminating empty responses and reducing costs.', 2, 'https://docs.aws.amazon.com/AWSSimpleQueueService/latest/SQSDeveloperGuide/sqs-long-polling.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company runs a tightly coupled application where the frontend directly calls the backend database. They want to improve the architecture for better fault tolerance. What pattern should the architect introduce?', '[{"id":"a","text":"Add more database replicas","is_correct":false,"explanation":"More replicas help with read scaling but do not decouple the architecture."},{"id":"b","text":"Introduce an asynchronous message queue (SQS) between the frontend and backend processing","is_correct":true,"explanation":"Adding SQS decouples the components, allowing the frontend to continue operating even if the backend is temporarily unavailable."},{"id":"c","text":"Use a faster network connection","is_correct":false,"explanation":"Faster networking does not improve fault tolerance or decoupling."},{"id":"d","text":"Deploy everything in a single AZ for lower latency","is_correct":false,"explanation":"Single AZ deployment reduces availability, the opposite of the goal."}]', 'Asynchronous decoupling with SQS allows components to fail independently. The queue buffers messages during backend outages, improving overall system resilience.', 2, 'https://docs.aws.amazon.com/wellarchitected/latest/reliability-pillar/design-interactions-in-a-distributed-system-to-mitigate-or-withstand-failures.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company manually provisions EC2 instances using the AWS Console. They want to improve repeatability and reduce configuration drift. What is the first step the architect should recommend?', '[{"id":"a","text":"Document the manual steps in a wiki","is_correct":false,"explanation":"Documentation does not prevent drift or ensure repeatability."},{"id":"b","text":"Convert manual configurations to CloudFormation or Terraform templates","is_correct":true,"explanation":"Infrastructure as Code ensures consistent, repeatable provisioning and enables version control, review, and automated deployment."},{"id":"c","text":"Create AMIs of every configured instance","is_correct":false,"explanation":"AMIs capture a point-in-time state but do not manage the full infrastructure lifecycle."},{"id":"d","text":"Use AWS Config to monitor changes","is_correct":false,"explanation":"Config detects drift but does not prevent it or provide repeatable provisioning."}]', 'Infrastructure as Code is the foundational practice for operational excellence. It enables version control, peer review, testing, and consistent deployments.', 1, 'https://docs.aws.amazon.com/wellarchitected/latest/operational-excellence-pillar/prepare.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company uses a single large Lambda function that handles multiple API endpoints. They want to improve maintainability and independent deployment. What refactoring should the architect recommend?', '[{"id":"a","text":"Increase the function memory","is_correct":false,"explanation":"More memory does not improve code maintainability or deployment independence."},{"id":"b","text":"Split the monolithic function into individual functions per API endpoint","is_correct":true,"explanation":"Single-purpose functions are easier to maintain, test, debug, and deploy independently without affecting other endpoints."},{"id":"c","text":"Use Lambda Layers to share code","is_correct":false,"explanation":"Layers help share dependencies but do not address the monolithic function structure."},{"id":"d","text":"Move to ECS Fargate","is_correct":false,"explanation":"Changing compute platform does not solve the monolithic code structure."}]', 'Single-purpose Lambda functions align with microservices principles: independent deployment, isolated failures, right-sized memory, and simpler testing and debugging.', 2, 'https://docs.aws.amazon.com/lambda/latest/dg/best-practices.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company has an application that creates resources but never cleans them up, leading to growing costs from unused resources. Which AWS tool helps identify and tag unused resources for cleanup?', '[{"id":"a","text":"AWS CloudTrail","is_correct":false,"explanation":"CloudTrail logs who created resources but does not identify unused ones."},{"id":"b","text":"AWS Resource Explorer combined with Cost Explorer and tag-based resource groups","is_correct":true,"explanation":"Resource Explorer discovers resources across accounts/regions, and tagging with Cost Explorer helps identify unused resources for cleanup."},{"id":"c","text":"AWS Organizations","is_correct":false,"explanation":"Organizations manages accounts, not resource lifecycle."},{"id":"d","text":"AWS CloudFormation","is_correct":false,"explanation":"CloudFormation manages infrastructure stacks but does not discover orphaned resources."}]', 'Resource Explorer provides a unified view of all resources. Combined with Cost Explorer and tagging policies, teams can identify and clean up unused resources.', 2, 'https://docs.aws.amazon.com/resource-explorer/latest/userguide/welcome.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company wants to implement the Well-Architected Framework''s reliability pillar recommendation of testing recovery procedures. Which AWS service can simulate failures to test resilience?', '[{"id":"a","text":"AWS Inspector","is_correct":false,"explanation":"Inspector scans for vulnerabilities, not failure simulation."},{"id":"b","text":"AWS Fault Injection Service (FIS)","is_correct":true,"explanation":"FIS provides controlled experiments to simulate failures like instance termination, CPU stress, and network disruption for resilience testing."},{"id":"c","text":"AWS Config","is_correct":false,"explanation":"Config monitors compliance, not failure simulation."},{"id":"d","text":"Amazon CloudWatch synthetics","is_correct":false,"explanation":"Synthetics monitors application availability, not fault injection."}]', 'AWS FIS enables chaos engineering by injecting faults like stopping instances, throttling APIs, or disrupting networks to validate application resilience.', 3, 'https://docs.aws.amazon.com/fis/latest/userguide/what-is.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company has multiple development teams deploying directly to production without testing. They want to implement a proper deployment pipeline with manual approval gates. Which service orchestrates this?', '[{"id":"a","text":"AWS CodeBuild","is_correct":false,"explanation":"CodeBuild handles building/testing but does not orchestrate multi-stage pipelines with approval gates."},{"id":"b","text":"AWS CodePipeline with manual approval actions","is_correct":true,"explanation":"CodePipeline supports multi-stage pipelines with manual approval actions that gate progression between stages."},{"id":"c","text":"AWS Lambda for deployments","is_correct":false,"explanation":"Lambda can trigger deployments but does not provide pipeline orchestration with approval gates."},{"id":"d","text":"AWS Systems Manager Maintenance Windows","is_correct":false,"explanation":"Maintenance Windows schedule tasks but do not provide CI/CD pipeline functionality."}]', 'CodePipeline manual approval actions pause the pipeline and notify reviewers via SNS. The pipeline only proceeds when an authorized user approves.', 2, 'https://docs.aws.amazon.com/codepipeline/latest/userguide/approvals-action-add.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company runs their application on EC2 instances with manually installed software. Configuration inconsistencies between instances cause bugs. How should the architect standardize deployments?', '[{"id":"a","text":"Document the installation steps","is_correct":false,"explanation":"Documentation does not enforce consistency."},{"id":"b","text":"Use AMIs built with EC2 Image Builder and deploy via launch templates in Auto Scaling groups","is_correct":true,"explanation":"Golden AMIs ensure every instance starts with identical software configuration, and launch templates enforce consistent deployment."},{"id":"c","text":"SSH into each instance and verify configuration","is_correct":false,"explanation":"Manual verification does not scale and is error-prone."},{"id":"d","text":"Use larger instances to avoid issues","is_correct":false,"explanation":"Instance size does not address configuration consistency."}]', 'Golden AMIs (pre-configured images) combined with launch templates ensure every instance starts with identical, tested software configuration, eliminating drift.', 2, 'https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/AMIs.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company has an application with hardcoded feature flags. They want to implement dynamic feature flags that can be toggled without redeployment. Which AWS service supports this?', '[{"id":"a","text":"AWS Lambda environment variables","is_correct":false,"explanation":"Lambda environment variables require function update and redeployment to change."},{"id":"b","text":"AWS AppConfig with feature flags","is_correct":true,"explanation":"AppConfig provides managed feature flags that can be toggled in real-time without deploying new code, with built-in safeguards."},{"id":"c","text":"DynamoDB table for flag storage","is_correct":false,"explanation":"DynamoDB can store flags but lacks deployment safeguards and gradual rollout features."},{"id":"d","text":"CloudFormation parameters","is_correct":false,"explanation":"CloudFormation parameter changes require stack updates."}]', 'AppConfig feature flags support instant toggling, percentage-based rollouts, and automatic rollback on CloudWatch alarm triggers, all without code deployment.', 3, 'https://docs.aws.amazon.com/appconfig/latest/userguide/appconfig-creating-feature-flag.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company wants to implement the AWS Well-Architected Framework for their existing workloads. Which tool helps them assess their architecture against best practices and identify improvement areas?', '[{"id":"a","text":"AWS CloudFormation linter","is_correct":false,"explanation":"CFN linter validates template syntax, not architectural best practices."},{"id":"b","text":"AWS Well-Architected Tool in the AWS Console","is_correct":true,"explanation":"The Well-Architected Tool guides workload reviews against the 6 pillars and provides improvement recommendations."},{"id":"c","text":"AWS Trusted Advisor","is_correct":false,"explanation":"Trusted Advisor provides automated checks but does not conduct comprehensive architectural reviews."},{"id":"d","text":"Amazon CodeGuru Reviewer","is_correct":false,"explanation":"CodeGuru reviews application code, not architecture patterns."}]', 'The Well-Architected Tool provides a structured review process, asking questions across the 6 pillars and generating improvement plans with prioritized recommendations.', 1, 'https://docs.aws.amazon.com/wellarchitected/latest/userguide/intro.html', 'SAA-C03-6.2', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company uses a relational database to store time-series metrics from IoT devices. Query performance degrades as data grows. Which purpose-built database should the architect recommend for time-series data?', '[{"id":"a","text":"Amazon Aurora","is_correct":false,"explanation":"Aurora is a general-purpose relational database not optimized for time-series ingestion and queries."},{"id":"b","text":"Amazon Timestream","is_correct":true,"explanation":"Timestream is purpose-built for time-series data with automatic data tiering and built-in time-series analytics functions."},{"id":"c","text":"Amazon DynamoDB","is_correct":false,"explanation":"DynamoDB can store time-series data but lacks native time-series query functions."},{"id":"d","text":"Amazon Redshift","is_correct":false,"explanation":"Redshift is for analytics but is not optimized for real-time time-series ingestion."}]', 'Amazon Timestream automatically manages data lifecycle with in-memory and magnetic storage tiers, and provides built-in time-series functions for interpolation and aggregation.', 3, 'https://docs.aws.amazon.com/timestream/latest/developerguide/what-is-timestream.html', 'SAA-C03-6.1', true, true),
('b1000000-0000-4000-8000-000000000006', 'single_choice', 'A company has an existing application that sends emails synchronously, causing request timeouts when the email service is slow. How should the architect improve this?', '[{"id":"a","text":"Increase the request timeout","is_correct":false,"explanation":"Increasing timeouts does not solve the underlying coupling issue."},{"id":"b","text":"Send emails asynchronously by publishing to an SQS queue and processing with a separate worker","is_correct":true,"explanation":"Async processing via SQS decouples email sending from the request path, improving response times and fault tolerance."},{"id":"c","text":"Use a faster email provider","is_correct":false,"explanation":"A faster provider helps but still leaves synchronous coupling."},{"id":"d","text":"Add a retry loop in the application","is_correct":false,"explanation":"Retry loops increase request latency further."}]', 'Moving email sending to an async queue decouples the operation from the user request. The request returns immediately while email is processed in the background.', 1, 'https://docs.aws.amazon.com/wellarchitected/latest/reliability-pillar/design-interactions-in-a-distributed-system-to-mitigate-or-withstand-failures.html', 'SAA-C03-6.2', true, true)
;
